    def preview_import_target_autoloop_policy_selection_snapshot(self) -> None:
        selected = filedialog.askopenfilename(
            title="target-autoloop selection JSON 불러오기",
            filetypes=[("JSON", "*.json"), ("All files", "*.*")],
        )
        if not selected:
            return
        import_path = Path(selected)
        try:
            payload = json.loads(import_path.read_text(encoding="utf-8"))
        except Exception as exc:
            self.target_autoloop_policy_editor_status_var.set(f"target-autoloop selection import preview 실패: {exc}")
            self._set_target_autoloop_policy_selection_warning(f"selection import preview parse failed: {exc}")
            return
        effective_document = self.__dict__.get("message_config_doc", {}) or {}
        target_ids = self._target_autoloop_policy_target_ids(effective_document)
        target_id_set = set(target_ids)
        saved_config_path = str((payload or {}).get("ConfigPath", "") or "").strip() if isinstance(payload, dict) else ""
        saved_run_root = str((payload or {}).get("RunRoot", "") or "").strip() if isinstance(payload, dict) else ""
        saved_target_ids_hash = str((payload or {}).get("TargetIdsHash", "") or "").strip() if isinstance(payload, dict) else ""
        filter_mode = str((payload or {}).get("FilterMode", "") or "").strip() if isinstance(payload, dict) else ""
        selected_target_ids = [
            str(item or "").strip()
            for item in list((payload or {}).get("SelectedTargetIds", []) or [])
            if str(item or "").strip()
        ] if isinstance(payload, dict) else []
        known_target_ids = [target_id for target_id in selected_target_ids if target_id in target_id_set]
        unknown_target_ids = [target_id for target_id in selected_target_ids if target_id not in target_id_set]
        current_filter_mode = str(self.target_autoloop_policy_filter_var.get() or "").strip() or "all"
        current_selected_target_ids = self._target_autoloop_policy_selected_target_ids(effective_document)
        current_selected_set = set(current_selected_target_ids)
        imported_selected_set = set(known_target_ids)
        added_target_ids = [target_id for target_id in known_target_ids if target_id not in current_selected_set]
        removed_target_ids = [target_id for target_id in current_selected_target_ids if target_id not in imported_selected_set]
        unchanged_target_ids = [target_id for target_id in known_target_ids if target_id in current_selected_set]
        warnings: list[str] = []
        blocking_reason = ""
        schema_version = (payload or {}).get("SchemaVersion", None) if isinstance(payload, dict) else None
        if not isinstance(payload, dict):
            blocking_reason = "payload가 object 형식이 아닙니다."
        elif schema_version is None:
            warnings.append("legacy schema")
        else:
            try:
                normalized_schema_version = int(schema_version or 0)
            except Exception:
                blocking_reason = f"schema parse failure ({schema_version})"
            else:
                if normalized_schema_version != TARGET_AUTOLOOP_POLICY_SELECTION_SCHEMA_VERSION:
                    blocking_reason = f"schema mismatch ({schema_version})"
        current_config_path = str(self.config_path_var.get() or "").strip()
        current_run_root = self._current_run_root_for_actions().strip()
        current_target_ids_hash = self._target_autoloop_policy_target_ids_hash(effective_document)
        if not blocking_reason and self._normalized_optional_path(saved_config_path) and self._normalized_optional_path(current_config_path):
            if self._normalized_optional_path(saved_config_path) != self._normalized_optional_path(current_config_path):
                blocking_reason = "config path mismatch"
        if not blocking_reason and self._normalized_optional_path(saved_run_root) and self._normalized_optional_path(current_run_root):
            if self._normalized_optional_path(saved_run_root) != self._normalized_optional_path(current_run_root):
                blocking_reason = "run root mismatch"
        if not blocking_reason and saved_target_ids_hash and saved_target_ids_hash != current_target_ids_hash:
            blocking_reason = "target ids hash mismatch"
        if filter_mode not in self._target_autoloop_policy_filter_options():
            warnings.append(f"unknown filter={filter_mode or '(empty)'}")
        if unknown_target_ids:
            warnings.append("unknown targets=" + ",".join(unknown_target_ids))
        analysis = {
            "path": str(import_path),
            "payload": payload,
            "blocking_reason": blocking_reason,
            "warnings": warnings,
            "resolved_filter_mode": filter_mode if filter_mode in self._target_autoloop_policy_filter_options() else "all",
            "current_filter_mode": current_filter_mode,
            "current_selected_target_ids": current_selected_target_ids,
            "known_target_ids": known_target_ids,
            "unknown_target_ids": unknown_target_ids,
            "added_target_ids": added_target_ids,
            "removed_target_ids": removed_target_ids,
            "unchanged_target_ids": unchanged_target_ids,
        }
        self.__dict__["_target_autoloop_policy_selection_import_preview"] = analysis
        if self._has_ui_attr("output_text"):
            self.set_text(self.output_text, format_target_autoloop_selection_import_preview_report(analysis))
        self.target_autoloop_policy_editor_status_var.set(
            "target-autoloop selection import preview 완료 / canApply={can_apply} / known={known_count} / unknown={unknown_count} / add={add_count} / remove={remove_count}".format(
                can_apply=(not bool(blocking_reason)),
                known_count=len(known_target_ids),
                unknown_count=len(unknown_target_ids),
                add_count=len(added_target_ids),
                remove_count=len(removed_target_ids),
            )
        )

    def apply_import_target_autoloop_policy_selection_snapshot(self) -> None:
        preview = self.__dict__.get("_target_autoloop_policy_selection_import_preview", None)
        if not isinstance(preview, dict):
            messagebox.showwarning("import preview 필요", "먼저 selection import preview를 실행하세요.")
            return
        blocking_reason = str(preview.get("blocking_reason", "") or "").strip()
        if blocking_reason:
            messagebox.showwarning("selection import 차단", blocking_reason)
            self.target_autoloop_policy_editor_status_var.set("target-autoloop selection import 차단: " + blocking_reason)
            return
        filter_mode = str(preview.get("resolved_filter_mode", "") or "").strip() or "all"
        selected_target_ids = [str(item or "").strip() for item in list(preview.get("known_target_ids", []) or []) if str(item or "").strip()]
        added_target_ids = [str(item or "").strip() for item in list(preview.get("added_target_ids", []) or []) if str(item or "").strip()]
        removed_target_ids = [str(item or "").strip() for item in list(preview.get("removed_target_ids", []) or []) if str(item or "").strip()]
        unchanged_target_ids = [str(item or "").strip() for item in list(preview.get("unchanged_target_ids", []) or []) if str(item or "").strip()]
        target_ids = self._target_autoloop_policy_target_ids(self.__dict__.get("message_config_doc", {}) or {})
        self.__dict__["_target_autoloop_policy_selection_change_guard"] = True
        try:
            self.target_autoloop_policy_filter_var.set(filter_mode)
            selected_set = set(selected_target_ids)
            for target_id in target_ids:
                store = self._target_autoloop_policy_card_store(target_id)
                store["bulk_selected_var"].set(target_id in selected_set)
        finally:
            self.__dict__["_target_autoloop_policy_selection_change_guard"] = False
        self._apply_target_autoloop_policy_filter_layout()
        warnings = [str(item or "").strip() for item in list(preview.get("warnings", []) or []) if str(item or "").strip()]
        if warnings:
            self._set_target_autoloop_policy_selection_warning("selection import 적용 주의: " + " / ".join(warnings))
        else:
            self._set_target_autoloop_policy_selection_warning("")
        if self._has_ui_attr("output_text"):
            self.set_text(
                self.output_text,
                format_target_autoloop_selection_import_apply_report(
                    preview_path=str(preview.get("path", "") or "").strip(),
                    filter_mode=filter_mode,
                    selected_target_ids=selected_target_ids,
                    added_target_ids=added_target_ids,
                    removed_target_ids=removed_target_ids,
                    unchanged_target_ids=unchanged_target_ids,
                    warnings=warnings,
                ),
            )
        self.target_autoloop_policy_editor_status_var.set(
            "target-autoloop selection import 적용 완료 / filter={filter_mode} / selected={count} / add={add_count} / remove={remove_count}".format(
                filter_mode=filter_mode,
                count=len(selected_target_ids),
                add_count=len(added_target_ids),
                remove_count=len(removed_target_ids),
            )
        )

    def save_selected_dirty_target_autoloop_policy_editor(self) -> None:
        if self._message_editor_has_unsaved_changes():
            messagebox.showwarning("저장 차단", "Initial/Handoff 문구 편집에 미저장 변경이 있습니다. 먼저 저장하거나 취소한 뒤 selected dirty target 저장을 진행하세요.")
            self.target_autoloop_policy_editor_status_var.set("selected dirty target 저장 차단: 문구 편집 미저장 변경이 있습니다.")
            return
        config_path = self.config_path_var.get().strip()
        if not config_path:
            messagebox.showwarning("ConfigPath 없음", "ConfigPath를 먼저 확인하세요.")
            return
        try:
            document = self.message_config_service.load_config_document(config_path)
            selected_dirty_target_ids = self._target_autoloop_policy_selected_dirty_target_ids(document)
            if not selected_dirty_target_ids:
                messagebox.showwarning("선택 dirty target 없음", "저장할 selected dirty target이 없습니다.")
                return
            for target_id in selected_dirty_target_ids:
                self._apply_target_autoloop_policy_card_values_to_document(document, target_id)
            backup_path = self.message_config_service.save_document(config_path, document)
        except Exception as exc:
            messagebox.showerror("selected dirty target 저장 실패", str(exc))
            self.target_autoloop_policy_editor_status_var.set(f"selected dirty target 저장 실패: {exc}")
            return
        self._apply_saved_target_autoloop_policy_document(document)
        self.target_autoloop_policy_editor_status_var.set(
            "selected dirty target {count}개 저장 완료 / targets={targets} / 백업: {backup}".format(
                count=len(selected_dirty_target_ids),
                targets=", ".join(selected_dirty_target_ids),
                backup=backup_path,
            )
        )

    def _apply_saved_target_autoloop_policy_document(self, document: dict) -> None:
        saved_document = self.message_config_service.clone_document(document)
        self.message_config_doc = saved_document
        self.message_config_original = self.message_config_service.clone_document(saved_document)
        self.__dict__["message_document_version"] = int(self.__dict__.get("message_document_version", 0) or 0) + 1
        self.message_preview_payload = None
        self.message_preview_doc_version = -1
        self.message_preview_cached_context_key = ""
        self.message_editor_dirty = False
        self.__dict__.pop("_message_snapshot_text_cache", None)
        self.__dict__.pop("_message_diff_summary_text_cache", None)
        self.__dict__.pop("_message_diff_body_text_cache", None)
        self._clear_pair_policy_route_snapshot_cache()
        self.refresh_target_autoloop_policy_editor(document=saved_document, refresh_reason="config")
        self._refresh_target_autoloop_status_if_visible_or_mark_pending()

    @staticmethod
    def _target_autoloop_policy_trigger_summary(trigger_kinds: list[str]) -> str:
        normalized = [str(item or "").strip() for item in list(trigger_kinds or []) if str(item or "").strip()]
        return ",".join(normalized) if normalized else "(none)"

    def _target_autoloop_policy_badge_spec(self, *, route_badge: str, enabled: bool) -> dict[str, str]:
        normalized_badge = str(route_badge or "").strip()
        if not enabled:
            return {"text": "DISABLED", "background": "#6B7280", "foreground": "#FFFFFF"}
        if normalized_badge == "ROUTE READY":
            return {"text": normalized_badge, "background": "#15803D", "foreground": "#FFFFFF"}
        if normalized_badge == "ROUTE CHECK":
            return {"text": normalized_badge, "background": "#B91C1C", "foreground": "#FFFFFF"}
        if normalized_badge == "ROUTE OUT":
            return {"text": normalized_badge, "background": "#6B7280", "foreground": "#FFFFFF"}
        if normalized_badge == "ROUTE EMPTY":
            return {"text": normalized_badge, "background": "#6B7280", "foreground": "#FFFFFF"}
        return {"text": normalized_badge or "ROUTE 미확인", "background": "#6B7280", "foreground": "#FFFFFF"}

    @staticmethod
    def _target_autoloop_policy_runtime_badge_spec(*, phase: str, enabled: bool) -> dict[str, str]:
        normalized_phase = str(phase or "").strip()
        if not enabled or normalized_phase == "disabled":
            return {"text": "DISABLED", "background": "#6B7280", "foreground": "#FFFFFF"}
        if normalized_phase in {"failed"}:
            return {"text": "ERROR", "background": "#B91C1C", "foreground": "#FFFFFF"}
        if normalized_phase in {"limit-reached", "output-ready"}:
            return {"text": "DONE", "background": "#15803D", "foreground": "#FFFFFF"}
        if normalized_phase in {"waiting-output", "claimed", "input-detected"}:
            return {"text": "RUNNING", "background": "#1D4ED8", "foreground": "#FFFFFF"}
        if normalized_phase in {"dispatch-delay", "queued", "paused", "cooldown"}:
            return {"text": "WAITING", "background": "#B45309", "foreground": "#FFFFFF"}
        if normalized_phase in {"stopped"}:
            return {"text": "STOPPED", "background": "#6B7280", "foreground": "#FFFFFF"}
        return {"text": "IDLE", "background": "#6B7280", "foreground": "#FFFFFF"}

    @staticmethod
    def _target_autoloop_smoke_cycle_text(*, cycle_count: int, max_cycle_count: int) -> str:
        cycle_count = max(0, int(cycle_count or 0))
        max_cycle_count = max(0, int(max_cycle_count or 0))
        max_label = str(max_cycle_count) if max_cycle_count > 0 else "미설정"
        if cycle_count >= TARGET_AUTOLOOP_SMOKE_MIN_CYCLES:
            return f"smoke {TARGET_AUTOLOOP_SMOKE_MIN_CYCLES}회 확인 완료 / 운영한도 {max_label}"
        return f"smoke {cycle_count}/{TARGET_AUTOLOOP_SMOKE_MIN_CYCLES} 확인 중 / 운영한도 {max_label}"

    @staticmethod
    def _target_autoloop_smoke_cycle_short_text(*, cycle_count: int) -> str:
        cycle_count = max(0, int(cycle_count or 0))
        if cycle_count >= TARGET_AUTOLOOP_SMOKE_MIN_CYCLES:
            return f"smoke {TARGET_AUTOLOOP_SMOKE_MIN_CYCLES}회 확인 완료"
        return f"smoke {cycle_count}/{TARGET_AUTOLOOP_SMOKE_MIN_CYCLES} 확인 중"

    @staticmethod
    def _target_autoloop_cycle_progress_text(*, phase: str, cycle_count: int, max_cycle_count: int) -> str:
        normalized_phase = str(phase or "").strip()
        cycle_count = max(0, int(cycle_count or 0))
        max_cycle_count = max(0, int(max_cycle_count or 0))
        active_phases = {"input-detected", "claimed", "waiting-output"}
        waiting_phases = {"queued", "dispatch-delay", "cooldown"}
        if max_cycle_count <= 0:
            if normalized_phase in active_phases:
                return f"{cycle_count} 완료 / {cycle_count + 1}번째 진행 중 / max 미설정"
            if normalized_phase in waiting_phases:
                return f"{cycle_count} 완료 / {cycle_count + 1}번째 대기 / max 미설정"
            return f"{cycle_count} 완료 / max 미설정"
        remaining = max(0, max_cycle_count - cycle_count)
        if normalized_phase in active_phases and cycle_count < max_cycle_count:
            return f"{cycle_count}/{max_cycle_count} 완료 / {cycle_count + 1}번째 진행 중 / 남은 {remaining}"
        if normalized_phase in waiting_phases and cycle_count < max_cycle_count:
            return f"{cycle_count}/{max_cycle_count} 완료 / {cycle_count + 1}번째 대기 / 남은 {remaining}"
        if normalized_phase == "paused":
            return f"{cycle_count}/{max_cycle_count} 완료 / 일시정지 / 남은 {remaining}"
        if normalized_phase in {"failed"}:
            return f"{cycle_count}/{max_cycle_count} 완료 / 실패 / 남은 {remaining}"
        if normalized_phase in {"limit-reached", "output-ready"} or cycle_count >= max_cycle_count:
            return f"{cycle_count}/{max_cycle_count} 완료 / 완료 / 남은 {remaining}"
        return f"{cycle_count}/{max_cycle_count} 완료 / 남은 {remaining}"

    def _target_autoloop_policy_progress_badge_spec(
        self,
        *,
        target_id: str,
        phase: str,
        next_action: str,
        dispatch_state: str,
        cycle_count: int,
        max_cycle_count: int,
        enabled: bool,
    ) -> dict[str, str]:
        normalized_target_id = str(target_id or "target").strip() or "target"
        if not bool(enabled):
            return {
                "text": f"{normalized_target_id} DISABLED",
                "background": "#6B7280",
                "foreground": "#FFFFFF",
            }
        remaining_count = max(0, max_cycle_count - cycle_count) if max_cycle_count > 0 else 0
        return self._target_autoloop_selected_progress_badge_spec(
            target_id=normalized_target_id,
            phase=phase,
            next_action=next_action,
            dispatch_state=dispatch_state,
            cycle_count=cycle_count,
            max_cycle_count=max_cycle_count,
            remaining_count=remaining_count,
        )

    def _target_autoloop_policy_runtime_summary_text(
        self,
        *,
        runtime_state: str,
        phase: str,
        next_action: str,
        dispatch_state: str,
        cycle_count: int,
        max_cycle_count: int,
        recovery_hint: str = "",
        watcher_coverage_hint: str = "",
    ) -> str:
        progress_text = self._target_autoloop_cycle_progress_text(
            phase=phase,
            cycle_count=cycle_count,
            max_cycle_count=max_cycle_count,
        )
        smoke_cycle_text = self._target_autoloop_smoke_cycle_text(
            cycle_count=cycle_count,
            max_cycle_count=max_cycle_count,
        )
        summary = (
            "runtime={runtime} / phase={phase} / next={next_action} / cycle={cycle}/{max_cycle} "
            "/ progress={progress} / {smoke_cycle} / dispatch={dispatch}"
        ).format(
            runtime=runtime_state,
            phase=phase or "(미확인)",
            next_action=next_action or "(미확인)",
            cycle=cycle_count,
            max_cycle=max_cycle_count,
            progress=progress_text,
            smoke_cycle=smoke_cycle_text,
            dispatch=dispatch_state or "(미확인)",
        )
        normalized_recovery_hint = str(recovery_hint or "").strip()
        if normalized_recovery_hint:
            summary += f" / recovery={normalized_recovery_hint}"
        normalized_watcher_coverage_hint = str(watcher_coverage_hint or "").strip()
        if normalized_watcher_coverage_hint:
            summary += f" / watcher={normalized_watcher_coverage_hint}"
        return summary

    def _target_autoloop_policy_card_watcher_coverage_text(
        self,
        runtime_snapshot: dict[str, object] | None,
        *,
        target_id: str,
    ) -> str:
        snapshot = runtime_snapshot if isinstance(runtime_snapshot, dict) else {}
        normalized_target_id = str(target_id or "").strip()
        if not normalized_target_id or not self._target_autoloop_watcher_is_fresh(snapshot):
            return ""
        manifest_row = self._target_autoloop_row_for_target(
            snapshot.get("manifest_targets", []),
            normalized_target_id,
        )
        if manifest_row and not bool(manifest_row.get("Enabled", False)):
            return ""
        covered, coverage_detail = self._target_autoloop_watcher_covers_target(
            snapshot,
            target_id=normalized_target_id,
        )
        watcher_target_ids = self._target_autoloop_watcher_target_ids(snapshot)
        watcher_target_text = self._target_autoloop_join_target_ids(watcher_target_ids) if watcher_target_ids else "unknown"
        if covered:
            return f"감지범위 포함({watcher_target_text})"
        detail = self._target_autoloop_compact_text(coverage_detail, max_chars=90)
        return f"감지범위 누락({detail})"

    @staticmethod
    def _target_autoloop_policy_recovery_hint(
        *,
        phase: str,
        dispatch_state: str,
        current_retry_count: int,
        stale_retry_count: int,
        router_inbox_ready_count: int,
        last_router_ready_path: str,
    ) -> str:
        normalized_phase = str(phase or "").strip()
        normalized_dispatch = str(dispatch_state or "").strip()
        if current_retry_count > 0:
            return f"현재 전송보류 재시도({current_retry_count})"
        if router_inbox_ready_count > 0:
            return f"router 처리 대기({router_inbox_ready_count}), 시작문/이어쓰기 재입력 금지"
        if normalized_phase == "waiting-output" and (str(last_router_ready_path or "").strip() or normalized_dispatch == "router-ready-file-created"):
            if stale_retry_count > 0:
                return f"이미 전송됨, 시작문 재입력 금지, stale pending={stale_retry_count}"
            return "이미 전송됨, 시작문 재입력 금지"
        if normalized_phase in {"queued", "dispatch-delay", "cooldown"}:
            return "대기 중, 시작문 재입력 금지"
        if normalized_phase == "limit-reached":
            return "추가 N회+감지 또는 새 RunRoot"
        if normalized_phase == "failed":
            return "실패 원인 확인 후 재시도"
        if stale_retry_count > 0:
            return f"stale pending={stale_retry_count}, 자동 재큐잉 금지"
        return ""

    @staticmethod
    def _target_autoloop_summary_items_for_target(
        summary: dict[str, object],
        items_key: str,
        target_id: str,
    ) -> list[dict[str, object]]:
        items = summary.get(items_key, []) if isinstance(summary, dict) else []
        if not isinstance(items, list):
            return []
        normalized_target_id = str(target_id or "").strip()
        return [
            item
            for item in items
            if isinstance(item, dict) and str(item.get("target_id", "") or "").strip() == normalized_target_id
        ]

    @staticmethod
    def _target_autoloop_count_summary_items_for_target(
        summary: dict[str, object],
        items_key: str,
        target_id: str,
    ) -> int:
        return len(RelayOperatorPanel._target_autoloop_summary_items_for_target(summary, items_key, target_id))

    @staticmethod
    def _target_autoloop_latest_summary_item_for_target(
        summary: dict[str, object],
        items_key: str,
        target_id: str,
    ) -> dict[str, object]:
        matched_items = RelayOperatorPanel._target_autoloop_summary_items_for_target(summary, items_key, target_id)
        if not matched_items:
            return {}

        def sort_key(item: dict[str, object]) -> tuple[float, str]:
            try:
                timestamp = float(item.get("last_write_time", 0.0) or 0.0)
            except (TypeError, ValueError):
                timestamp = 0.0
            return timestamp, str(item.get("path", "") or "")

        return sorted(matched_items, key=sort_key)[-1]

    @staticmethod
    def _target_autoloop_retry_pending_item_requires_manual_review(item: dict[str, object] | None) -> bool:
        if not isinstance(item, dict):
            return False
        policies = (
            str(item.get("send_retry_policy", "") or "").strip(),
            str(item.get("focus_lost_retry_policy", "") or "").strip(),
        )
        return "manual-review-duplicate-risk" in policies

    @staticmethod
    def _target_autoloop_retry_pending_item_requires_submit_only(item: dict[str, object] | None) -> bool:
        if not isinstance(item, dict):
            return False
        policies = {
            str(item.get("send_retry_policy", "") or "").strip(),
            str(item.get("focus_lost_retry_policy", "") or "").strip(),
        }
        stages = {
            str(item.get("send_stage", "") or "").strip(),
            str(item.get("focus_lost_stage", "") or "").strip(),
        }
        return "manual-submit-only-retry" in policies or "submit-ready-no-dispatch" in stages

    @staticmethod
    def _target_autoloop_retry_pending_item_is_user_active_hold(item: dict[str, object] | None) -> bool:
        if not isinstance(item, dict):
            return False
        failure_category = str(item.get("failure_category", "") or "").strip()
        failure_message = str(item.get("failure_message", "") or "").strip()
        return failure_category == "user_active_hold" or "user_active_hold" in failure_message

    @staticmethod
    def _target_autoloop_retry_pending_item_missing_delivery_metadata(item: dict[str, object] | None) -> bool:
        if not isinstance(item, dict):
            return False
        if "delivery_metadata_exists" not in item:
            return False
        return not bool(item.get("delivery_metadata_exists", False))

    @staticmethod
    def _target_autoloop_retry_pending_items_require_manual_review(items: list[dict[str, object]]) -> bool:
        return any(RelayOperatorPanel._target_autoloop_retry_pending_item_requires_manual_review(item) for item in items)

    @staticmethod
    def _target_autoloop_output_block_item_for_target(
        runtime_snapshot: dict[str, object],
        target_id: str,
    ) -> dict[str, object]:
        output_block_summary = runtime_snapshot.get("output_block_summary", {})
        if not isinstance(output_block_summary, dict):
            return {}
        items = output_block_summary.get("items", [])
        if not isinstance(items, list):
            return {}
        normalized_target_id = str(target_id or "").strip()
        for item in items:
            if isinstance(item, dict) and str(item.get("target_id", "") or "").strip() == normalized_target_id:
                return item
        return {}

    def _target_autoloop_publish_ready_marker_rebuild_eligibility(
        self,
        runtime_snapshot: dict[str, object] | None = None,
        *,
        target_id: str | None = None,
    ) -> tuple[bool, str]:
        snapshot = runtime_snapshot or self._target_autoloop_runtime_snapshot()
        normalized_target_id = str(target_id or "").strip()
        if not normalized_target_id:
            return False, "target을 확인하세요."
        run_root_error = str(snapshot.get("run_root_error", "") or "").strip()
        if run_root_error:
            return False, f"RunRoot를 읽지 못했습니다: {run_root_error}"
        run_root = str(snapshot.get("run_root", "") or "").strip()
        if not run_root:
            return False, "RunRoot가 필요합니다."
        manifest_row = self._target_autoloop_row_for_target(
            snapshot.get("manifest_targets", []),
            normalized_target_id,
        )
        if not manifest_row:
            return False, f"{normalized_target_id} manifest target이 없습니다."
        if not bool(manifest_row.get("Enabled", False)):
            return False, f"{normalized_target_id}가 manifest에서 enabled가 아닙니다."
        artifact_snapshot = self._target_autoloop_selected_target_artifact_snapshot(
            snapshot,
            target_id=normalized_target_id,
        )
        path_states = artifact_snapshot.get("path_states", {})
        if not isinstance(path_states, dict):
            path_states = {}
        if not bool(path_states.get("summary", False)):
            return False, f"{normalized_target_id} summary.txt가 없어 helper 재생성을 할 수 없습니다."
        if not bool(path_states.get("review_zip", False)):
            return False, f"{normalized_target_id} review.zip이 없어 helper 재생성을 할 수 없습니다."
        marker_state = artifact_snapshot.get("publish_ready_marker_state", {})
        if not isinstance(marker_state, dict):
            marker_state = {}
        marker_reason = str(marker_state.get("reason", "") or "marker-state-unknown")
        if bool(marker_state.get("valid", False)):
            return False, f"{normalized_target_id} publish.ready marker는 이미 strict-ok입니다. 다음 단계는 ready 재검사입니다."
        publish_ready_path = str(artifact_snapshot.get("publish_ready_path", "") or "").strip()
        if not publish_ready_path:
            return False, f"{normalized_target_id} PublishReadyPath를 계산하지 못했습니다."
        return (
            True,
            f"{normalized_target_id} summary.txt/review.zip 기준으로 publish.ready marker를 helper로 재생성합니다. reason={marker_reason}",
        )

    def _target_autoloop_policy_card_primary_action_spec(
        self,
        runtime_snapshot: dict[str, object],
        target_id: str,
    ) -> dict[str, object]:
        normalized_target_id = str(target_id or "").strip()
        if not normalized_target_id:
            return {
                "label": "권장 액션",
                "action_key": "",
                "enabled": False,
                "detail": "target을 확인하세요.",
            }

        router_session = runtime_snapshot.get("router_session", {})
        if not isinstance(router_session, dict):
            router_session = {}
        if bool(runtime_snapshot.get("router_config_drift", False)) or bool(router_session.get("router_config_drift", False)):
            return {
                "label": "router 설정 재시작",
                "action_key": "restart_router_for_autoloop",
                "enabled": True,
                "detail": "router 실행 설정이 현재 config와 다릅니다. 재시작 후 전송보류를 재시도하세요.",
            }

        retry_pending_summary = runtime_snapshot.get("retry_pending_summary", {})
        if not isinstance(retry_pending_summary, dict):
            retry_pending_summary = {}
        current_retry_count = self._target_autoloop_count_summary_items_for_target(
            retry_pending_summary,
            "current_items",
            normalized_target_id,
        )
        stale_retry_count = self._target_autoloop_count_summary_items_for_target(
            retry_pending_summary,
            "stale_items",
            normalized_target_id,
        )
        if current_retry_count > 0:
            current_retry_items = self._target_autoloop_summary_items_for_target(
                retry_pending_summary,
                "current_items",
                normalized_target_id,
            )
            current_retry_item = self._target_autoloop_latest_summary_item_for_target(
                retry_pending_summary,
                "current_items",
                normalized_target_id,
            )
            if self._target_autoloop_retry_pending_item_requires_submit_only(current_retry_item):
                send_stage = str(current_retry_item.get("send_stage", "") or "").strip()
                focus_hint = str(current_retry_item.get("operator_retry_hint", "") or "").strip()
                return {
                    "label": f"{normalized_target_id} Enter만 제출",
                    "action_key": "submit_only_retry",
                    "enabled": True,
                    "detail": (
                        f"payload 붙여넣기 후 submit 직전 멈춘 current retry-pending {current_retry_count}개가 있습니다. "
                        "재붙여넣기하지 않고 target 셀창에 Enter만 1회 보냅니다."
                        + (f" stage={send_stage}." if send_stage else "")
                        + (f" {focus_hint}" if focus_hint else "")
                    ),
                }
            if self._target_autoloop_retry_pending_item_is_user_active_hold(current_retry_item):
                missing_delivery_tail = (
                    " delivery metadata가 없으면 재큐잉 시 자동으로 최소 metadata를 복구합니다."
                    if self._target_autoloop_retry_pending_item_missing_delivery_metadata(current_retry_item)
                    else ""
                )
                debug_log_path = str(current_retry_item.get("debug_log_path", "") or "").strip()
                return {
                    "label": f"{normalized_target_id} idle 후 재시도",
                    "action_key": "requeue_retry_pending",
                    "enabled": True,
                    "detail": (
                        f"current retry-pending {current_retry_count}개가 있지만 원인은 target/Codex 실패가 아니라 사용자 입력 감지입니다. "
                        "Chrome/다른 창 조작으로 idle 조건을 만족하지 못해 안전하게 전송을 중단했습니다. "
                        "마우스/키보드에서 손을 떼고 이 target만 재시도하세요."
                        + missing_delivery_tail
                        + (f" debugLog={debug_log_path}" if debug_log_path else "")
                    ),
                }
            if self._target_autoloop_retry_pending_items_require_manual_review(current_retry_items):
                return {
                    "label": f"{normalized_target_id} 수동확인 필요",
                    "action_key": "",
                    "enabled": False,
                    "detail": (
                        f"current retry-pending {current_retry_count}개 중 submit 이후 중복위험 항목이 있습니다. "
                        "결과 산출물/셀창 상태를 먼저 확인하고 자동 재큐잉하지 마세요."
                    ),
                }
            return {
                "label": f"{normalized_target_id} 전송보류 재시도",
                "action_key": "requeue_retry_pending",
                "enabled": True,
                "detail": f"현재 전송과 연결된 retry-pending {current_retry_count}개만 재큐잉합니다.",
            }

        router_inbox_ready_summary = runtime_snapshot.get("router_inbox_ready_summary", {})
        if not isinstance(router_inbox_ready_summary, dict):
            router_inbox_ready_summary = {}
        router_inbox_ready_count = self._target_autoloop_count_summary_items_for_target(
            router_inbox_ready_summary,
            "items",
            normalized_target_id,
        )

        status_row = self._target_autoloop_row_for_target(
            runtime_snapshot.get("targets", []),
            normalized_target_id,
        )
        manifest_row = self._target_autoloop_row_for_target(
            runtime_snapshot.get("manifest_targets", []),
            normalized_target_id,
        )
        manifest_targets = runtime_snapshot.get("manifest_targets", [])
        if isinstance(manifest_targets, list) and manifest_targets and not manifest_row:
            return {
                "label": "target 설정 확인",
                "action_key": "",
                "enabled": False,
                "detail": f"{normalized_target_id}가 현재 RunRoot manifest에 없습니다. 같은 RunRoot에서 이어가려면 target별 RunRoot/route를 먼저 확인하세요.",
            }
        if manifest_row and not bool(manifest_row.get("Enabled", False)):
            return {
                "label": "target 활성화 확인",
                "action_key": "",
                "enabled": False,
                "detail": f"{normalized_target_id}가 manifest에서 disabled 상태입니다. target 설정에서 Enabled를 켜고 새 RunRoot를 준비하세요.",
            }
        trigger_kinds_value = manifest_row.get("TriggerKinds", None) if manifest_row else None
        trigger_kinds = [
            str(item or "").strip()
            for item in list(trigger_kinds_value or [])
            if str(item or "").strip()
        ] if trigger_kinds_value is not None else []
        if manifest_row and trigger_kinds_value is not None and "publish-ready" not in trigger_kinds:
            return {
                "label": "publish-ready 설정 확인",
                "action_key": "",
                "enabled": False,
                "detail": f"{normalized_target_id} publish-ready trigger가 꺼져 있습니다. 산출물 기반 추가 진행/ready 재검사를 쓰려면 trigger를 켜고 저장하세요.",
            }
        phase = str(status_row.get("Phase", "") or manifest_row.get("Phase", "") or "").strip()
        next_action = str(status_row.get("NextAction", "") or manifest_row.get("NextAction", "") or "").strip()
        dispatch_state = str(status_row.get("LastDispatchState", "") or "").strip()
        last_router_ready_path = str(status_row.get("LastRouterReadyPath", "") or "").strip()
        cycle_count = self._target_autoloop_int_or_zero(status_row.get("CycleCount", 0))
        max_cycle_count = self._target_autoloop_int_or_zero(status_row.get("MaxCycleCount", manifest_row.get("MaxCycleCount", 0)))
        if self._target_autoloop_is_dispatch_delay_row(status_row):
            eligible_at_text = str(status_row.get("PendingDispatchEligibleAt", "") or "").strip()
            remaining_label = self._target_autoloop_remaining_delay_label(eligible_at_text)
            pending_delay_seconds = self._target_autoloop_int_or_zero(status_row.get("PendingDispatchDelaySeconds", 0))
            delay_range = self._target_autoloop_delay_range_summary_label(status_row)
            detail_parts = [
                f"{normalized_target_id} publish.ready는 감지됐고 설정된 지연 뒤 다음 전송을 예약한 상태입니다.",
                "실패가 아니므로 전송보류 재시도/이어쓰기 재입력은 누르지 마세요.",
            ]
            if remaining_label:
                detail_parts.append(remaining_label)
            if eligible_at_text:
                detail_parts.append(f"eligibleAt={eligible_at_text}")
            if pending_delay_seconds > 0:
                detail_parts.append(f"pendingDelay={pending_delay_seconds}s")
            if delay_range:
                detail_parts.append(f"delay={delay_range}")
            return {
                "label": f"{normalized_target_id} 전송 지연 대기",
                "action_key": "",
                "enabled": False,
                "target_id": normalized_target_id,
                "detail": " ".join(detail_parts),
            }
        output_block_item = self._target_autoloop_output_block_item_for_target(
            runtime_snapshot,
            normalized_target_id,
        )
        marker_rebuild_allowed, marker_rebuild_detail = self._target_autoloop_publish_ready_marker_rebuild_eligibility(
            runtime_snapshot,
            target_id=normalized_target_id,
        )
        if marker_rebuild_allowed:
            return {
                "label": f"{normalized_target_id} ready marker 재생성",
                "action_key": "rebuild_publish_ready_marker",
                "enabled": True,
                "target_id": normalized_target_id,
                "detail": marker_rebuild_detail,
            }
        if bool(output_block_item.get("ready_unaccepted", False)):
            publish_ready_path = str(output_block_item.get("publish_ready_path", "") or "").strip()
            if self._target_autoloop_watcher_is_fresh(runtime_snapshot):
                covered, coverage_detail = self._target_autoloop_watcher_covers_target(
                    runtime_snapshot,
                    target_id=normalized_target_id,
                )
                if not covered:
                    restart_target_ids = self._target_autoloop_watcher_scope_restart_target_ids(
                        runtime_snapshot,
                        target_id=normalized_target_id,
                    )
                    return {
                        "label": f"{normalized_target_id} 포함 감지 재시작",
                        "action_key": "restart_watch_with_target_scope",
                        "enabled": True,
                        "detail": (
                            f"{normalized_target_id} publish.ready는 생성됐지만 watcher accepted가 없습니다. "
                            f"{coverage_detail} 전송보류 재시도가 아니라 감지 범위 문제입니다. "
                            "현재 감지를 정지한 뒤 target 범위를 {0}(으)로 맞춰 다시 시작합니다."
                        ).format(
                            self._target_autoloop_join_target_ids(restart_target_ids) if restart_target_ids else normalized_target_id
                        ),
                    }
                return {
                    "label": "watcher 수락 대기",
                    "action_key": "",
                    "enabled": False,
                    "detail": (
                        f"{normalized_target_id} publish.ready는 생성됐지만 watcher accepted가 아직 없습니다. "
                        f"현재 active watcher가 이 target을 포함합니다. 다음 sweep을 기다리되, 상태가 지속되면 감지 정지 후 재시작하세요. "
                        f"publishReady={publish_ready_path}"
                    ),
                }
            process_once_allowed, process_once_detail = self._target_autoloop_process_once_eligibility(
                runtime_snapshot,
                target_id=normalized_target_id,
            )
            if process_once_allowed:
                return {
                    "label": f"{normalized_target_id} ready 재검사",
                    "action_key": "process_once",
                    "enabled": True,
                    "detail": (
                        f"{process_once_detail} / publish.ready가 watcher accepted로 이어지지 않았습니다. "
                        f"publishReady={publish_ready_path}"
                    ),
                }

        if stale_retry_count > 0:
            return {
                "label": "stale 보류 확인",
                "action_key": "",
                "enabled": False,
                "detail": (
                    f"{normalized_target_id} stale retry-pending {stale_retry_count}개만 있습니다. "
                    "현재 LastRouterReadyPath와 연결된 current 항목이 아니라 자동 재시도하지 않습니다. "
                    "새 산출물이 있으면 ready 재검사 또는 감지 재시작을 사용하세요."
                ),
            }

        if router_inbox_ready_count > 0:
            return {
                "label": "router 처리 대기",
                "action_key": "",
                "enabled": False,
                "detail": (
                    f"router inbox ready {router_inbox_ready_count}개가 있어 시작문/이어쓰기 재입력은 금지입니다. "
                    "이미 전송 대기열에 들어간 상태이므로 router/visible dispatch 상태와 focus_lost 로그를 확인하세요."
                ),
            }
        if phase == "waiting-output" and (last_router_ready_path or dispatch_state == "router-ready-file-created"):
            watcher_health, _watcher_health_detail = self._target_autoloop_watcher_health(runtime_snapshot)
            start_allowed, start_detail = self._target_autoloop_scoped_start_eligibility(
                runtime_snapshot,
                target_id=normalized_target_id,
            )
            if watcher_health in {"stopped", "stale"}:
                start_target_ids = self._target_autoloop_default_start_target_ids(
                    runtime_snapshot,
                    target_id=normalized_target_id,
                )
                start_scope_text = self._target_autoloop_join_target_ids(start_target_ids) if start_target_ids else normalized_target_id
                detail = (
                    f"{normalized_target_id}에는 이미 payload가 전송됐지만 watcher가 {watcher_health} 상태라 "
                    "Codex가 산출물을 만들어도 자동 감지/다음 cycle 진행이 안 될 수 있습니다. "
                    "같은 payload를 다시 넣지 말고 감지를 다시 시작하세요."
                )
                if start_detail:
                    detail += f" {start_detail}"
                detail += f" 감지 target={start_scope_text}"
                return {
                    "label": f"{normalized_target_id} 감지 시작 필요",
                    "action_key": "start_watch",
                    "enabled": bool(start_allowed),
                    "target_id": normalized_target_id,
                    "detail": detail,
                }
            detail = "이미 전송된 상태입니다. 해당 셀창 결과와 산출물을 기다리세요."
            if stale_retry_count > 0:
                detail += f" stale pending={stale_retry_count}개는 자동 재큐잉하지 않습니다."
            return {
                "label": "결과 대기",
                "action_key": "",
                "enabled": False,
                "detail": detail,
            }
        if phase in {"queued", "dispatch-delay", "cooldown"}:
            return {
                "label": "대기 중",
                "action_key": "",
                "enabled": False,
                "detail": f"phase={phase or '-'} 상태입니다. 시작문 재입력 없이 감지/dispatch 처리를 기다리세요.",
            }

        additional_cycles, additional_detail = self._target_autoloop_extend_cycles_value(target_id=normalized_target_id)
        limit_reached = phase == "limit-reached" or next_action == "limit-reached" or (max_cycle_count > 0 and cycle_count >= max_cycle_count)
        if limit_reached:
            if additional_cycles > 0 and not additional_detail:
                extend_allowed, extend_detail = self._target_autoloop_extend_cycle_limit_eligibility(
                    runtime_snapshot,
                    additional_cycles=additional_cycles,
                    target_id=normalized_target_id,
                )
                if extend_allowed:
                    return {
                        "label": f"{normalized_target_id} 추가 {additional_cycles}회+감지",
                        "action_key": "extend_cycle_limit_then_start_watch",
                        "enabled": True,
                        "detail": extend_detail,
                    }
                return {
                    "label": "추가 조건 확인",
                    "action_key": "",
                    "enabled": False,
                    "detail": extend_detail,
                }
            return {
                "label": "추가 횟수 확인",
                "action_key": "",
                "enabled": False,
                "detail": additional_detail or "추가 진행 횟수를 확인하세요.",
            }

        process_once_allowed, process_once_detail = self._target_autoloop_process_once_eligibility(
            runtime_snapshot,
            target_id=normalized_target_id,
        )
        if process_once_allowed:
            return {
                "label": f"{normalized_target_id} ready 재검사",
                "action_key": "process_once",
                "enabled": True,
                "detail": process_once_detail,
            }

        watcher_health, _watcher_health_detail = self._target_autoloop_watcher_health(runtime_snapshot)
        start_allowed, start_detail = self._target_autoloop_scoped_start_eligibility(
            runtime_snapshot,
            target_id=normalized_target_id,
        )
        if self._target_autoloop_watcher_is_fresh(runtime_snapshot):
            covered, coverage_detail = self._target_autoloop_watcher_covers_target(
                runtime_snapshot,
                target_id=normalized_target_id,
            )
            if not covered:
                restart_target_ids = self._target_autoloop_watcher_scope_restart_target_ids(
                    runtime_snapshot,
                    target_id=normalized_target_id,
                )
                return {
                    "label": f"{normalized_target_id} 포함 감지 재시작",
                    "action_key": "restart_watch_with_target_scope",
                    "enabled": True,
                    "detail": (
                        f"{coverage_detail} 현재 감지를 정지한 뒤 target 범위를 "
                        f"{self._target_autoloop_join_target_ids(restart_target_ids) if restart_target_ids else normalized_target_id}(으)로 맞춰 다시 시작합니다."
                    ),
                }
        if watcher_health in {"stopped", "stale"} and start_allowed:
            start_target_ids = self._target_autoloop_default_start_target_ids(
                runtime_snapshot,
                target_id=normalized_target_id,
            )
            start_scope_text = self._target_autoloop_join_target_ids(start_target_ids) if start_target_ids else normalized_target_id
            start_label = (
                f"{normalized_target_id} 포함 감지 시작"
                if len(start_target_ids) > 1
                else f"{normalized_target_id} 감지 시작"
            )
            return {
                "label": start_label,
                "action_key": "start_watch",
                "enabled": True,
                "detail": (start_detail or f"{normalized_target_id} 감지를 시작할 수 있습니다.") + f" 감지 target={start_scope_text}",
            }

        return {
            "label": "상태 확인",
            "action_key": "",
            "enabled": False,
            "detail": start_detail or process_once_detail or "현재 자동 실행할 권장 액션이 없습니다.",
        }

    def _target_autoloop_policy_build_preview_text(
        self,
        *,
        policy: dict[str, object],
        route_row: dict[str, object] | None = None,
        route_error: str = "",
    ) -> str:
        route_row = route_row or {}
        trigger_summary = self._target_autoloop_policy_trigger_summary(list(policy.get("TriggerKinds", []) or []))
        route_phase = str(route_row.get("Phase", "") or "")
        route_cycle_count = self._target_autoloop_int_or_zero(route_row.get("CycleCount", 0))
        route_max_cycle_count = self._target_autoloop_int_or_zero(
            route_row.get("MaxCycleCount", policy.get("MaxCycleCount", 0))
        )
        route_progress_text = self._target_autoloop_cycle_progress_text(
            phase=route_phase,
            cycle_count=route_cycle_count,
            max_cycle_count=route_max_cycle_count,
        )
        route_smoke_cycle_text = self._target_autoloop_smoke_cycle_text(
            cycle_count=route_cycle_count,
            max_cycle_count=route_max_cycle_count,
        )
        lines = [
            "target={0} / enabled={1} / triggers={2} / maxCycle={3}".format(
                policy.get("TargetId", "") or "(없음)",
                bool(policy.get("Enabled", False)),
                trigger_summary,
                policy.get("MaxCycleCount", 0),
            ),
            "window={0}".format(policy.get("WindowTitle", "") or "(없음)"),
            "workRepoRoot={0}".format(policy.get("WorkRepoRoot", "") or "(공통 RunRoot 사용)"),
            "autoloopFixed={0} / effective={1}".format(
                self._target_autoloop_fixed_mode_label(str(policy.get("FixedSuffixMode", "") or "")),
                str(policy.get("EffectiveFixedSuffix", "") or "(없음)"),
            ),
            "route={0} / scope={1} / contract={2} / phase={3} / next={4}".format(
                route_row.get("RouteBadge", "") or "ROUTE 미확인",
                route_row.get("RouteScope", "") or "(미확인)",
                route_row.get("ContractState", "") or "(미확인)",
                route_row.get("Phase", "") or "(미확인)",
                route_row.get("NextAction", "") or "(미확인)",
            ),
            "runtime={0} / cycle={1}/{2}".format(
                self._target_autoloop_policy_runtime_badge_spec(
                    phase=route_phase,
                    enabled=bool(policy.get("Enabled", False)),
                )["text"],
                route_cycle_count,
                route_max_cycle_count,
            ),
            "progress={0} / {1}".format(route_progress_text, route_smoke_cycle_text),
            "outbox={0}".format(route_row.get("SourceOutboxPath", "") or "(없음)"),
            "queue={0}".format(route_row.get("QueueRoot", "") or "(없음)"),
            "targetRunRoot={0}".format(route_row.get("TargetRunRoot", "") or "(공통 RunRoot 사용)"),
            "summary={0}".format(route_row.get("SourceSummaryPath", "") or "(없음)"),
            "review.zip={0}".format(route_row.get("SourceReviewZipPath", "") or "(없음)"),
            "publish.ready={0}".format(route_row.get("PublishReadyPath", "") or "(없음)"),
        ]
        if route_error:
            lines.append("warning=" + route_error)
        return "\n".join(lines)

    def _apply_target_autoloop_policy_route_feedback(
        self,
        *,
        target_id: str,
        policy: dict[str, object],
        route_row: dict[str, object] | None = None,
        route_error: str = "",
    ) -> None:
        store = self._target_autoloop_policy_card_store(target_id)
        route_badge = str((route_row or {}).get("RouteBadge", "") or ("DISABLED" if not bool(policy.get("Enabled", False)) else "ROUTE 미확인"))
        store["route_badge_var"].set(route_badge)
        route_scope = str((route_row or {}).get("RouteScope", "") or "").strip()
        route_scope_reason = str((route_row or {}).get("RouteScopeReason", "") or "").strip()
        route_state = "route={0} / scope={1} / contract={2} / phase={3} / next={4}".format(
            route_badge,
            route_scope or "(미확인)",
            str((route_row or {}).get("ContractState", "") or "(미확인)"),
            str((route_row or {}).get("Phase", "") or "(미확인)"),
            str((route_row or {}).get("NextAction", "") or "(미확인)"),
        )
        if route_scope_reason:
            route_state += f" / scopeReason={route_scope_reason}"
        if route_error:
            route_state += " / warning=route-preview-failed"
        store["route_state_var"].set(route_state)
        store["effective_preview_var"].set(
            self._target_autoloop_policy_build_preview_text(
                policy=policy,
                route_row=route_row,
                route_error=route_error,
            )
        )
        self._sync_target_autoloop_policy_effective_preview_widget(target_id)
        badge_spec = self._target_autoloop_policy_badge_spec(route_badge=route_badge, enabled=bool(policy.get("Enabled", False)))
        badge_label = self.__dict__.get("target_autoloop_policy_card_badge_labels", {}).get(target_id)
        if badge_label is not None:
            try:
                badge_label.configure(
                    text=badge_spec["text"],
                    bg=badge_spec["background"],
                    fg=badge_spec["foreground"],
                )
            except Exception:
                pass
        phase = str((route_row or {}).get("Phase", "") or "")
        runtime_badge_spec = self._target_autoloop_policy_runtime_badge_spec(
            phase=phase,
            enabled=bool(policy.get("Enabled", False)),
        )
        cycle_count = self._target_autoloop_int_or_zero((route_row or {}).get("CycleCount", 0))
        max_cycle_count = self._target_autoloop_int_or_zero(
            (route_row or {}).get("MaxCycleCount", policy.get("MaxCycleCount", 0))
        )
        progress_badge_spec = self._target_autoloop_policy_progress_badge_spec(
            target_id=target_id,
            phase=phase,
            next_action=str((route_row or {}).get("NextAction", "") or ""),
            dispatch_state=str((route_row or {}).get("LastDispatchState", "") or ""),
            cycle_count=cycle_count,
            max_cycle_count=max_cycle_count,
            enabled=bool(policy.get("Enabled", False)),
        )
        store["runtime_badge_var"].set(progress_badge_spec["text"])
        store["runtime_summary_var"].set(
            self._target_autoloop_policy_runtime_summary_text(
                runtime_state=runtime_badge_spec["text"],
                phase=phase or "(미확인)",
                next_action=str((route_row or {}).get("NextAction", "") or "(미확인)"),
                dispatch_state=str((route_row or {}).get("LastDispatchState", "") or "(미확인)"),
                cycle_count=cycle_count,
                max_cycle_count=max_cycle_count,
            )
        )
        runtime_badge_label = self.__dict__.get("target_autoloop_policy_card_runtime_badge_labels", {}).get(target_id)
        if runtime_badge_label is not None:
            self._configure_optional_widget(
                runtime_badge_label,
                text=progress_badge_spec["text"],
                bg=progress_badge_spec["background"],
                fg=progress_badge_spec["foreground"],
            )
        self._apply_target_autoloop_policy_cwd_feedback(target_id)

    def _apply_target_autoloop_policy_card_values_to_document(self, document: dict, target_id: str) -> dict[str, object]:
        store = self._target_autoloop_policy_card_store(target_id)
        trigger_kinds: list[str] = []
        if bool(store["trigger_input_var"].get()):
            trigger_kinds.append("input-file")
        if bool(store["trigger_publish_var"].get()):
            trigger_kinds.append("publish-ready")
        if not trigger_kinds:
            raise ValueError(f"{target_id}는 TriggerKinds를 최소 1개 선택해야 합니다.")
        run_mode = str(((document or {}).get("TargetAutoloop", {}) or {}).get("RunMode", "target-inbox-submit") or "").strip() or "target-inbox-submit"
        if run_mode == "target-inbox-submit" and "publish-ready" in trigger_kinds:
            target_autoloop_section = document.setdefault("TargetAutoloop", {})
            if isinstance(target_autoloop_section, dict):
                target_autoloop_section["RunMode"] = "target-autoloop"
        try:
            max_cycle_count = int(str(store["max_cycle_var"].get() or "0").strip() or "0")
        except ValueError as exc:
            raise ValueError(f"{target_id} MaxCycleCount는 정수여야 합니다.") from exc
        if max_cycle_count < 0:
            raise ValueError(f"{target_id} MaxCycleCount는 0 이상이어야 합니다.")
        enabled = bool(store["enabled_var"].get())
        work_repo_root = str(store["work_repo_root_var"].get() or "").strip()
        validation_error = self._target_autoloop_work_repo_root_validation_error(
            target_id=target_id,
            work_repo_root=work_repo_root,
            enabled=enabled,
            document=document,
        )
        if validation_error:
            raise ValueError(validation_error)
        return self.message_config_service.set_target_autoloop_target_values(
            document,
            target_id,
            enabled=enabled,
            trigger_kinds=trigger_kinds,
            max_cycle_count=max_cycle_count,
            work_repo_root=work_repo_root,
        )

    def _target_autoloop_work_repo_root_validation_error(
        self,
        *,
        target_id: str,
        work_repo_root: str,
        enabled: bool,
        document: dict | None = None,
    ) -> str:
        normalized_target_id = str(target_id or "").strip() or "target"
        normalized_root = str(work_repo_root or "").strip()
        section = (document or {}).get("TargetAutoloop", {}) if isinstance(document, dict) else {}
        strict_external = str((section or {}).get("ExternalPathPolicy", "") or "").strip() == "strict"
        if not normalized_root:
            if strict_external and bool(enabled):
                return (
                    f"{normalized_target_id} WorkRepoRoot는 strict 모드에서 필수입니다. "
                    "패널의 WorkRepoRoot 선택으로 자동화 repo 밖 절대경로를 지정하세요."
                )
            return ""
        try:
            root_path = Path(normalized_root)
        except Exception as exc:
            return f"{normalized_target_id} WorkRepoRoot 경로를 해석하지 못했습니다: {exc}"
        if not root_path.is_absolute():
            return (
                f"{normalized_target_id} WorkRepoRoot는 절대경로여야 합니다: {normalized_root}. "
                "패널에서 폴더 선택 버튼으로 외부 repo를 지정하세요."
            )
        if self._path_is_within_root(normalized_root, ROOT):
            return (
                f"{normalized_target_id} WorkRepoRoot는 자동화 repo 밖이어야 합니다. "
                f"automationRoot={ROOT} workRepoRoot={normalized_root}"
            )
        return ""

    def _ensure_target_autoloop_prepare_config_enabled(
        self,
        config_path: str,
        target_ids: list[str],
    ) -> str:
        normalized_config_path = str(config_path or "").strip()
        if not normalized_config_path:
            return ""
        path = Path(normalized_config_path)
        if not path.is_absolute():
            path = ROOT / path
        if not path.exists() or not path.is_file():
            return ""

        document = self.message_config_service.load_config_document(str(path))
        original_document = self.message_config_service.clone_document(document)
        target_autoloop_section = document.setdefault("TargetAutoloop", {})
        if not isinstance(target_autoloop_section, dict):
            raise ValueError("TargetAutoloop section is not editable")
        target_autoloop_section["Enabled"] = True
        target_autoloop_section["RunMode"] = "target-autoloop"
        for target_id in target_ids:
            self._apply_target_autoloop_policy_card_values_to_document(document, target_id)
        if document == original_document:
            return ""
        backup_path = self.message_config_service.save_document(str(path), document)
        self._apply_saved_target_autoloop_policy_document(document)
        return str(backup_path)

    def refresh_target_autoloop_policy_editor(self, *, document: dict | None = None, refresh_reason: str = "config") -> None:
        config_path = self.config_path_var.get().strip()
        if not config_path:
            self.target_autoloop_policy_editor_status_var.set("ConfigPath가 없어 target-autoloop 정책 카드를 불러오지 못했습니다.")
            return
        try:
            source_document = self._resolve_config_document_for_preview(document=document, config_path=config_path)
        except Exception as exc:
            self.target_autoloop_policy_editor_status_var.set(f"target-autoloop 정책 카드 로드 실패: {exc}")
            return

        section = dict(source_document.get("TargetAutoloop", {}) or {})
        run_mode = str(section.get("RunMode", "target-inbox-submit") or "").strip() or "target-inbox-submit"
        route_error = ""
        route_rows_by_target: dict[str, dict[str, object]] = {}
        closeout_summary = "closeout: pending-proof / mode=not-ready / reason=no-proof"
        closeout_next_step = ""
        try:
            route_payload = self.message_config_service.render_target_autoloop_route_matrix(
                source_document,
                config_path=config_path,
                run_root=self._current_run_root_for_actions().strip(),
            )
            closeout_summary = str(((route_payload.get("ProofCloseout", {}) or {}).get("Summary", "") or "").strip() or closeout_summary)
            closeout_next_step = str(((route_payload.get("ProofCloseout", {}) or {}).get("RecommendedNextStep", "") or "").strip())
            for row in list(route_payload.get("Targets", []) or []):
                if isinstance(row, dict):
                    target_id = str(row.get("TargetId", "") or "").strip()
                    if target_id:
                        route_rows_by_target[target_id] = row
        except Exception as exc:
            route_error = str(exc)

        enabled_count = 0
        publish_ready_count = 0
        dirty_count = 0
        target_ids = self._target_autoloop_policy_target_ids(source_document)
        for target_id in target_ids:
            policy = self.message_config_service.effective_target_autoloop_target(source_document, target_id)
            store = self._target_autoloop_policy_card_store(target_id)
            store["meta_var"].set(
                "{target} / window={window} / runMode={mode}".format(
                    target=target_id,
                    window=policy.get("WindowTitle", "") or "(없음)",
                    mode=policy.get("RunMode", "") or "(없음)",
                )
            )
            store["enabled_var"].set(bool(policy.get("Enabled", False)))
            trigger_kinds = list(policy.get("TriggerKinds", []) or [])
            store["trigger_input_var"].set("input-file" in trigger_kinds)
            store["trigger_publish_var"].set("publish-ready" in trigger_kinds)
            store["max_cycle_var"].set(str(int(policy.get("MaxCycleCount", 0) or 0)))
            store["work_repo_root_var"].set(str(policy.get("WorkRepoRoot", "") or "").strip())
            if bool(policy.get("Enabled", False)):
                enabled_count += 1
            if "publish-ready" in trigger_kinds:
                publish_ready_count += 1
            publish_checkbutton = self.__dict__.get("target_autoloop_policy_card_trigger_publish_checkbuttons", {}).get(target_id)
            if publish_checkbutton is not None:
                self._configure_optional_widget(
                    publish_checkbutton,
                    state="normal",
                )
            self._apply_target_autoloop_policy_route_feedback(
                target_id=target_id,
                policy=policy,
                route_row=route_rows_by_target.get(target_id),
                route_error=route_error,
            )
            self._refresh_target_autoloop_policy_card_loaded_badge(target_id, document=source_document)
            self._apply_target_autoloop_policy_cwd_feedback(target_id)
            if not self._target_autoloop_policy_card_matches_loaded_policy(target_id, document=source_document):
                dirty_count += 1

        self._refresh_target_autoloop_policy_clone_controls(target_ids)
        self._load_target_autoloop_policy_selection_state(document=source_document)
        self._apply_target_autoloop_policy_filter_layout(document=source_document, save_selection=False)
        closeout_text = closeout_summary
        if closeout_next_step:
            closeout_text += " / next=" + closeout_next_step
        self.target_autoloop_policy_closeout_var.set(closeout_text)
        if refresh_reason == "route":
            status_prefix = "실효 경로 새로고침 완료: 저장된 config와 현재 RunRoot 기준 route/runtime preview를 다시 계산했습니다"
        else:
            status_prefix = "Config에서 다시 읽기 완료: config 문서를 다시 로드하고 8 target 카드 값을 저장본 기준으로 동기화했습니다"
        self.target_autoloop_policy_editor_status_var.set(
            "{prefix} / runMode={mode} / enabled={enabled}/{total} / publish-ready={publish_ready} / dirty={dirty} / routePreview={route_preview}".format(
                prefix=status_prefix,
                mode=run_mode,
                enabled=enabled_count,
                total=len(target_ids),
                publish_ready=publish_ready_count,
                dirty=dirty_count,
                route_preview="failed" if route_error else "ok",
            )
        )
        self.refresh_target_autoloop_fixed_suffix_editor(document=source_document)
        self.refresh_target_autoloop_seed_composer()

    def save_target_autoloop_policy_editor(self) -> None:
        if self._message_editor_has_unsaved_changes():
            messagebox.showwarning("저장 차단", "Initial/Handoff 문구 편집에 미저장 변경이 있습니다. 먼저 저장하거나 취소한 뒤 target-autoloop 설정을 저장하세요.")
            self.target_autoloop_policy_editor_status_var.set("target-autoloop 설정 저장 차단: 문구 편집 미저장 변경이 있습니다.")
            return
        config_path = self.config_path_var.get().strip()
        if not config_path:
            messagebox.showwarning("ConfigPath 없음", "ConfigPath를 먼저 확인하세요.")
            return
        try:
            document = self.message_config_service.load_config_document(config_path)
            target_ids = self._target_autoloop_policy_target_ids(document)
            for target_id in target_ids:
                self._apply_target_autoloop_policy_card_values_to_document(document, target_id)
            backup_path = self.message_config_service.save_document(config_path, document)
        except Exception as exc:
            messagebox.showerror("target-autoloop 설정 저장 실패", str(exc))
            self.target_autoloop_policy_editor_status_var.set(f"target-autoloop 설정 저장 실패: {exc}")
            return
        self._apply_saved_target_autoloop_policy_document(document)
        status_message = f"target-autoloop 설정 저장 완료 / 백업: {backup_path}"
        refresh_status_message = str(self.target_autoloop_policy_editor_status_var.get() or "").strip()
        if refresh_status_message and refresh_status_message != status_message:
            status_message += "\n" + refresh_status_message
        status_message += "\nAutoloop 부분 새로고침만 수행했습니다. 전체 상태가 필요하면 별도 전체 새로고침을 누르세요."
        self.target_autoloop_policy_editor_status_var.set(status_message)

    def _refresh_target_autoloop_policy_clone_controls(self, target_ids: list[str]) -> None:
        options = list(target_ids)
        combo_state = "readonly" if options else "disabled"
        self._configure_optional_widget(self.target_autoloop_policy_clone_source_combo, values=options, state=combo_state)
        self._configure_optional_widget(self.target_autoloop_policy_clone_target_combo, values=options, state=combo_state)

        current_source = str(self.target_autoloop_policy_clone_source_var.get() or "").strip()
        if current_source not in options:
            current_source = options[0] if options else ""
            self.target_autoloop_policy_clone_source_var.set(current_source)

        current_target = str(self.target_autoloop_policy_clone_target_var.get() or "").strip()
        needs_target_reset = current_target not in options
        if len(options) > 1 and current_target == current_source:
            needs_target_reset = True
        if needs_target_reset:
            if not options:
                current_target = ""
            elif len(options) == 1:
                current_target = options[0]
            else:
                current_target = next((target_id for target_id in options if target_id != current_source), options[0])
            self.target_autoloop_policy_clone_target_var.set(current_target)

        clone_enabled = len(options) > 1 and bool(current_source) and bool(current_target) and current_source != current_target
        self._configure_optional_widget(self.target_autoloop_policy_clone_button, state="normal" if clone_enabled else "disabled")

    def _apply_target_autoloop_policy_source_to_targets(self, source_target_id: str, target_ids: list[str], *, mode_label: str) -> None:
        source_store = self._target_autoloop_policy_card_store(source_target_id)
        applied_targets: list[str] = []
        for target_id in target_ids:
            target_store = self._target_autoloop_policy_card_store(target_id)
            target_store["enabled_var"].set(bool(source_store["enabled_var"].get()))
            target_store["trigger_input_var"].set(bool(source_store["trigger_input_var"].get()))
            target_store["trigger_publish_var"].set(bool(source_store["trigger_publish_var"].get()))
            target_store["max_cycle_var"].set(str(source_store["max_cycle_var"].get() or "").strip())
            target_store["work_repo_root_var"].set(str(source_store["work_repo_root_var"].get() or "").strip())
            self._refresh_target_autoloop_policy_card_loaded_badge(target_id)
            applied_targets.append(target_id)
        self._refresh_target_autoloop_policy_card_loaded_badge(source_target_id)
        self._apply_target_autoloop_policy_filter_layout()
        self.refresh_target_autoloop_seed_composer()
        self.target_autoloop_policy_editor_status_var.set(
            "{source} 설정을 {mode} target {count}개에 일괄 적용했습니다: {targets}".format(
                source=source_target_id,
                mode=mode_label,
                count=len(applied_targets),
                targets=", ".join(applied_targets),
            )
        )

