    def _selected_pair_id(self) -> str:
        return self.pair_id_var.get().strip() or "pair01"

    def _selected_home_pair_selection(self) -> str:
        selection = self.home_pair_tree.selection()
        if selection:
            return selection[0]
        return ""

    def _selected_home_pair_id(self) -> str:
        selection = self._selected_home_pair_selection()
        if selection:
            return selection
        return self._selected_pair_id()

    def _selected_pair_summary(self) -> PairSummaryModel | None:
        return self.pair_controller.selected_summary(self.panel_state, self._selected_home_pair_id())

    def _home_pair_detail_text(self, summary: PairSummaryModel | None) -> str:
        detail = self.pair_controller.build_summary_detail(summary)
        if summary and summary.pair_id != self._selected_pair_id():
            detail += " / 실행 기준은 현재 선택 Pair를 유지합니다. 이 Pair로 실행하려면 '선택 Pair 반영'을 누르세요. 결과 탭에서는 이 Pair를 보조 강조합니다."
        return detail

    def _action_pair_summary(self) -> PairSummaryModel | None:
        if not self.panel_state:
            return None
        selected_pair = self._selected_pair_id()
        return next((summary for summary in self.panel_state.pairs if summary.pair_id == selected_pair), None)

    def _refresh_pair_focus_strip(self) -> None:
        if not self._has_ui_attr("pair_focus_summary_var"):
            return
        pair_id = self._selected_pair_id()
        summary = self._action_pair_summary()
        snapshot = self._build_pair_runtime_snapshot(pair_id) if pair_id else {}
        badge_spec = dict(snapshot.get("Badge") or self._pair_runtime_status_badge_spec(snapshot or {"PairId": pair_id}))
        targets = summary.targets if summary else "(targets 미확인)"
        latest_state = summary.latest_state if summary and summary.latest_state else "(상태 미확인)"
        run_root = str(snapshot.get("RunRoot", "") or "").strip()
        run_leaf = os.path.basename(os.path.normpath(run_root)) if run_root else "(runroot 없음)"
        self.pair_focus_badge_var.set(str(badge_spec.get("text", "") or "STATE 미확인"))
        self.pair_focus_summary_var.set(f"{pair_id} / {targets} / latest={latest_state}")
        detail_parts = [
            "phase={0}".format(str(snapshot.get("CurrentPhase", "") or summary.current_phase if summary else "").strip() or "(없음)"),
            "next={0}".format(str(snapshot.get("NextAction", "") or summary.next_action if summary else "").strip() or "(없음)"),
            "rt={0}".format(int(snapshot.get("RoundtripCount", 0) or (summary.roundtrip_count if summary else 0))),
            "handoff={0}".format(int(summary.handoff_ready_count if summary else 0)),
            "zip={0}".format(int(summary.zip_count if summary else 0)),
            "fail={0}".format(int(summary.failure_count if summary else 0)),
            "run={0}".format(run_leaf),
        ]
        typed_window_summary = str(snapshot.get("TypedWindowRecoverySummary", "") or "").strip()
        if typed_window_summary:
            detail_parts.append(f"tw={typed_window_summary}")
        self.pair_focus_detail_var.set(" / ".join(detail_parts))
        if self._has_ui_attr("pair_focus_badge_label"):
            try:
                self.pair_focus_badge_label.configure(
                    text=self.pair_focus_badge_var.get(),
                    bg=str(badge_spec.get("background", "#6B7280")),
                    fg=str(badge_spec.get("foreground", "#FFFFFF")),
                )
            except Exception:
                pass

    def _launcher_wrapper_path(self) -> str:
        if self.effective_data:
            return self.effective_data.get("Config", {}).get("LauncherWrapperPath", "") or ""
        return ""

    def _binding_profile_path(self) -> str:
        if self.effective_data:
            return self.effective_data.get("Config", {}).get("BindingProfilePath", "") or ""
        return ""

    def _wrapper_audit_log_path(self) -> str:
        binding_profile_path = self._binding_profile_path().strip()
        if not binding_profile_path:
            return ""
        try:
            binding_path = Path(binding_profile_path)
        except Exception:
            return ""
        return str(binding_path.with_name(binding_path.stem + "-wrapper-events.jsonl"))

    def _archive_wrapper_audit_for_next_window_launch(self, *, reason_tag: str, action_label: str) -> str:
        audit_path = self._wrapper_audit_log_path().strip()
        if not audit_path:
            return ""
        audit_file = Path(audit_path)
        if not audit_file.exists() or not audit_file.is_file():
            return ""
        try:
            raw = audit_file.read_text(encoding="utf-8")
        except Exception as exc:
            return f"{action_label}: wrapper audit 분리 실패 ({exc})"
        if not raw.strip():
            return ""
        normalized_reason = re.sub(r"[^A-Za-z0-9._-]+", "-", str(reason_tag or "launch")).strip("-") or "launch"
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S_%f")
        archive_path = audit_file.with_name(
            f"{audit_file.stem}.{timestamp}.{normalized_reason}.prelaunch{audit_file.suffix}"
        )
        try:
            archive_path.write_text(raw, encoding="utf-8")
            audit_file.write_text("", encoding="utf-8")
        except Exception as exc:
            return f"{action_label}: wrapper audit 분리 실패 ({exc})"
        return f"{action_label}: wrapper audit 분리 완료 -> {archive_path}"

    def archive_wrapper_audit_for_next_launch(self) -> None:
        action_label = "재기동 전 창 audit 분리"
        audit_path = self._wrapper_audit_log_path().strip()
        if not audit_path:
            messagebox.showwarning("창 audit 없음", "BindingProfilePath가 없어 wrapper audit 경로를 계산하지 못했습니다.")
            return
        notice = self._archive_wrapper_audit_for_next_window_launch(
            reason_tag="manual-prepare",
            action_label=action_label,
        )
        if not notice:
            self.set_text(self.output_text, f"[wrapper audit 분리]\n{action_label}: 분리할 wrapper audit가 없습니다.\n{audit_path}")
            self.set_operator_status(
                "창 audit 분리 대기",
                "현재 wrapper audit 로그가 비어 있거나 아직 생성되지 않았습니다.",
                "마지막 결과: 창 audit 분리 대기",
            )
            self.last_result_var.set("마지막 결과: 창 audit 분리 대기")
            return
        self.set_text(self.output_text, f"[wrapper audit 분리]\n{notice}")
        self._refresh_wrapper_audit_compare_summary()
        self.set_operator_status(
            "창 audit 분리 완료",
            "다음 공식 8창 재기동부터 새 wrapper audit만 누적되도록 이전 로그를 archive로 분리했습니다.",
            "마지막 결과: 창 audit 분리 완료",
        )
        self.last_result_var.set("마지막 결과: 창 audit 분리 완료")

    def _latest_wrapper_audit_archive_path(self) -> str:
        audit_path = self._wrapper_audit_log_path().strip()
        if not audit_path:
            return ""
        audit_file = Path(audit_path)
        parent = audit_file.parent
        pattern = f"{audit_file.stem}.*.prelaunch{audit_file.suffix}"
        try:
            candidates = [path for path in parent.glob(pattern) if path.is_file()]
        except Exception:
            return ""
        if not candidates:
            return ""
        candidates.sort(
            key=lambda path: (
                path.stat().st_mtime if path.exists() else 0.0,
                str(path.name).lower(),
            ),
            reverse=True,
        )
        return str(candidates[0])

    def _wrapper_audit_payloads_from_path(self, path_value: str) -> list[dict[str, object]]:
        normalized = str(path_value or "").strip()
        if not normalized:
            return []
        path = Path(normalized)
        if not path.exists() or not path.is_file():
            return []
        try:
            lines = [line.strip() for line in path.read_text(encoding="utf-8").splitlines() if line.strip()]
        except Exception:
            return []
        return self._wrapper_audit_payloads_from_lines(lines)

    @staticmethod
    def _wrapper_audit_compare_summary_text(previous_payload: dict[str, object], current_payload: dict[str, object]) -> str:
        def _count_text(payload: dict[str, object], key: str) -> str:
            value = payload.get(key, None)
            if value is None:
                return ""
            return str(value).strip()

        fields = [
            ("event", str(previous_payload.get("event", "") or "").strip(), str(current_payload.get("event", "") or "").strip()),
            ("decision", RelayOperatorPanel._wrapper_audit_decision_text(previous_payload), RelayOperatorPanel._wrapper_audit_decision_text(current_payload)),
            ("reason", str(previous_payload.get("decision_reason", "") or "").strip(), str(current_payload.get("decision_reason", "") or "").strip()),
            ("caller", RelayOperatorPanel._wrapper_audit_caller_text(previous_payload), RelayOperatorPanel._wrapper_audit_caller_text(current_payload)),
            ("source", RelayOperatorPanel._wrapper_audit_caller_source_kind(previous_payload), RelayOperatorPanel._wrapper_audit_caller_source_kind(current_payload)),
            ("live", _count_text(previous_payload, "live_binding_count"), _count_text(current_payload, "live_binding_count")),
            ("known", _count_text(previous_payload, "existing_binding_count"), _count_text(current_payload, "existing_binding_count")),
            ("dead", _count_text(previous_payload, "dead_binding_count"), _count_text(current_payload, "dead_binding_count")),
            ("created", _count_text(previous_payload, "created_window_count"), _count_text(current_payload, "created_window_count")),
        ]
        changed = [
            f"- {label}: {before or '-'} -> {after or '-'}"
            for label, before, after in fields
            if (before or "") != (after or "")
        ]
        if not changed:
            return "핵심 변화:\n- decision / caller / source / live / known / dead / created 변화 없음"
        return "핵심 변화:\n" + "\n".join(changed)

    @staticmethod
    def _wrapper_audit_compare_badges(previous_payload: dict[str, object], current_payload: dict[str, object]) -> list[str]:
        def _count_value(payload: dict[str, object], key: str) -> int | None:
            value = payload.get(key, None)
            if value in (None, ""):
                return None
            try:
                return int(value)
            except Exception:
                return None

        badges: list[str] = []
        previous_decision = RelayOperatorPanel._wrapper_audit_decision_text(previous_payload)
        current_decision = RelayOperatorPanel._wrapper_audit_decision_text(current_payload)
        previous_stale = bool(RelayOperatorPanel._wrapper_audit_stale_binding_text(previous_payload))
        current_stale = bool(RelayOperatorPanel._wrapper_audit_stale_binding_text(current_payload))
        previous_live = _count_value(previous_payload, "live_binding_count")
        current_live = _count_value(current_payload, "live_binding_count")
        previous_caller = RelayOperatorPanel._wrapper_audit_caller_text(previous_payload)
        current_caller = RelayOperatorPanel._wrapper_audit_caller_text(current_payload)
        previous_source = RelayOperatorPanel._wrapper_audit_caller_source_kind(previous_payload)
        current_source = RelayOperatorPanel._wrapper_audit_caller_source_kind(current_payload)

        if previous_stale and current_stale:
            badges.append("stale binding 지속")
        elif previous_stale and not current_stale:
            if current_decision in {"reuse", "attach-only"} and (current_live or 0) > 0:
                badges.append("정상 재사용 전환")
            elif (current_live or 0) > 0:
                badges.append("공식 8창 회복")
            else:
                badges.append("stale 해소")
        elif not previous_stale and current_stale:
            badges.append("stale binding 발생")

        if previous_decision == "blocked" and current_decision == "blocked":
            badges.append("launch 차단 유지")
        elif previous_decision == "blocked" and current_decision in {"reuse", "attach-only"}:
            if "정상 재사용 전환" not in badges:
                badges.append("launch 허용 전환")
        elif previous_decision in {"reuse", "attach-only"} and current_decision == "blocked":
            badges.append("launch 차단 전환")

        if previous_live == 0 and (current_live or 0) > 0 and "정상 재사용 전환" not in badges and "공식 8창 회복" not in badges:
            badges.append("공식 8창 회복")
        elif (previous_live or 0) > 0 and current_live == 0 and not current_stale:
            badges.append("공식 8창 이탈")

        if previous_caller != current_caller or previous_source != current_source:
            badges.append("caller 변경")
        return badges

    @staticmethod
    def _wrapper_audit_compare_badge_summary_text(previous_payload: dict[str, object], current_payload: dict[str, object]) -> str:
        badges = RelayOperatorPanel._wrapper_audit_compare_badges(previous_payload, current_payload)
        if not badges:
            return "비교 배지: [변화 없음]"
        return "비교 배지: " + " ".join(f"[{badge}]" for badge in badges)

    @staticmethod
    def _wrapper_audit_compare_gap_text(previous_timestamp: str, current_timestamp: str) -> str:
        previous_text = str(previous_timestamp or "").strip()
        current_text = str(current_timestamp or "").strip()
        if not previous_text or not current_text:
            return ""
        try:
            previous_dt = datetime.fromisoformat(previous_text.replace("Z", "+00:00"))
            current_dt = datetime.fromisoformat(current_text.replace("Z", "+00:00"))
        except Exception:
            return ""
        total_seconds = abs(int((current_dt - previous_dt).total_seconds()))
        days, remainder = divmod(total_seconds, 86400)
        hours, remainder = divmod(remainder, 3600)
        minutes, seconds = divmod(remainder, 60)
        parts: list[str] = []
        if days:
            parts.append(f"{days}d")
        if hours:
            parts.append(f"{hours}h")
        if minutes:
            parts.append(f"{minutes}m")
        if seconds or not parts:
            parts.append(f"{seconds}s")
        return " ".join(parts[:2])

    @staticmethod
    def _wrapper_audit_compare_transition_text(previous_payload: dict[str, object], current_payload: dict[str, object], gap_text: str = "") -> str:
        badges = RelayOperatorPanel._wrapper_audit_compare_badges(previous_payload, current_payload)
        if "정상 재사용 전환" in badges or "공식 8창 회복" in badges:
            label = "회복 전환"
        elif "stale binding 지속" in badges:
            label = "stale 지속"
        elif "launch 차단 유지" in badges:
            label = "차단 유지"
        elif "launch 차단 전환" in badges:
            label = "차단 전환"
        elif "launch 허용 전환" in badges:
            label = "허용 전환"
        elif "stale binding 발생" in badges:
            label = "stale 발생"
        elif "공식 8창 이탈" in badges:
            label = "8창 이탈"
        elif "caller 변경" in badges:
            label = "caller 변경"
        else:
            label = "변화 없음"
        gap_value = str(gap_text or "").strip()
        if gap_value and label != "변화 없음":
            return f"{label} {gap_value}"
        return label

    def _wrapper_audit_compare_latest_badge_text(self) -> str:
        current_path = self._wrapper_audit_log_path().strip()
        if not current_path:
            return "최근 audit 비교: 현재 wrapper audit 경로를 계산하지 못했습니다."
        archive_path = self._latest_wrapper_audit_archive_path().strip()
        if not archive_path:
            return "최근 audit 비교: 비교 전 archive가 아직 없습니다."
        previous_payloads = self._wrapper_audit_payloads_from_path(archive_path)
        if not previous_payloads:
            return "최근 audit 비교: 이전 prelaunch archive에 비교할 이벤트가 없습니다."
        current_payloads = self._wrapper_audit_payloads_from_path(current_path)
        if not current_payloads:
            return "최근 audit 비교: 현재 wrapper audit에 비교할 이벤트가 없습니다."
        current_payload = current_payloads[-1]
        previous_payload = previous_payloads[-1]
        summary = self._wrapper_audit_compare_badge_summary_text(previous_payload, current_payload).strip()
        if not summary:
            return "최근 audit 비교: [변화 없음]"
        previous_timestamp = str(previous_payload.get("timestamp", "") or "").strip()
        current_timestamp = str(current_payload.get("timestamp", "") or "").strip()
        gap_text = self._wrapper_audit_compare_gap_text(previous_timestamp, current_timestamp)
        transition_text = self._wrapper_audit_compare_transition_text(previous_payload, current_payload, gap_text)
        text = f"최근 audit 비교: {transition_text} / " + summary.replace("비교 배지:", "", 1).strip()
        if previous_timestamp:
            text = f"{text} / prev={previous_timestamp}"
        if current_timestamp:
            text = f"{text} / at={current_timestamp}"
        return text

    def _wrapper_audit_compare_transition_summary_text(self, previous_payload: dict[str, object], current_payload: dict[str, object]) -> str:
        previous_timestamp = str(previous_payload.get("timestamp", "") or "").strip()
        current_timestamp = str(current_payload.get("timestamp", "") or "").strip()
        gap_text = self._wrapper_audit_compare_gap_text(previous_timestamp, current_timestamp)
        transition_text = self._wrapper_audit_compare_transition_text(previous_payload, current_payload, gap_text)
        parts = [f"비교 전환: {transition_text}"]
        if previous_timestamp:
            parts.append(f"prev={previous_timestamp}")
        if current_timestamp:
            parts.append(f"at={current_timestamp}")
        return " / ".join(parts)

    def open_latest_wrapper_audit_archive(self) -> None:
        archive_path = self._latest_wrapper_audit_archive_path().strip()
        if not archive_path:
            messagebox.showwarning("이전 창 audit 없음", "열 수 있는 prelaunch wrapper audit archive가 없습니다.")
            return
        self._open_path(archive_path, kind="이전 창 audit archive")
        if self._has_ui_attr("output_text"):
            self.set_text(self.output_text, f"[wrapper audit archive]\n가장 최근 prelaunch archive:\n{archive_path}")
        self._refresh_wrapper_audit_compare_summary()
        self.set_operator_status(
            "이전 창 audit 열기",
            "가장 최근 prelaunch wrapper audit archive를 열었습니다.",
            "마지막 결과: 이전 창 audit 열기",
        )
        self.last_result_var.set("마지막 결과: 이전 창 audit 열기")

    def compare_wrapper_audit_with_latest_archive(self) -> None:
        current_path = self._wrapper_audit_log_path().strip()
        archive_path = self._latest_wrapper_audit_archive_path().strip()
        if not current_path:
            messagebox.showwarning("창 audit 없음", "BindingProfilePath가 없어 현재 wrapper audit 경로를 계산하지 못했습니다.")
            return
        if not archive_path:
            messagebox.showwarning("이전 창 audit 없음", "비교할 prelaunch wrapper audit archive가 없습니다.")
            return
        previous_payloads = self._wrapper_audit_payloads_from_path(archive_path)
        current_payloads = self._wrapper_audit_payloads_from_path(current_path)
        if not previous_payloads:
            messagebox.showwarning("이전 창 audit 비어 있음", f"이전 prelaunch archive에 비교할 이벤트가 없습니다.\n{archive_path}")
            return
        if not current_payloads:
            messagebox.showwarning("현재 창 audit 비어 있음", f"현재 wrapper audit에 비교할 이벤트가 없습니다.\n{current_path}")
            return
        previous_payload = previous_payloads[-1]
        current_payload = current_payloads[-1]
        lines = [
            "[wrapper audit 비교]",
            self._wrapper_audit_compare_transition_summary_text(previous_payload, current_payload),
            "",
            f"이전 prelaunch archive: {archive_path}",
            self._format_wrapper_audit_event_line(previous_payload),
            "",
            f"현재 wrapper audit: {current_path}",
            self._format_wrapper_audit_event_line(current_payload),
            "",
            self._wrapper_audit_compare_badge_summary_text(previous_payload, current_payload),
            "",
            self._wrapper_audit_compare_summary_text(previous_payload, current_payload),
        ]
        self.set_text(self.output_text, "\n".join(lines).strip())
        self._refresh_wrapper_audit_compare_summary()
        self.set_operator_status(
            "창 audit 비교 완료",
            "직전 prelaunch archive와 현재 wrapper audit latest를 비교했습니다.",
            "마지막 결과: 창 audit 비교 완료",
        )
        self.last_result_var.set("마지막 결과: 창 audit 비교 완료")

    def _wrapper_audit_summary_text(self) -> str:
        audit_path = self._wrapper_audit_log_path().strip()
        if not audit_path:
            return "창 audit: BindingProfilePath가 없어 wrapper audit 경로를 계산하지 못했습니다."
        audit_file = Path(audit_path)
        if not audit_file.exists():
            return f"창 audit: 로그 없음 ({audit_path})"
        try:
            lines = [line.strip() for line in audit_file.read_text(encoding='utf-8').splitlines() if line.strip()]
        except Exception as exc:
            return f"창 audit: 로그 읽기 실패 ({exc})"
        if not lines:
            return f"창 audit: 로그 비어 있음 ({audit_path})"
        try:
            payload = json.loads(lines[-1])
        except Exception as exc:
            return f"창 audit: 최신 이벤트 파싱 실패 ({exc})"
        payloads = self._wrapper_audit_payloads_from_lines(lines)
        duplicate_risk = self._wrapper_audit_duplicate_suspicion_text(payloads)
        guidance = self._wrapper_audit_guidance_text(payloads)
        event = str(payload.get("event", "") or "(unknown)")
        timestamp = str(payload.get("timestamp", "") or "(time unknown)")
        decision = self._wrapper_audit_decision_text(payload)
        decision_reason = str(payload.get("decision_reason", "") or "").strip()
        invocation_id = str(payload.get("invocation_id", "") or "").strip()
        live_binding_count = payload.get("live_binding_count", "")
        existing_binding_count = payload.get("existing_binding_count", "")
        existing_wrapper_shell_count = payload.get("existing_wrapper_shell_count", "")
        created_window_count = payload.get("created_window_count", "")
        parts = [f"창 audit: {event} @ {timestamp}"]
        if duplicate_risk:
            parts.append(duplicate_risk)
        if guidance:
            parts.append(guidance)
        caller_text = self._wrapper_audit_caller_text(payload)
        if caller_text:
            parts.append(caller_text)
        caller_source_kind = self._wrapper_audit_caller_source_kind(payload)
        if caller_source_kind and caller_source_kind not in {"panel", "launcher", "external"}:
            parts.append(f"source={caller_source_kind}")
        parent_label = self._wrapper_audit_parent_process_label(payload)
        if parent_label and caller_source_kind in {"launcher", "external", "external-bat", "external-shortcut", "external-shell"}:
            parts.append(f"parent={parent_label}")
        if decision:
            parts.append(f"decision={decision}")
        if invocation_id:
            parts.append(f"inv={invocation_id[:8]}")
        if decision_reason:
            parts.append(f"reason={decision_reason}")
        if live_binding_count != "":
            parts.append(f"live={live_binding_count}")
        if existing_binding_count != "":
            parts.append(f"known={existing_binding_count}")
        if existing_wrapper_shell_count != "":
            parts.append(f"shells={existing_wrapper_shell_count}")
        if created_window_count != "":
            parts.append(f"created={created_window_count}")
        stale_binding_text = self._wrapper_audit_stale_binding_text(payload)
        if stale_binding_text:
            parts.append(stale_binding_text)
        return " / ".join(parts)

    @staticmethod
    def _format_wrapper_audit_event_line(payload: dict[str, object]) -> str:
        event = str(payload.get("event", "") or "(unknown)")
        timestamp = str(payload.get("timestamp", "") or "(time unknown)")
        decision = RelayOperatorPanel._wrapper_audit_decision_text(payload)
        decision_reason = str(payload.get("decision_reason", "") or "").strip()
        invocation_id = str(payload.get("invocation_id", "") or "").strip()
        live_binding_count = payload.get("live_binding_count", "")
        existing_binding_count = payload.get("existing_binding_count", "")
        existing_wrapper_shell_count = payload.get("existing_wrapper_shell_count", "")
        created_window_count = payload.get("created_window_count", "")
        if "reuse" in event:
            category = "REUSE"
        elif "block" in event or "skip" in event or "stale" in event:
            category = "BLOCKED"
        elif "replace" in event or "close" in event:
            category = "REPLACE"
        elif "launch" in event or "spawn" in event or "create" in event:
            category = "LAUNCH"
        elif "error" in event or "fail" in event:
            category = "ERROR"
        else:
            category = "STATE"
        parts = [f"[{category}] {event} @ {timestamp}"]
        caller_text = RelayOperatorPanel._wrapper_audit_caller_text(payload)
        if caller_text:
            parts.append(caller_text)
        caller_source_kind = RelayOperatorPanel._wrapper_audit_caller_source_kind(payload)
        if caller_source_kind and caller_source_kind not in {"panel", "launcher", "external"}:
            parts.append(f"source={caller_source_kind}")
        if decision:
            parts.append(f"decision={decision}")
        if invocation_id:
            parts.append(f"inv={invocation_id[:8]}")
        if decision_reason:
            parts.append(f"reason={decision_reason}")
        if live_binding_count != "":
            parts.append(f"live={live_binding_count}")
        if existing_binding_count != "":
            parts.append(f"known={existing_binding_count}")
        if existing_wrapper_shell_count != "":
            parts.append(f"shells={existing_wrapper_shell_count}")
        if created_window_count != "":
            parts.append(f"created={created_window_count}")
        stale_binding_text = RelayOperatorPanel._wrapper_audit_stale_binding_text(payload)
        if stale_binding_text:
            parts.append(stale_binding_text)
        return " / ".join(parts)

    @staticmethod
    def _wrapper_audit_decision_text(payload: dict[str, object]) -> str:
        explicit = str(payload.get("decision", "") or "").strip().lower()
        if explicit:
            return explicit
        event = str(payload.get("event", "") or "").strip().lower()
        if event == "invoke":
            return "inspect"
        if "reuse" in event:
            return "reuse"
        if "attach" in event:
            return "attach-only"
        if "block" in event or "skip" in event or "stale" in event:
            return "blocked"
        if "replace" in event or "close" in event:
            return "replace"
        if "launch" in event or "spawn" in event or "create" in event:
            return "launch"
        if "error" in event or "fail" in event:
            return "error"
        return ""

    @staticmethod
    def _wrapper_audit_caller_text(payload: dict[str, object]) -> str:
        parent_pid = str(payload.get("parent_pid", "") or "").strip()
        parent_name = str(payload.get("parent_process_name", "") or "").strip()
        parent_command_line = str(payload.get("parent_command_line", "") or "").strip().lower()
        caller_kind = ""
        if "relay_operator_panel.py" in parent_command_line:
            caller_kind = "panel"
        elif "s_8windows_left_monitor" in parent_command_line or "codex_visible.py" in parent_command_line:
            caller_kind = "launcher"
        elif parent_name or parent_pid:
            caller_kind = "external"
        if not caller_kind and not parent_name and not parent_pid:
            return ""
        process_label = parent_name or "unknown"
        pid_label = parent_pid or "?"
        return f"caller={caller_kind}({process_label}#{pid_label})"

    @staticmethod
    def _wrapper_audit_caller_source_kind(payload: dict[str, object] | None) -> str:
        base_kind = RelayOperatorPanel._wrapper_audit_caller_kind(payload)
        if base_kind != "external":
            return base_kind
        if not isinstance(payload, dict):
            return "external"
        parent_name = str(payload.get("parent_process_name", "") or "").strip().lower()
        parent_command_line = str(payload.get("parent_command_line", "") or "").strip().lower()
        if ".lnk" in parent_command_line or parent_name == "explorer.exe":
            return "external-shortcut"
        if ".bat" in parent_command_line or ".cmd" in parent_command_line:
            return "external-bat"
        if parent_name in {"cmd.exe", "powershell.exe", "pwsh.exe", "windowsterminal.exe", "wt.exe"}:
            return "external-shell"
        return "external"

    @staticmethod
    def _wrapper_audit_parent_process_label(payload: dict[str, object]) -> str:
        if not isinstance(payload, dict):
            return ""
        parent_pid = str(payload.get("parent_pid", "") or "").strip()
        parent_name = str(payload.get("parent_process_name", "") or "").strip() or "unknown"
        if not parent_name and not parent_pid:
            return ""
        return f"{parent_name}#{parent_pid or '?'}"

    @staticmethod
    def _wrapper_audit_parent_process_highlight_lines(payload: dict[str, object]) -> list[str]:
        caller_kind = RelayOperatorPanel._wrapper_audit_caller_source_kind(payload)
        if caller_kind not in {"launcher", "external", "external-bat", "external-shortcut", "external-shell"}:
            return []
        parent_label = RelayOperatorPanel._wrapper_audit_parent_process_label(payload)
        parent_command_line = str(payload.get("parent_command_line", "") or "").strip()
        lines = [f"부모 호출자: {caller_kind} / {parent_label or 'unknown#?'}"]
        if parent_command_line:
            lines.append(f"실행줄: {parent_command_line}")
        return lines

    @staticmethod
    def _wrapper_audit_stale_binding_text(payload: dict[str, object] | None) -> str:
        if not isinstance(payload, dict):
            return ""
        try:
            live_binding_count = int(payload.get("live_binding_count", "") or 0)
        except Exception:
            live_binding_count = 0
        try:
            existing_binding_count = int(payload.get("existing_binding_count", "") or 0)
        except Exception:
            existing_binding_count = 0
        try:
            dead_binding_count = int(payload.get("dead_binding_count", "") or 0)
        except Exception:
            dead_binding_count = 0
        event = str(payload.get("event", "") or "").strip()
        decision_reason = str(payload.get("decision_reason", "") or "").strip()
        binding_updated_at = str(payload.get("binding_profile_updated_at", "") or "").strip()
        if existing_binding_count <= 0:
            return ""
        if not (
            event == "stale_bindings_detected"
            or (live_binding_count == 0 and decision_reason == "binding_shells_not_running")
        ):
            return ""
        parts = [f"stale=공식 8창 셸 종료 감지(known={existing_binding_count}, live={live_binding_count})"]
        if dead_binding_count > 0:
            parts.append(f"dead={dead_binding_count}")
        if binding_updated_at:
            parts.append(f"binding_at={binding_updated_at}")
        return " / ".join(parts)

    def _wrapper_audit_latest_decision_summary_text(self, payload: dict[str, object] | None = None) -> str:
        current_payload = payload if isinstance(payload, dict) else self._wrapper_audit_latest_payload()
        if not current_payload:
            return ""
        event = str(current_payload.get("event", "") or "").strip()
        caller_text = self._wrapper_audit_caller_text(current_payload)
        caller_source_kind = self._wrapper_audit_caller_source_kind(current_payload)
        decision_text = self._wrapper_audit_decision_text(current_payload)
        decision_reason = str(current_payload.get("decision_reason", "") or "").strip()
        parts = ["최근 wrapper audit:"]
        if event:
            parts.append(f"event={event}")
        if caller_text:
            parts.append(caller_text)
        if caller_source_kind and caller_source_kind not in {"panel", "launcher", "external"}:
            parts.append(f"source={caller_source_kind}")
        if decision_text:
            parts.append(f"decision={decision_text}")
        if decision_reason:
            parts.append(f"reason={decision_reason}")
        stale_binding_text = self._wrapper_audit_stale_binding_text(current_payload)
        if stale_binding_text:
            parts.append(stale_binding_text)
        if len(parts) <= 1:
            return ""
        return " ".join([parts[0], " / ".join(parts[1:])])

    def _current_output_text_value(self) -> str:
        widget = self.__dict__.get("output_text")
        if widget is not None:
            try:
                return str(widget.get("1.0", "end-1c") or "").strip()
            except Exception:
                pass
        return str(self.__dict__.get("_captured_output", "") or "").strip()

    def _window_guard_wrapper_compare_text(self, guard_decision: str, payload: dict[str, object] | None) -> str:
        if not isinstance(payload, dict):
            return ""
        wrapper_decision = self._wrapper_audit_decision_text(payload)
        caller_text = self._wrapper_audit_caller_text(payload)
        caller_source_kind = self._wrapper_audit_caller_source_kind(payload)
        if not wrapper_decision:
            return ""
        guard_label = self._window_guard_decision_label(guard_decision)
        compare_text = f"비교: panel guard={guard_label} / latest wrapper={wrapper_decision}"
        if caller_text:
            compare_text += f" / {caller_text}"
        if caller_source_kind and caller_source_kind not in {"panel", "launcher", "external"}:
            compare_text += f" / source={caller_source_kind}"
        if guard_decision == "block" and wrapper_decision == "blocked":
            compare_text += " / 차단 축이 일치합니다."
        elif guard_decision == "reroute-attach" and wrapper_decision in {"reuse", "attach-only"}:
            compare_text += " / 재사용·attach 축이 대체로 일치합니다."
        elif guard_decision != "allow" and wrapper_decision not in {"reuse", "attach-only", "blocked"}:
            compare_text += " / panel 판단과 다른 축이므로 caller/binding 상태를 다시 확인하세요."
        return compare_text

    def _wrapper_audit_caller_summary_text(self) -> str:
        payload = self._wrapper_audit_latest_payload()
        if not payload:
            return "최근 wrapper caller: 아직 caller/decision 정보를 읽지 않았습니다."
        caller_text = self._wrapper_audit_caller_text(payload)
        caller_source_kind = self._wrapper_audit_caller_source_kind(payload)
        decision_text = self._wrapper_audit_decision_text(payload)
        decision_reason = str(payload.get("decision_reason", "") or "").strip()
        timestamp = str(payload.get("timestamp", "") or "").strip()
        parts = ["최근 wrapper caller:"]
        if caller_text:
            parts.append(caller_text)
        if caller_source_kind and caller_source_kind not in {"panel", "launcher", "external"}:
            parts.append(f"source={caller_source_kind}")
        if decision_text:
            parts.append(f"decision={decision_text}")
        if decision_reason:
            parts.append(f"reason={decision_reason}")
        if timestamp:
            parts.append(f"at={timestamp}")
        if len(parts) <= 1:
            return parts[0]
        return parts[0] + " " + " / ".join(parts[1:])

    @staticmethod
    def _wrapper_audit_caller_kind(payload: dict[str, object] | None) -> str:
        if not isinstance(payload, dict):
            return ""
        parent_name = str(payload.get("parent_process_name", "") or "").strip()
        parent_command_line = str(payload.get("parent_command_line", "") or "").strip().lower()
        if "relay_operator_panel.py" in parent_command_line:
            return "panel"
        if "s_8windows_left_monitor" in parent_command_line or "codex_visible.py" in parent_command_line:
            return "launcher"
        if parent_name or str(payload.get("parent_pid", "") or "").strip():
            return "external"
        return ""

    def _wrapper_audit_caller_badge_text(self) -> str:
        caller_kind = self._wrapper_audit_caller_source_kind(self._wrapper_audit_latest_payload())
        if not caller_kind:
            return "CALLER 미확인"
        if caller_kind == "external-bat":
            return "CALLER EXT-BAT"
        if caller_kind == "external-shortcut":
            return "CALLER EXT-LNK"
        if caller_kind == "external-shell":
            return "CALLER EXT-SHELL"
        return f"CALLER {caller_kind.upper()}"

    def _wrapper_caller_badge_action_spec(self) -> tuple[str, str]:
        caller_kind = self._wrapper_audit_caller_source_kind(self._wrapper_audit_latest_payload())
        primary_key = str(self.__dict__.get("_wrapper_guidance_action_key", "") or "").strip()
        secondary_key = str(self.__dict__.get("_wrapper_guidance_secondary_action_key", "") or "").strip()
        if caller_kind in {"external-bat", "external-shortcut", "external-shell"}:
            label_prefix = {
                "external-bat": ".bat caller",
                "external-shortcut": "바로가기 caller",
                "external-shell": "셸 caller",
            }.get(caller_kind, "외부 caller")
            if secondary_key:
                return f"{label_prefix} 증거 묶음 열기", "run_wrapper_guidance_secondary_action"
            if primary_key:
                return f"{label_prefix} 1차 가이드 열기", "run_wrapper_guidance_action"
            return "창 audit 로그 열기", "open_wrapper_audit_log"
        if caller_kind == "launcher" or caller_kind.startswith("external"):
            if secondary_key:
                return "외부 caller 증거 묶음 열기", "run_wrapper_guidance_secondary_action"
            if primary_key:
                return "외부 caller 1차 가이드 열기", "run_wrapper_guidance_action"
            return "창 audit 로그 열기", "open_wrapper_audit_log"
        if caller_kind == "panel":
            if primary_key:
                return "panel caller 1차 가이드 열기", "run_wrapper_guidance_action"
            if secondary_key:
                return "panel caller 증거 묶음 열기", "run_wrapper_guidance_secondary_action"
            return "창 audit 로그 열기", "open_wrapper_audit_log"
        if secondary_key:
            return "최근 caller 증거 묶음 열기", "run_wrapper_guidance_secondary_action"
        if primary_key:
            return "최근 caller 1차 가이드 열기", "run_wrapper_guidance_action"
        return "창 audit 로그 열기", "open_wrapper_audit_log"

    def run_wrapper_audit_caller_badge_action(self, _event: object | None = None) -> None:
        action_label, runner_name = self._wrapper_caller_badge_action_spec()
        payload = self._wrapper_audit_latest_payload()
        runner = getattr(self, runner_name, None)
        if callable(runner):
            runner()
        highlight_lines = self._wrapper_audit_parent_process_highlight_lines(payload or {})
        if highlight_lines and self._has_ui_attr("output_text"):
            existing_output = self._current_output_text_value()
            lines = ["최근 wrapper caller 강조:"]
            lines.extend(highlight_lines)
            if existing_output:
                lines.extend(["", existing_output])
            self.set_text(self.output_text, "\n".join(lines).strip())
        if self._has_ui_attr("operator_status_var"):
            self.set_operator_status(
                "최근 wrapper caller 증거 열기",
                f"{action_label}\n{self._wrapper_audit_caller_summary_text()}".strip(),
                f"마지막 결과: {action_label}",
            )

    def _refresh_wrapper_audit_caller_badge(self) -> None:
        if self._has_ui_attr("wrapper_audit_caller_var"):
            self.wrapper_audit_caller_var.set(self._wrapper_audit_caller_summary_text())
        if self._has_ui_attr("wrapper_audit_caller_badge_var"):
            badge_text = self._wrapper_audit_caller_badge_text()
            self.wrapper_audit_caller_badge_var.set(badge_text)
            badge_label = self.__dict__.get("wrapper_audit_caller_badge_label")
            if badge_label is not None:
                caller_kind = self._wrapper_audit_caller_source_kind(self._wrapper_audit_latest_payload())
                background, foreground = self._wrapper_caller_badge_palette(caller_kind)
                try:
                    badge_label.configure(
                        text=badge_text,
                        bg=background,
                        fg=foreground,
                    )
                except Exception:
                    pass

    def _refresh_wrapper_audit_compare_summary(self) -> None:
        if self._has_ui_attr("wrapper_audit_compare_var"):
            self.wrapper_audit_compare_var.set(self._wrapper_audit_compare_latest_badge_text())

    def _wrapper_audit_payloads(self) -> list[dict[str, object]]:
        audit_path = self._wrapper_audit_log_path().strip()
        if not audit_path:
            return []
        audit_file = Path(audit_path)
        if not audit_file.exists():
            return []
        try:
            lines = [line.strip() for line in audit_file.read_text(encoding="utf-8").splitlines() if line.strip()]
        except Exception:
            return []
        return self._wrapper_audit_payloads_from_lines(lines)

    def _wrapper_audit_latest_payload(self) -> dict[str, object] | None:
        payloads = self._wrapper_audit_payloads()
        if not payloads:
            return None
        return payloads[-1]

    @staticmethod
    def _wrapper_audit_payloads_from_lines(lines: list[str]) -> list[dict[str, object]]:
        payloads: list[dict[str, object]] = []
        for line in lines:
            try:
                payload = json.loads(line)
            except Exception:
                continue
            if isinstance(payload, dict):
                payloads.append(payload)
        return payloads

    @staticmethod
    def _wrapper_audit_recent_decision_timeline(payloads: list[dict[str, object]], *, limit: int = 3) -> list[str]:
        timeline: list[str] = []
        for payload in payloads[-max(int(limit or 0), 1):]:
            timestamp = str(payload.get("timestamp", "") or "(time unknown)")
            event = str(payload.get("event", "") or "(unknown)")
            decision = RelayOperatorPanel._wrapper_audit_decision_text(payload) or event
            caller_text = RelayOperatorPanel._wrapper_audit_caller_text(payload)
            caller_source_kind = RelayOperatorPanel._wrapper_audit_caller_source_kind(payload)
            decision_reason = str(payload.get("decision_reason", "") or "").strip()
            parts = [f"{timestamp} -> {decision} ({event})"]
            if caller_text:
                parts.append(caller_text)
            if caller_source_kind and caller_source_kind not in {"panel", "launcher", "external"}:
                parts.append(f"source={caller_source_kind}")
            if decision_reason:
                parts.append(f"reason={decision_reason}")
            timeline.append(" / ".join(parts))
        return timeline

    @staticmethod
    def _wrapper_audit_duplicate_suspicion_text(payloads: list[dict[str, object]]) -> str:
        if not payloads:
            return ""
        recent_payloads = payloads[-6:]
        launch_count = 0
        invoke_count = 0
        duplicate_block_count = 0
        wrapper_shell_block_count = 0
        partial_binding_block_count = 0
        replace_close_failed_count = 0
        for payload in recent_payloads:
            event = str(payload.get("event", "") or "").strip()
            decision_reason = str(payload.get("decision_reason", "") or "").strip()
            if event == "invoke":
                invoke_count += 1
            if event == "launch_complete":
                launch_count += 1
            if event == "launch_blocked" and decision_reason in {"wrapper_shells_already_running", "partial_existing_bindings"}:
                duplicate_block_count += 1
            if event == "launch_blocked" and decision_reason == "wrapper_shells_already_running":
                wrapper_shell_block_count += 1
            if event == "launch_blocked" and decision_reason == "partial_existing_bindings":
                partial_binding_block_count += 1
            if event == "replace_existing_close_failed":
                replace_close_failed_count += 1
        if wrapper_shell_block_count >= 1 and invoke_count >= 2:
            return "중복 호출 의심: wrapper가 이미 실행 중인데 다시 invoke되었습니다. 원인=wrapper shell 중복"
        if partial_binding_block_count >= 1:
            return "중복 호출 의심: 기존 binding 일부가 남은 상태에서 다시 호출되었습니다. 원인=partial binding 잔존"
        if replace_close_failed_count >= 1:
            return "중복 호출 의심: replace 과정에서 기존 창 종료가 끝나기 전에 재호출되었습니다. 원인=replace close 실패"
        if launch_count >= 2:
            return "중복 호출 의심: 최근 wrapper launch가 반복되었습니다. 원인=launch 반복"
        if duplicate_block_count >= 2:
            return "중복 호출 의심: 기존 wrapper shell/binding이 살아 있는 상태에서 재호출이 반복되었습니다. 원인=중복 재호출"
        return ""

    @staticmethod
    def _wrapper_audit_guidance_text(payloads: list[dict[str, object]]) -> str:
        suspicion = RelayOperatorPanel._wrapper_audit_duplicate_suspicion_text(payloads)
        latest_payload = payloads[-1] if payloads else {}
        stale_binding_text = RelayOperatorPanel._wrapper_audit_stale_binding_text(latest_payload)
        caller_source_kind = RelayOperatorPanel._wrapper_audit_caller_source_kind(latest_payload)
        source_guidance = ""
        if caller_source_kind == "external-bat":
            source_guidance = "호출자 가이드: 외부 .bat/.cmd 시작 스크립트와 panel 동시 실행, start-visible-lane 계열 wrapper 중복 호출을 먼저 확인하세요."
        elif caller_source_kind == "external-shortcut":
            source_guidance = "호출자 가이드: Windows 바로가기(.lnk) 또는 Explorer 시작 경로에서 panel과 wrapper를 함께 띄우는지 먼저 확인하세요."
        elif caller_source_kind == "external-shell":
            source_guidance = "호출자 가이드: 수동 cmd/powershell/pwsh 셸에서 wrapper 재실행 또는 이전 세션 잔존 여부를 먼저 확인하세요."
        elif caller_source_kind == "launcher":
            source_guidance = "호출자 가이드: launcher 스크립트가 panel 외부에서 wrapper를 다시 부르는지 먼저 확인하세요."
        stale_guidance = ""
        if stale_binding_text:
            stale_guidance = (
                "가이드: binding에는 공식 8창 기록이 남았지만 현재 live 셸은 0입니다. "
                "마지막 binding 갱신 이후 수동 종료, Windows Terminal 종료, 강제 종료 중 하나일 수 있습니다. "
                "현재 로그만으로 종료 원인은 확정할 수 없으니 binding/audit 시각을 확인한 뒤 공식 8창만 재기동하세요."
            )
        if not suspicion:
            return f"{stale_guidance} {source_guidance}".strip()
        if "원인=wrapper shell 중복" in suspicion or "원인=launch 반복" in suspicion:
            base_guidance = "가이드: panel 시작만으로는 공식 8창 launch가 반복되지 않습니다. 외부 bat/shortcut/복구 루프의 wrapper 중복 호출 경로를 먼저 확인하세요."
            return f"{stale_guidance} {base_guidance} {source_guidance}".strip()
        if "원인=partial binding 잔존" in suspicion:
            base_guidance = "가이드: 공식 8창 일부가 binding에 남아 있습니다. 새 창을 더 띄우기보다 binding-managed 8창 재사용/정리 상태를 먼저 맞추세요."
            return f"{stale_guidance} {base_guidance} {source_guidance}".strip()
        if "원인=replace close 실패" in suspicion:
            base_guidance = "가이드: replace 절차에서 기존 binding 창 종료가 끝나지 않았습니다. binding JSON 기준 남은 HWND와 공식 8창 종료 상태부터 확인하세요."
            return f"{stale_guidance} {base_guidance} {source_guidance}".strip()
        if "원인=중복 재호출" in suspicion:
            base_guidance = "가이드: 기존 wrapper shell 또는 binding이 살아 있는 상태입니다. panel보다 외부 호출자 중복 실행과 기존 세션 정리 상태를 먼저 확인하세요."
            return f"{stale_guidance} {base_guidance} {source_guidance}".strip()
        return f"{stale_guidance} {source_guidance}".strip()

    @staticmethod
    def _wrapper_guidance_action_label(
        action_key: str,
        *,
        secondary: bool = False,
        caller_source_kind: str = "",
        ordered_action_keys: tuple[str, ...] = (),
    ) -> str:
        prefix = "보조 가이드" if secondary else "가이드"
        caller_suffix_map = {
            "external-bat": "(.bat caller)",
            "external-shortcut": "(.lnk caller)",
            "external-shell": "(셸 caller)",
            "launcher": "(launcher caller)",
        }
        caller_suffix = caller_suffix_map.get(str(caller_source_kind or "").strip(), "")
        if secondary and action_key == "open_guidance_bundle":
            if ordered_action_keys:
                short_map = {
                    "open_binding_profile": "binding",
                    "open_wrapper_audit": "audit",
                    "open_watcher_status": "status",
                }
                ordered = [short_map.get(key, key) for key in ordered_action_keys if short_map.get(key, key)]
                if ordered:
                    return f"{prefix}: {' -> '.join(ordered)} 묶음 열기 {caller_suffix}".strip()
            return f"{prefix}: 관련 파일 묶음 열기 {caller_suffix}".strip()
        if caller_source_kind == "external-bat" and action_key == "open_wrapper_audit":
            return f"{prefix}: audit 먼저 열기 {caller_suffix}".strip()
        if caller_source_kind == "external-shortcut" and action_key == "open_binding_profile":
            return f"{prefix}: binding 먼저 열기 {caller_suffix}".strip()
        if caller_source_kind == "external-shell" and action_key == "open_watcher_status":
            return f"{prefix}: status 먼저 열기 {caller_suffix}".strip()
        if caller_source_kind == "launcher" and action_key == "open_wrapper_audit":
            return f"{prefix}: audit 먼저 열기 {caller_suffix}".strip()
        mapping = {
            "open_binding_profile": f"{prefix}: binding JSON 열기",
            "open_wrapper_audit": f"{prefix}: 창 audit 로그 열기",
            "open_watcher_status": f"{prefix}: watch status 열기",
            "open_guidance_bundle": f"{prefix}: 관련 파일 묶음 열기",
        }
        return mapping.get(action_key, "보조 가이드 없음" if secondary else "가이드 없음")

    def _wrapper_audit_guidance_action_specs(self) -> tuple[tuple[str, str], tuple[str, str]]:
        audit_path = self._wrapper_audit_log_path().strip()
        binding_path = self._binding_profile_path().strip()
        status_path = ""
        controller = self.__dict__.get("watcher_controller")
        if controller is not None and hasattr(controller, "runtime_status"):
            try:
                status_path = str(getattr(self._watcher_runtime_status(), "status_path", "") or "").strip()
            except Exception:
                status_path = ""
        if not audit_path and not binding_path and not status_path:
            return ("가이드 없음", ""), ("보조 가이드 없음", "")
        payloads: list[dict[str, object]] = []
        if audit_path:
            audit_file = Path(audit_path)
            if audit_file.exists() and audit_file.is_file():
                try:
                    lines = [line.strip() for line in audit_file.read_text(encoding="utf-8").splitlines() if line.strip()]
                except Exception:
                    lines = []
                payloads = self._wrapper_audit_payloads_from_lines(lines)
        suspicion = self._wrapper_audit_duplicate_suspicion_text(payloads)
        caller_source_kind = self._wrapper_audit_caller_source_kind(payloads[-1] if payloads else {})
        stale_binding_text = self._wrapper_audit_stale_binding_text(payloads[-1] if payloads else {})
        if stale_binding_text:
            preferred = ["open_wrapper_audit", "open_binding_profile", "open_watcher_status"]
        elif "원인=partial binding 잔존" in suspicion or "원인=replace close 실패" in suspicion:
            preferred = ["open_binding_profile", "open_wrapper_audit", "open_watcher_status"]
        elif suspicion:
            preferred = ["open_wrapper_audit", "open_watcher_status", "open_binding_profile"]
        elif caller_source_kind == "external-shortcut":
            preferred = ["open_binding_profile", "open_wrapper_audit", "open_watcher_status"]
        elif caller_source_kind == "external-shell":
            preferred = ["open_watcher_status", "open_wrapper_audit", "open_binding_profile"]
        elif caller_source_kind in {"external-bat", "external-shortcut", "external-shell", "launcher"}:
            preferred = ["open_wrapper_audit", "open_watcher_status", "open_binding_profile"]
        elif status_path:
            preferred = ["open_watcher_status", "open_wrapper_audit", "open_binding_profile"]
        else:
            preferred = ["open_wrapper_audit", "open_binding_profile", "open_watcher_status"]
        available = {
            "open_binding_profile": binding_path,
            "open_wrapper_audit": audit_path,
            "open_watcher_status": status_path,
        }
        selected = [action_key for action_key in preferred if available.get(action_key)]
        if not selected:
            return ("가이드 없음", ""), ("보조 가이드 없음", "")
        primary_key = selected[0]
        bundle_paths = tuple(dict.fromkeys(available[action_key] for action_key in selected if available.get(action_key)))
        secondary_key = "open_guidance_bundle" if len(bundle_paths) >= 2 else ""
        self._wrapper_guidance_secondary_bundle_paths = bundle_paths
        secondary_label = (
            f"보조 가이드: 관련 파일 {len(bundle_paths)}개 열기"
            if secondary_key
            else "보조 가이드 없음"
        )
        return (
            self._wrapper_guidance_action_label(primary_key, caller_source_kind=caller_source_kind),
            primary_key,
        ), (
            self._wrapper_guidance_action_label(
                secondary_key,
                secondary=True,
                caller_source_kind=caller_source_kind,
                ordered_action_keys=tuple(selected),
            ) if secondary_key else secondary_label,
            secondary_key,
        )

    def _refresh_wrapper_guidance_action(self) -> None:
        self._wrapper_guidance_secondary_bundle_paths = ()
        primary, secondary = self._wrapper_audit_guidance_action_specs()
        self._wrapper_guidance_action_key = primary[1]
        self._wrapper_guidance_secondary_action_key = secondary[1]
        if self._has_ui_attr("wrapper_guidance_action_var"):
            self.wrapper_guidance_action_var.set(primary[0])
        if self._has_ui_attr("wrapper_guidance_secondary_action_var"):
            self.wrapper_guidance_secondary_action_var.set(secondary[0])

    def run_wrapper_guidance_action(self) -> None:
        action_key = str(self.__dict__.get("_wrapper_guidance_action_key", "") or "").strip()
        self._run_wrapper_guidance_action_key(action_key)

    def run_wrapper_guidance_secondary_action(self) -> None:
        action_key = str(self.__dict__.get("_wrapper_guidance_secondary_action_key", "") or "").strip()
        self._run_wrapper_guidance_action_key(action_key)

    def _run_wrapper_guidance_action_key(self, action_key: str) -> None:
        if action_key == "open_guidance_bundle":
            self.open_wrapper_guidance_bundle()
            return
        if action_key == "open_binding_profile":
            self.open_binding_profile_file()
            return
        if action_key == "open_watcher_status":
            self.open_watcher_status_file()
            return
        if action_key == "open_wrapper_audit":
            self.open_wrapper_audit_log()
            return

    def open_wrapper_guidance_bundle(self) -> None:
        bundle_paths = [str(path or "").strip() for path in self.__dict__.get("_wrapper_guidance_secondary_bundle_paths", ()) if str(path or "").strip()]
        self._open_paths_bundle(bundle_paths, kind="wrapper 가이드 관련 파일")
        named_paths = self._wrapper_guidance_bundle_named_paths(bundle_paths)
        self._append_wrapper_guidance_history(named_paths)
        if self._has_ui_attr("output_text"):
            self.set_text(self.output_text, self._wrapper_guidance_bundle_snapshot_text(named_paths))

    def _wrapper_guidance_bundle_named_paths(self, bundle_paths: list[str]) -> list[tuple[str, str]]:
        binding_path = self._binding_profile_path().strip()
        audit_path = self._wrapper_audit_log_path().strip()
        status_path = ""
        controller = self.__dict__.get("watcher_controller")
        if controller is not None and hasattr(controller, "runtime_status"):
            try:
                status_path = str(getattr(self._watcher_runtime_status(), "status_path", "") or "").strip()
            except Exception:
                status_path = ""
        kind_by_path = {
            binding_path: "binding JSON",
            audit_path: "창 audit 로그",
            status_path: "watch status",
        }
        named_paths: list[tuple[str, str]] = []
        for path_value in bundle_paths:
            normalized = str(path_value or "").strip()
            if not normalized:
                continue
            kind = kind_by_path.get(normalized, "")
            if not kind:
                lowered_name = Path(normalized).name.lower()
                if "wrapper" in lowered_name and "event" in lowered_name:
                    kind = "창 audit 로그"
                elif "status" in lowered_name:
                    kind = "watch status"
                elif lowered_name.endswith(".json"):
                    kind = "binding JSON"
                else:
                    kind = "관련 파일"
            named_paths.append((kind, normalized))
        return named_paths

    def _wrapper_guidance_bundle_snapshot_text(self, named_paths: list[tuple[str, str]]) -> str:
        lines = ["wrapper 가이드 관련 파일 요약:"]
        for kind, path_value in named_paths:
            lines.append(f"- {kind}: {self.format_path_state(self._path_state_snapshot(path_value))}")
            lines.append(f"  {path_value}")
        summary = self._wrapper_audit_summary_text().strip()
        if summary:
            lines.append("")
            lines.append(summary)
        return "\n".join(lines)

    def _wrapper_guidance_history_cause_label(self, named_paths: list[tuple[str, str]]) -> str:
        audit_path = self._wrapper_audit_log_path().strip()
        if audit_path:
            audit_file = Path(audit_path)
            if audit_file.exists() and audit_file.is_file():
                try:
                    lines = [line.strip() for line in audit_file.read_text(encoding="utf-8").splitlines() if line.strip()]
                except Exception:
                    lines = []
                payloads = self._wrapper_audit_payloads_from_lines(lines)
                suspicion = self._wrapper_audit_duplicate_suspicion_text(payloads)
                if "원인=" in suspicion:
                    return suspicion.split("원인=", 1)[1].strip()
                if payloads:
                    latest_event = str(payloads[-1].get("event", "") or "").strip()
                    latest_reason = str(payloads[-1].get("decision_reason", "") or "").strip()
                    if latest_event == "reuse_existing_bound_windows" or latest_reason == "bindings_complete":
                        return "정상 재사용"
                    if latest_event == "launch_complete":
                        return "launch 완료"
        if named_paths:
            return "직접 지정 bundle"
        return "일반 점검"

    def _append_wrapper_guidance_history(self, named_paths: list[tuple[str, str]]) -> None:
        if not named_paths:
            return
        timestamp = self._utc_now_iso()
        cause_label = self._wrapper_guidance_history_cause_label(named_paths)
        kind_summary = ", ".join(kind for kind, _path in named_paths)
        entry = f"{timestamp} / cause={cause_label} / files={len(named_paths)} / {kind_summary}"
        history_records = list(self.__dict__.get("_wrapper_guidance_history_records", []))
        history_records.append(
            {
                "timestamp": timestamp,
                "cause": cause_label,
                "kind_summary": kind_summary,
                "file_count": str(len(named_paths)),
            }
        )
        history_records = history_records[-6:]
        self._wrapper_guidance_history_records = history_records
        history_entries = list(self.__dict__.get("_wrapper_guidance_history_entries", []))
        history_entries.append(entry)
        history_entries = history_entries[-3:]
        self._wrapper_guidance_history_entries = history_entries
        if self._has_ui_attr("wrapper_guidance_history_summary_var"):
            self.wrapper_guidance_history_summary_var.set(self._wrapper_guidance_history_summary_text(history_records))
        if self._has_ui_attr("wrapper_guidance_history_var"):
            self.wrapper_guidance_history_var.set("최근 guidance snapshot:\n" + "\n".join(reversed(history_entries)))

    @staticmethod
    def _wrapper_guidance_history_summary_text(history_records: list[dict[str, str]]) -> str:
        if not history_records:
            return "guidance 집계: (없음)"
        counts: dict[str, int] = {}
        last_index: dict[str, int] = {}
        last_timestamp: dict[str, str] = {}
        for index, record in enumerate(history_records):
            cause = str(record.get("cause", "") or "일반 점검")
            counts[cause] = counts.get(cause, 0) + 1
            last_index[cause] = index
            last_timestamp[cause] = str(record.get("timestamp", "") or "-")
        priority_map = {
            "partial binding 잔존": 0,
            "replace close 실패": 0,
            "wrapper shell 중복": 1,
            "launch 반복": 1,
            "중복 재호출": 1,
            "직접 지정 bundle": 2,
            "launch 완료": 2,
            "일반 점검": 2,
            "정상 재사용": 3,
        }
        ordered_causes = sorted(
            counts.keys(),
            key=lambda cause: (
                priority_map.get(cause, 2),
                -last_index.get(cause, -1),
            ),
        )
        parts = [
            f"{cause} {counts[cause]}건 (마지막={last_timestamp.get(cause, '-')})"
            for cause in ordered_causes
        ]
        return "guidance 집계: " + " / ".join(parts)

    def _append_window_guard_smoke_history(
        self,
        *,
        decision: str,
        expected_count: int,
        binding_count: int,
        live_shell_count: int,
        latest_payload: dict[str, object] | None,
    ) -> None:
        timestamp = self._utc_now_iso()
        panel_label = self._window_guard_decision_label(decision)
        wrapper_decision = self._wrapper_audit_decision_text(latest_payload or {}) or "-"
        caller_source = self._wrapper_audit_caller_source_kind(latest_payload or {}) or "-"
        snapshot_summary = f"live={live_shell_count}/{expected_count} / binding={binding_count}"
        history_records = list(self.__dict__.get("_window_guard_smoke_history_records", []))
        history_records.append(
            {
                "timestamp": timestamp,
                "panel_label": panel_label,
                "decision": decision,
                "wrapper_decision": wrapper_decision,
                "source": caller_source,
                "snapshot": snapshot_summary,
            }
        )
        history_records = history_records[-6:]
        self._window_guard_smoke_history_records = history_records
        history_entries = list(self.__dict__.get("_window_guard_smoke_history_entries", []))
        history_entries.append(self._window_guard_smoke_history_entry_text(history_records[-1]))
        history_entries = history_entries[-3:]
        self._window_guard_smoke_history_entries = history_entries
        self._refresh_window_guard_smoke_history_vars()
        self._save_window_guard_smoke_history()

    @staticmethod
    def _window_guard_smoke_history_summary_text(history_records: list[dict[str, str]]) -> str:
        if not history_records:
            return "guard smoke 집계: (없음)"
        counts: dict[str, int] = {}
        last_index: dict[str, int] = {}
        last_timestamp: dict[str, str] = {}
        for index, record in enumerate(history_records):
            panel_label = str(record.get("panel_label", "") or "허용")
            counts[panel_label] = counts.get(panel_label, 0) + 1
            last_index[panel_label] = index
            last_timestamp[panel_label] = str(record.get("timestamp", "") or "-")
        priority_map = {
            "차단": 0,
            "attach-only 우회": 1,
            "허용": 2,
        }
        ordered_labels = sorted(
            counts.keys(),
            key=lambda label: (
                priority_map.get(label, 2),
                -last_index.get(label, -1),
            ),
        )
        parts = [
            f"{label} {counts[label]}건 (마지막={last_timestamp.get(label, '-')})"
            for label in ordered_labels
        ]
        return "guard smoke 집계: " + " / ".join(parts)

    def _window_guard_smoke_history_file_path(self) -> Path:
        raw_value = self.__dict__.get("window_guard_smoke_history_path", SNAPSHOT_DIR / "window-guard-smoke-history.json")
        try:
            return Path(raw_value)
        except Exception:
            return SNAPSHOT_DIR / "window-guard-smoke-history.json"

    @staticmethod
    def _window_guard_smoke_history_entry_text(record: dict[str, str]) -> str:
        timestamp = str(record.get("timestamp", "") or "-")
        panel_label = str(record.get("panel_label", "") or "허용")
        decision = str(record.get("decision", "") or "-")
        wrapper_decision = str(record.get("wrapper_decision", "") or "-")
        source = str(record.get("source", "") or "-")
        snapshot = str(record.get("snapshot", "") or "-")
        return (
            f"{timestamp} / panel={panel_label}({decision}) / wrapper={wrapper_decision} / "
            f"source={source} / {snapshot}"
        )

    @staticmethod
    def _window_guard_smoke_history_compare_badges_text(previous_record: dict[str, str], current_record: dict[str, str]) -> str:
        badges: list[str] = []
        previous_panel = str(previous_record.get("panel_label", "") or "허용")
        current_panel = str(current_record.get("panel_label", "") or "허용")
        if previous_panel == "차단" and current_panel != "차단":
            badges.append("[차단 해소]")
        elif previous_panel != current_panel:
            badges.append("[panel 변경]")
        previous_wrapper = str(previous_record.get("wrapper_decision", "") or "-")
        current_wrapper = str(current_record.get("wrapper_decision", "") or "-")
        if previous_wrapper != current_wrapper:
            badges.append("[재사용 전환]" if current_wrapper in {"reuse", "attach-only"} else "[wrapper 변경]")
        previous_source = str(previous_record.get("source", "") or "-")
        current_source = str(current_record.get("source", "") or "-")
        if previous_source != current_source:
            badges.append("[caller 변경]")
        previous_snapshot = str(previous_record.get("snapshot", "") or "-")
        current_snapshot = str(current_record.get("snapshot", "") or "-")
        if previous_snapshot != current_snapshot:
            badges.append("[snapshot 변경]")
        if not badges:
            return "변화 배지: [변화 없음]"
        return "변화 배지: " + " ".join(badges)

    @staticmethod
    def _window_guard_smoke_history_compare_text(previous_record: dict[str, str], current_record: dict[str, str]) -> str:
        changes: list[str] = []
        previous_panel = str(previous_record.get("panel_label", "") or "허용")
        current_panel = str(current_record.get("panel_label", "") or "허용")
        if previous_panel != current_panel:
            changes.append(f"panel {previous_panel} -> {current_panel}")
        previous_wrapper = str(previous_record.get("wrapper_decision", "") or "-")
        current_wrapper = str(current_record.get("wrapper_decision", "") or "-")
        if previous_wrapper != current_wrapper:
            changes.append(f"wrapper {previous_wrapper} -> {current_wrapper}")
        previous_source = str(previous_record.get("source", "") or "-")
        current_source = str(current_record.get("source", "") or "-")
        if previous_source != current_source:
            changes.append(f"source {previous_source} -> {current_source}")
        previous_snapshot = str(previous_record.get("snapshot", "") or "-")
        current_snapshot = str(current_record.get("snapshot", "") or "-")
        if previous_snapshot != current_snapshot:
            changes.append(f"snapshot {previous_snapshot} -> {current_snapshot}")
        if not changes:
            return "이전 대비: 변화 없음"
        return "이전 대비: " + " / ".join(changes)

    def _refresh_window_guard_smoke_history_vars(self) -> None:
        history_records = list(self.__dict__.get("_window_guard_smoke_history_records", []))
        history_entries = list(self.__dict__.get("_window_guard_smoke_history_entries", []))
        warning_text = str(self.__dict__.get("window_guard_smoke_history_warning", "") or "").strip()
        badge_text, badge_style = self._window_guard_smoke_badge_text_and_style(history_records, warning_text=warning_text)
        if self._has_ui_attr("window_guard_smoke_badge_var"):
            self.window_guard_smoke_badge_var.set(badge_text)
        self._apply_window_guard_smoke_badge_widget_style(badge_style)
        if self._has_ui_attr("window_guard_smoke_history_summary_var"):
            self.window_guard_smoke_history_summary_var.set(self._window_guard_smoke_history_summary_text(history_records))
        detail_lines: list[str] = []
        if len(history_records) >= 2:
            detail_lines.append(self._window_guard_smoke_history_compare_badges_text(history_records[-2], history_records[-1]))
            detail_lines.append(self._window_guard_smoke_history_compare_text(history_records[-2], history_records[-1]))
        if history_entries:
            detail_lines.extend(reversed(history_entries))
        elif warning_text:
            detail_lines.append(f"warning: {warning_text}")
        else:
            detail_lines.append("(없음)")
        if warning_text and history_entries:
            detail_lines.append(f"warning: {warning_text}")
        if self._has_ui_attr("window_guard_smoke_history_var"):
            self.window_guard_smoke_history_var.set("최근 guard smoke snapshot:\n" + "\n".join(detail_lines))

    def _load_window_guard_smoke_history(self) -> None:
        self.window_guard_smoke_history_warning = ""
        history_path = self._window_guard_smoke_history_file_path()
        try:
            if not history_path.exists():
                self._window_guard_smoke_history_records = []
                self._window_guard_smoke_history_entries = []
                self._refresh_window_guard_smoke_history_vars()
                return
            raw = history_path.read_text(encoding="utf-8")
        except OSError as exc:
            self._window_guard_smoke_history_records = []
            self._window_guard_smoke_history_entries = []
            self.window_guard_smoke_history_warning = f"guard-smoke-history read failed: {exc}"
            self._refresh_window_guard_smoke_history_vars()
            return
        if not raw.strip():
            self._window_guard_smoke_history_records = []
            self._window_guard_smoke_history_entries = []
            self._refresh_window_guard_smoke_history_vars()
            return
        try:
            payload = json.loads(raw)
        except Exception as exc:
            self._window_guard_smoke_history_records = []
            self._window_guard_smoke_history_entries = []
            self.window_guard_smoke_history_warning = (
                f"guard-smoke-history parse failed; history reset ({history_path.name}): {exc}"
            )
            self._refresh_window_guard_smoke_history_vars()
            return
        if not isinstance(payload, dict):
            self._window_guard_smoke_history_records = []
            self._window_guard_smoke_history_entries = []
            self.window_guard_smoke_history_warning = (
                f"guard-smoke-history payload is not an object; history reset ({history_path.name})"
            )
            self._refresh_window_guard_smoke_history_vars()
            return
        schema_version = payload.get("SchemaVersion", None)
        if schema_version not in (None, WINDOW_GUARD_SMOKE_HISTORY_SCHEMA_VERSION):
            self._window_guard_smoke_history_records = []
            self._window_guard_smoke_history_entries = []
            self.window_guard_smoke_history_warning = (
                "guard-smoke-history schema version is unsupported; history reset "
                f"({history_path.name}, version={schema_version})"
            )
            self._refresh_window_guard_smoke_history_vars()
            return
        history_payload = payload.get("History", payload)
        if not isinstance(history_payload, list):
            self._window_guard_smoke_history_records = []
            self._window_guard_smoke_history_entries = []
            self.window_guard_smoke_history_warning = (
                f"guard-smoke-history history payload is invalid; history reset ({history_path.name})"
            )
            self._refresh_window_guard_smoke_history_vars()
            return
        history_records: list[dict[str, str]] = []
        history_entries: list[str] = []
        for item in history_payload:
            if not isinstance(item, dict):
                continue
            record = {
                "timestamp": str(item.get("timestamp", "") or "").strip(),
                "panel_label": str(item.get("panel_label", "") or "허용").strip(),
                "decision": str(item.get("decision", "") or "-").strip(),
                "wrapper_decision": str(item.get("wrapper_decision", "") or "-").strip(),
                "source": str(item.get("source", "") or "-").strip(),
                "snapshot": str(item.get("snapshot", "") or "-").strip(),
            }
            history_records.append(record)
            entry = str(item.get("entry", "") or "").strip() or self._window_guard_smoke_history_entry_text(record)
            history_entries.append(entry)
        self._window_guard_smoke_history_records = history_records[-6:]
        self._window_guard_smoke_history_entries = history_entries[-3:]
        self._refresh_window_guard_smoke_history_vars()

    def _save_window_guard_smoke_history(self) -> None:
        temp_path: Path | None = None
        history_path = self._window_guard_smoke_history_file_path()
        try:
            history_path.parent.mkdir(parents=True, exist_ok=True)
            history_records = list(self.__dict__.get("_window_guard_smoke_history_records", []))
            payload = {
                "SchemaVersion": WINDOW_GUARD_SMOKE_HISTORY_SCHEMA_VERSION,
                "SavedAt": datetime.now().isoformat(timespec="seconds"),
                "History": [
                    {
                        "timestamp": str(record.get("timestamp", "") or "").strip(),
                        "panel_label": str(record.get("panel_label", "") or "").strip(),
                        "decision": str(record.get("decision", "") or "").strip(),
                        "wrapper_decision": str(record.get("wrapper_decision", "") or "").strip(),
                        "source": str(record.get("source", "") or "").strip(),
                        "snapshot": str(record.get("snapshot", "") or "").strip(),
                        "entry": self._window_guard_smoke_history_entry_text(record),
                    }
                    for record in history_records
                    if isinstance(record, dict)
                ],
            }
            temp_path = history_path.with_name(
                history_path.name + f".{os.getpid()}.{threading.get_ident()}.tmp"
            )
            temp_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
            os.replace(temp_path, history_path)
            self.window_guard_smoke_history_warning = ""
        except Exception as exc:
            self.window_guard_smoke_history_warning = f"guard-smoke-history save failed: {exc}"
        finally:
            if temp_path is not None and temp_path.exists():
                try:
                    temp_path.unlink()
                except OSError:
                    pass
        self._refresh_window_guard_smoke_history_vars()

    def _wrapper_guidance_focus_target(self) -> tuple[str, str]:
        history_records = list(self.__dict__.get("_wrapper_guidance_history_records", []))
        latest_cause = str(history_records[-1].get("cause", "") or "") if history_records else ""
        if latest_cause in {"partial binding 잔존", "replace close 실패"}:
            return "wrapper_guidance_action_button", "가이드 버튼"
        if latest_cause in {"wrapper shell 중복", "launch 반복", "중복 재호출", "직접 지정 bundle", "launch 완료"}:
            return "wrapper_guidance_secondary_action_button", "보조 가이드 버튼"
        if latest_cause == "정상 재사용":
            return "wrapper_guidance_action_button", "가이드 버튼"
        return "watcher_issue_action_button", "Pair watcher 권장 버튼"

    def _wrapper_guidance_focus_target_spec(self) -> dict[str, object]:
        target_attr, target_label = self._wrapper_guidance_focus_target()
        auto_runner = ""
        auto_allowed = False
        safe_when_busy = False
        if target_attr == "wrapper_guidance_action_button":
            auto_runner = "run_wrapper_guidance_action"
            auto_allowed = True
            safe_when_busy = True
        elif target_attr == "wrapper_guidance_secondary_action_button":
            auto_runner = "run_wrapper_guidance_secondary_action"
            auto_allowed = True
            safe_when_busy = True
        elif target_attr == "watcher_issue_action_button":
            auto_runner = "run_watcher_issue_action"
            action_key = str(self.__dict__.get("_watcher_issue_action_key", "") or "").strip()
            auto_allowed = bool(action_key and self._dashboard_action_is_read_only(action_key))
            safe_when_busy = auto_allowed
        return {
            "attr": target_attr,
            "label": target_label,
            "auto_runner": auto_runner,
            "auto_allowed": auto_allowed,
            "safe_when_busy": safe_when_busy,
        }

    def _focus_widget_if_possible(self, attr_name: str) -> bool:
        widget = self.__dict__.get(attr_name)
        if widget is None:
            return False
        try:
            if hasattr(widget, "focus_set"):
                widget.focus_set()
                return True
        except Exception:
            return False
        return False

    def _widget_is_enabled_for_auto_run(self, attr_name: str) -> bool:
        widget = self.__dict__.get(attr_name)
        if widget is None:
            return False
        state_value = getattr(widget, "state", "")
        if isinstance(state_value, str) and state_value.strip().lower() == "disabled":
            return False
        try:
            if hasattr(widget, "cget"):
                cget_state = str(widget.cget("state") or "").strip().lower()
                if cget_state == "disabled":
                    return False
        except Exception:
            pass
        return True

    def _auto_run_focus_target_if_safe(self, spec: dict[str, object]) -> bool:
        if self._busy and not bool(spec.get("safe_when_busy", False)):
            return False
        if not bool(spec.get("auto_allowed", False)):
            return False
        target_attr = str(spec.get("attr", "") or "").strip()
        if not target_attr or not self._widget_is_enabled_for_auto_run(target_attr):
            return False
        runner_name = str(spec.get("auto_runner", "") or "").strip()
        if not runner_name:
            return False
        runner = getattr(self, runner_name, None)
        if not callable(runner):
            return False
        runner()
        return True

    def focus_ops_watcher_section(self) -> None:
        if self._has_ui_attr("notebook") and self._has_ui_attr("ops_tab"):
            try:
                self.notebook.select(self.ops_tab)
            except Exception:
                pass
        target_spec = self._wrapper_guidance_focus_target_spec()
        target_attr = str(target_spec.get("attr", "") or "").strip()
        target_label = str(target_spec.get("label", "") or "Pair watcher 권장 버튼")
        focused = self._focus_widget_if_possible(target_attr)
        auto_ran = self._auto_run_focus_target_if_safe(target_spec)
        lines = ["OPS Pair watcher 섹션으로 이동:"]
        if self._has_ui_attr("watcher_issue_badge_var"):
            lines.append(str(self.watcher_issue_badge_var.get() or "상태 배지: 준비"))
        if self._has_ui_attr("watcher_issue_stage_var"):
            lines.append(str(self.watcher_issue_stage_var.get() or "제어 흐름: 아직 Pair watcher 제어 결과가 없습니다."))
        if self._has_ui_attr("target_autoloop_summary_var"):
            lines.append(str(self.target_autoloop_summary_var.get() or "mode/controller summary: (없음)"))
        if self._has_ui_attr("target_autoloop_recent_result_var"):
            lines.append(str(self.target_autoloop_recent_result_var.get() or "최근 결과: (없음)"))
        if self._has_ui_attr("target_autoloop_retry_reason_var"):
            lines.append(str(self.target_autoloop_retry_reason_var.get() or "재시도 사유: (없음)"))
        if self._has_ui_attr("target_autoloop_history_var"):
            lines.append(str(self.target_autoloop_history_var.get() or "권장 이력: (없음)"))
        if self._has_ui_attr("wrapper_guidance_history_summary_var"):
            lines.append(str(self.wrapper_guidance_history_summary_var.get() or "guidance 집계: (없음)"))
        if self._has_ui_attr("wrapper_guidance_history_var"):
            lines.append(str(self.wrapper_guidance_history_var.get() or "최근 guidance snapshot: (없음)"))
        if self._has_ui_attr("window_guard_smoke_history_summary_var"):
            lines.append(str(self.window_guard_smoke_history_summary_var.get() or "guard smoke 집계: (없음)"))
        suffix = ""
        if focused:
            suffix += " [focus]"
        if auto_ran:
            suffix += " [auto-run]"
        lines.append(f"추천 포커스: {target_label}{suffix}")
        if self._has_ui_attr("output_text"):
            self.set_text(self.output_text, "\n".join(lines))

    def run_shared_visible_window_guard_smoke(self) -> None:
        snapshot = self._shared_visible_window_process_snapshot()
        lane_name = str(self.effective_data.get("Config", {}).get("LaneName", "") or "").strip()
        expected_count = int(snapshot.get("expected_count", 8) or 8)
        binding_count = int(snapshot.get("binding_count", 0) or 0)
        live_shell_count = int(snapshot.get("live_shell_count", 0) or 0)
        current_decision, current_detail = self._shared_visible_window_launch_guard_decision(action_label="창 guard smoke")
        payloads = self._wrapper_audit_payloads()
        latest_payload = payloads[-1] if payloads else self._wrapper_audit_latest_payload()
        if latest_payload and not payloads:
            payloads = [latest_payload]
        lines = [
            "창 guard smoke:",
            f"- lane: {lane_name or '(없음)'}",
            f"- 현재 snapshot: live={live_shell_count}/{expected_count} / binding={binding_count}",
            f"- 현재 판정: {self._window_guard_decision_label(current_decision)} ({current_decision})",
        ]
        caller_summary = self._wrapper_audit_caller_summary_text().strip()
        if caller_summary:
            lines.append(f"- {caller_summary}")
        latest_audit_summary = self._wrapper_audit_latest_decision_summary_text(latest_payload).strip()
        if latest_audit_summary:
            lines.append(f"- {latest_audit_summary}")
        compare_text = self._window_guard_wrapper_compare_text(current_decision, latest_payload)
        if compare_text:
            lines.append(f"- {compare_text}")
        for highlight_line in self._wrapper_audit_parent_process_highlight_lines(latest_payload or {}):
            lines.append(f"- {highlight_line}")
        decision_timeline = self._wrapper_audit_recent_decision_timeline(payloads, limit=3)
        if decision_timeline:
            lines.append("")
            lines.append("최근 3개 wrapper decision 타임라인:")
            lines.extend(f"- {entry}" for entry in decision_timeline)
        self._append_window_guard_smoke_history(
            decision=current_decision,
            expected_count=expected_count,
            binding_count=binding_count,
            live_shell_count=live_shell_count,
            latest_payload=latest_payload,
        )
        if self._has_ui_attr("window_guard_smoke_history_summary_var"):
            lines.append("")
            lines.append(str(self.window_guard_smoke_history_summary_var.get() or "guard smoke 집계: (없음)"))
        if self._has_ui_attr("window_guard_smoke_history_var"):
            lines.append(str(self.window_guard_smoke_history_var.get() or "최근 guard smoke snapshot: (없음)"))
        if current_detail:
            lines.append("")
            lines.extend(current_detail.splitlines())
        elif not self._is_shared_visible_lane():
            lines.append("")
            lines.append("현재 lane은 shared visible 창 guard 대상이 아닙니다.")
        else:
            lines.append("")
            lines.append("현재 snapshot 기준 새 창 launch 차단 조건은 감지되지 않았습니다.")
        scenario_specs = [
            (
                "시나리오 A. startup guard",
                {
                    "startup_guard_active": True,
                    "remaining_sec": int(WINDOW_ACTION_STARTUP_GUARD_SEC),
                    "expected_count": expected_count,
                    "binding_count": 0,
                    "live_shell_count": 0,
                },
            ),
            (
                "시나리오 B. 공식 8창 완전 감지",
                {
                    "startup_guard_active": False,
                    "remaining_sec": 0,
                    "expected_count": expected_count,
                    "binding_count": expected_count,
                    "live_shell_count": expected_count,
                },
            ),
            (
                "시나리오 C. 공식 8창 부분 감지",
                {
                    "startup_guard_active": False,
                    "remaining_sec": 0,
                    "expected_count": expected_count,
                    "binding_count": max(1, expected_count - 3),
                    "live_shell_count": max(1, expected_count - 5),
                },
            ),
        ]
        for title, kwargs in scenario_specs:
            decision, detail = self._shared_visible_window_launch_guard_outcome(**kwargs)
            lines.append("")
            lines.append(title)
            lines.append(f"판정: {self._window_guard_decision_label(decision)} ({decision})")
            if detail:
                lines.extend(detail.splitlines())
        if self._has_ui_attr("output_text"):
            self.set_text(self.output_text, "\n".join(lines))
        self.set_operator_status(
            "창 guard smoke 완료",
            "startup guard / 완전 감지 / 부분 감지 시나리오를 실제 launch 없이 비교했습니다.",
            "마지막 결과: 창 guard smoke 완료",
        )

    def _wrapper_audit_recent_text(self, *, limit: int = 3) -> str:
        audit_path = self._wrapper_audit_log_path().strip()
        if not audit_path:
            return "최근 창 audit: BindingProfilePath가 없어 wrapper audit 경로를 계산하지 못했습니다."
        audit_file = Path(audit_path)
        if not audit_file.exists():
            return f"최근 창 audit: 로그 없음 ({audit_path})"
        try:
            lines = [line.strip() for line in audit_file.read_text(encoding="utf-8").splitlines() if line.strip()]
        except Exception as exc:
            return f"최근 창 audit: 로그 읽기 실패 ({exc})"
        if not lines:
            return f"최근 창 audit: 로그 비어 있음 ({audit_path})"
        payloads = self._wrapper_audit_payloads_from_lines(lines)
        duplicate_risk = self._wrapper_audit_duplicate_suspicion_text(payloads)
        guidance = self._wrapper_audit_guidance_text(payloads)
        latest_payload = payloads[-1] if payloads else None
        recent_entries: list[str] = []
        for line in lines[-max(int(limit or 0), 1):]:
            try:
                payload = json.loads(line)
            except Exception as exc:
                recent_entries.append(f"parse-failed ({exc})")
                continue
            if isinstance(payload, dict):
                recent_entries.append(self._format_wrapper_audit_event_line(payload))
        if not recent_entries:
            return f"최근 창 audit: 표시할 이벤트 없음 ({audit_path})"
        lines_out = ["최근 창 audit:"]
        latest_summary = self._wrapper_audit_latest_decision_summary_text(latest_payload).strip()
        if latest_summary:
            lines_out.append(f"- {latest_summary}")
        for highlight_line in self._wrapper_audit_parent_process_highlight_lines(latest_payload or {}):
            lines_out.append(f"- {highlight_line}")
        if duplicate_risk:
            lines_out.append(f"- {duplicate_risk}")
        if guidance:
            lines_out.append(f"- {guidance}")
        lines_out.extend(f"- {entry}" for entry in recent_entries)
        return "\n".join(lines_out)

    def _sync_preview_selection_with_pair(self, pair_id: str, *, target_id: str = "") -> bool:
        preview_index = None
        if target_id:
            for index, row in enumerate(self.preview_rows):
                if row.get("TargetId", "") == target_id and ((not pair_id) or row.get("PairId", "") == pair_id):
                    preview_index = index
                    break
            if preview_index is None:
                for index, row in enumerate(self.preview_rows):
                    if row.get("TargetId", "") == target_id:
                        preview_index = index
                        break
        if preview_index is None:
            preview_index = self.pair_controller.top_preview_index(self.preview_rows, pair_id)
        if preview_index is not None:
            iid = str(preview_index)
            self.row_tree.selection_set(iid)
            self.row_tree.see(iid)
            self.on_row_selected()
            return True
        return False

    def _sync_home_pair_selection(self, pair_id: str) -> None:
        if not pair_id:
            return
        if pair_id in self.home_pair_tree.get_children():
            self.home_pair_tree.selection_set(pair_id)
            self.home_pair_tree.see(pair_id)

    def _extract_prepared_run_root(self, text: str) -> str:
        return extract_prepared_run_root(text)

    def _render_action_frame(self, frame: ttk.LabelFrame, actions: list[ActionModel]) -> None:
        for child in frame.winfo_children():
            child.destroy()

        if not actions:
            ttk.Label(frame, text="(없음)", justify="left").grid(row=0, column=0, sticky="w")
            return

        for idx, action in enumerate(actions):
            row = ttk.Frame(frame)
            row.grid(row=idx, column=0, sticky="ew", pady=(0, 6))
            row.columnconfigure(0, weight=1)
            detail = action.detail or action.command_text or "-"
            ttk.Label(row, text=action.label, font=("Segoe UI", 9, "bold")).grid(row=0, column=0, sticky="w")
            ttk.Label(row, text=detail, wraplength=520, justify="left").grid(row=1, column=0, sticky="w")
            button = ttk.Button(
                row,
                text=action.label,
                command=lambda action_key=action.action_key, command_text=action.command_text: self.handle_dashboard_action(action_key, command_text=command_text),
            )
            read_only = self._dashboard_action_is_read_only(action.action_key)
            setattr(button, "_relay_dashboard_action_button", True)
            setattr(button, "_relay_dashboard_action_read_only", read_only)
            button.grid(row=0, column=1, rowspan=2, sticky="e", padx=(8, 0))
            if self._busy and not read_only:
                button.configure(state="disabled")

    def _render_issue_frame(self, frame: ttk.LabelFrame, issues: list[IssueModel]) -> None:
        for child in frame.winfo_children():
            child.destroy()

        if not issues:
            ttk.Label(frame, text="현재 즉시 복구가 필요한 항목은 없습니다.", justify="left").grid(row=0, column=0, sticky="w")
            return

        for idx, issue in enumerate(issues):
            row = ttk.Frame(frame)
            row.grid(row=idx, column=0, sticky="ew", pady=(0, 6))
            row.columnconfigure(0, weight=1)
            ttk.Label(row, text=issue.title, font=("Segoe UI", 9, "bold")).grid(row=0, column=0, sticky="w")
            ttk.Label(row, text=issue.detail, wraplength=520, justify="left").grid(row=1, column=0, sticky="w")
            button = ttk.Button(row, text=issue.action_label, command=lambda action_key=issue.action_key: self.handle_dashboard_action(action_key))
            read_only = self._dashboard_action_is_read_only(issue.action_key)
            setattr(button, "_relay_dashboard_action_button", True)
            setattr(button, "_relay_dashboard_action_read_only", read_only)
            button.grid(row=0, column=1, rowspan=2, sticky="e", padx=(8, 0))
            if self._busy and not read_only:
                button.configure(state="disabled")

    def _iter_widget_descendants(self, widget) -> Iterator[object]:
        children_method = getattr(widget, "winfo_children", None)
        if not callable(children_method):
            return
        try:
            children = list(children_method())
        except Exception:
            return
        for child in children:
            yield child
            yield from self._iter_widget_descendants(child)

    def _disable_button_if_mutating(self, button, *, action_key: str = "", read_only: bool | None = None) -> None:
        if button is None:
            return
        resolved_read_only = self._dashboard_action_is_read_only(action_key) if read_only is None else bool(read_only)
        if resolved_read_only:
            return
        configure = getattr(button, "configure", None)
        if callable(configure):
            configure(state="disabled")

    def _set_home_dashboard_busy_controls(self) -> None:
        if self._has_ui_attr("home_primary_action_button"):
            self._disable_button_if_mutating(
                self.home_primary_action_button,
                action_key=str(self.__dict__.get("_home_primary_action_key", "") or ""),
            )
        if self._has_ui_attr("home_secondary_action_button"):
            self._disable_button_if_mutating(
                self.home_secondary_action_button,
                action_key=str(self.__dict__.get("_home_secondary_action_key", "") or ""),
            )
        for button in dict(self.__dict__.get("home_stage_buttons", {}) or {}).values():
            self._disable_button_if_mutating(button)
        for frame_name in ("home_next_actions_frame", "home_issue_frame"):
            frame = self.__dict__.get(frame_name)
            for widget in self._iter_widget_descendants(frame):
                if not bool(getattr(widget, "_relay_dashboard_action_button", False)):
                    continue
                self._disable_button_if_mutating(
                    widget,
                    read_only=bool(getattr(widget, "_relay_dashboard_action_read_only", False)),
                )

    def _selected_action_pair_summary(self) -> PairSummaryModel | None:
        pair_id = self._selected_pair_id()
        if not self.panel_state or not pair_id:
            return None
        for summary in self.panel_state.pairs:
            if summary.pair_id == pair_id:
                return summary
        return None

    def _build_home_execution_context_model(
        self,
        *,
        current_preview: StartRunPreview | None = None,
        new_preview: StartRunPreview | None = None,
    ) -> HomeExecutionContextModel:
        badge_spec = self._current_context_badge_spec()
        action_context = self._action_context_state()
        inspection_context = self._selected_inspection_context_state()
        pair_summary = self._selected_action_pair_summary()
        current_preview = current_preview or self._build_start_run_preview(START_MODE_CURRENT_RUN)
        new_preview = new_preview or self._build_start_run_preview(START_MODE_NEW_RUN)
        run_root = self._current_run_root_for_actions().strip()
        run_root_state = self.run_root_status_var.get().strip() if self._has_ui_attr("run_root_status_var") else ""
        source_label = self._context_source_label(action_context.source) or action_context.source or "controls"

        summary = "실행 {0}".format(self._action_context_summary(action_context))
        if source_label:
            summary += f" / source={source_label}"

        detail_parts = [f"RunRoot={self._current_run_root_display_text()}"]
        if run_root_state:
            detail_parts.append(run_root_state)
        detail_parts.append(f"watcher={self._watcher_status() or '미확인'}")
        if pair_summary is not None:
            detail_parts.append(f"pair상태={pair_summary.latest_state or '(없음)'}")
            if pair_summary.current_phase:
                detail_parts.append(f"phase={pair_summary.current_phase}")
            detail_parts.append(f"왕복={pair_summary.roundtrip_count}")
            detail_parts.append(f"forwarded={pair_summary.forwarded_state_count}")
            next_handoff = pair_summary.next_expected_handoff or pair_summary.next_action
            if next_handoff:
                detail_parts.append(f"다음={next_handoff}")
        detail_parts.append(f"현재Run={'가능' if current_preview.allowed else '불가'}")
        detail_parts.append(f"새Run={'가능' if new_preview.allowed else '불가'}")
        if self._inspection_context_differs_from_action():
            detail_parts.append(f"보고={self._inspection_context_summary(inspection_context)}")

        warning_parts: list[str] = []
        if self._inspection_context_differs_from_action():
            warning_parts.append("보고 row와 실행 문맥이 다릅니다. 추천 실행 전에 문맥 반영을 먼저 권장합니다.")
        if not run_root:
            warning_parts.append("현재 실행 RunRoot가 없습니다. 새 RunRoot 준비가 먼저 필요합니다.")
        elif self._current_run_root_is_stale_for_actions():
            warning_parts.append("현재 실행 RunRoot가 stale입니다. 기존 state를 재사용할 수 있으니 새 RunRoot 준비를 권장합니다.")
        elif not (Path(run_root) / "manifest.json").exists():
            warning_parts.append("현재 실행 RunRoot에 manifest.json이 없어 문맥이 아직 완성되지 않았습니다.")
        headless_block_summary = self._shared_visible_typed_window_headless_block_summary()
        if headless_block_summary:
            warning_parts.append(f"{headless_block_summary} / shared visible은 typed-window 경로만 허용")
        start_issue_text = self._watcher_start_issue_text(current_preview, new_preview)
        if start_issue_text:
            warning_parts.append(start_issue_text)

        return HomeExecutionContextModel(
            badge_text=str(badge_spec.get("text", "") or "문맥 확인"),
            badge_background=str(badge_spec.get("background", "#6B7280")),
            badge_foreground=str(badge_spec.get("foreground", "#FFFFFF")),
            summary=summary,
            detail=" | ".join(part for part in detail_parts if part),
            warning=" / ".join(part for part in warning_parts if part),
            apply_enabled=bool(badge_spec.get("apply_enabled", False)),
            run_root_open_enabled=bool(run_root and Path(run_root).exists()),
            clear_enabled=bool(self.run_root_var.get().strip()),
        )

    @staticmethod
    def _home_recommendation_from_action(action: ActionModel) -> PrimaryActionRecommendation:
        return PrimaryActionRecommendation(
            title=action.label or "추천 실행",
            action_key=action.action_key,
            button_label=action.label or action.action_key or "실행",
            detail=action.detail or action.command_text or "현재 상태 기준 다음 실행 단계입니다.",
            command_text=action.command_text,
            read_only=RelayOperatorPanel._dashboard_action_is_read_only(action.action_key),
            enabled=bool(action.action_key),
        )

    def _home_recommendation_from_issue(self, issue: IssueModel) -> PrimaryActionRecommendation:
        return PrimaryActionRecommendation(
            title=issue.title or issue.action_label or "복구 / 점검",
            action_key=issue.action_key,
            button_label=issue.action_label or issue.action_key or "실행",
            detail=issue.detail or "현재 홈 상태에서 가장 먼저 풀어야 할 차단 항목입니다.",
            read_only=self._dashboard_action_is_read_only(issue.action_key),
            enabled=bool(issue.action_key),
        )

    def _default_home_safe_recommendation(self) -> PrimaryActionRecommendation:
        run_root = self._current_run_root_for_actions().strip()
        if run_root:
            return PrimaryActionRecommendation(
                title="현재 RunRoot 요약 보기",
                action_key="run_paired_summary",
                button_label="runroot 요약",
                detail="현재 실행 RunRoot의 manifest, Pair watcher, pair 요약을 읽습니다.",
                read_only=True,
            )
        return PrimaryActionRecommendation(
            title="빠른 새로고침",
            action_key="refresh_quick",
            button_label="빠른 새로고침",
            detail="현재 lane, pair, Pair watcher 상태를 다시 읽습니다.",
            read_only=True,
        )

    def _build_home_primary_action_recommendation(
        self,
        *,
        current_preview: StartRunPreview | None = None,
        new_preview: StartRunPreview | None = None,
    ) -> PrimaryActionRecommendation:
        if self._inspection_context_differs_from_action():
            return PrimaryActionRecommendation(
                title="보고 row를 실행 문맥으로 맞추기",
                action_key="apply_selected_inspection_context",
                button_label="선택 row 실행 기준 반영",
                detail="현재 보고 있는 preview row 또는 board target을 실제 실행 Pair/Target으로 고정합니다.",
                read_only=False,
            )
        start_run_recommendation = self._build_start_run_cta_recommendation(
            current_preview=current_preview,
            new_preview=new_preview,
        )
        if self.panel_state:
            for issue in self.panel_state.issues:
                if issue.action_key and not self._dashboard_action_is_read_only(issue.action_key):
                    if self._is_start_related_action_key(issue.action_key) and start_run_recommendation is not None:
                        return start_run_recommendation
                    return self._home_recommendation_from_issue(issue)
            if self.panel_state.next_actions:
                first_action = self.panel_state.next_actions[0]
                if first_action.action_key:
                    if self._is_start_related_action_key(first_action.action_key) and start_run_recommendation is not None:
                        return start_run_recommendation
                    return self._home_recommendation_from_action(first_action)
        if start_run_recommendation is not None:
            return start_run_recommendation
        watcher_recommendation = self._watcher_recommendation() if getattr(self, "watcher_controller", None) is not None else None
        if watcher_recommendation is not None and getattr(watcher_recommendation, "action_key", ""):
            return PrimaryActionRecommendation(
                title=watcher_recommendation.label or "Pair watcher 권장 조치",
                action_key="watcher_recommended_action",
                button_label=watcher_recommendation.label or "Pair watcher 권장 조치",
                detail=watcher_recommendation.detail or "현재 Pair watcher 진단 기준 권장 조치입니다.",
                read_only=self._dashboard_action_is_read_only(getattr(watcher_recommendation, "action_key", "")),
            )
        if self.panel_state and self.panel_state.issues:
            first_issue = self.panel_state.issues[0]
            if first_issue.action_key:
                return self._home_recommendation_from_issue(first_issue)
        return self._default_home_safe_recommendation()

    def _build_home_secondary_action_recommendation(
        self,
        primary: PrimaryActionRecommendation,
    ) -> PrimaryActionRecommendation:
        candidates: list[PrimaryActionRecommendation] = []
        if self.panel_state:
            for issue in self.panel_state.issues:
                if issue.action_key and self._dashboard_action_is_read_only(issue.action_key):
                    candidates.append(self._home_recommendation_from_issue(issue))
            for action in self.panel_state.next_actions:
                if action.action_key and self._dashboard_action_is_read_only(action.action_key):
                    candidates.append(self._home_recommendation_from_action(action))
        candidates.append(self._default_home_safe_recommendation())
        for candidate in candidates:
            if candidate.action_key and candidate.action_key != primary.action_key:
                return candidate
        return PrimaryActionRecommendation(
            title="안전 조회 항목 없음",
            action_key="",
            button_label="상태 보기",
            detail="추가로 실행할 읽기 전용 조회 항목이 없습니다.",
            read_only=True,
            enabled=False,
        )

    def _apply_home_execution_context_model(self, model: HomeExecutionContextModel) -> None:
        watcher_badge_text = ""
        if self._has_ui_attr("watcher_issue_badge_var"):
            watcher_badge_text = str(self.watcher_issue_badge_var.get() or "").strip()
        self._sync_watcher_badge_aux_surfaces(watcher_badge_text or "상태 배지: 준비")
        self.home_execution_badge_var.set(model.badge_text or "문맥 확인")
        self.home_execution_summary_var.set(model.summary or "실행 문맥 정보를 읽는 중입니다.")
        self.home_execution_detail_var.set(model.detail or "실행 Pair, RunRoot, Pair watcher 상태를 여기서 확인합니다.")
        self.home_execution_warning_var.set(model.warning or " ")
        if self._has_ui_attr("home_execution_badge_label"):
            try:
                self.home_execution_badge_label.configure(
                    text=self.home_execution_badge_var.get(),
                    bg=model.badge_background,
                    fg=model.badge_foreground,
                )
            except Exception:
                pass
        if self._has_ui_attr("home_apply_context_button"):
            self.home_apply_context_button.configure(state="normal" if (model.apply_enabled and not self._busy) else "disabled")
        if self._has_ui_attr("home_clear_run_root_button"):
            self.home_clear_run_root_button.configure(state="normal" if (model.clear_enabled and not self._busy) else "disabled")
        if self._has_ui_attr("home_open_run_root_button"):
            self.home_open_run_root_button.configure(state="normal" if model.run_root_open_enabled else "disabled")

    def _apply_home_action_recommendation(
        self,
        recommendation: PrimaryActionRecommendation,
        *,
        primary: bool,
    ) -> None:
        title_var = self.home_primary_action_title_var if primary else self.home_secondary_action_title_var
        detail_var = self.home_primary_action_detail_var if primary else self.home_secondary_action_detail_var
        button_var = self.home_primary_action_button_var if primary else self.home_secondary_action_button_var
        button = self.home_primary_action_button if primary else self.home_secondary_action_button
        action_key = str(recommendation.action_key or "").strip()
        command_text = str(recommendation.command_text or "")
        if primary:
            self._home_primary_action_key = action_key
            self._home_primary_action_command_text = command_text
        else:
            self._home_secondary_action_key = action_key
            self._home_secondary_action_command_text = command_text
        title_var.set(recommendation.title or ("추천 실행" if primary else "안전 조회"))
        detail_var.set(recommendation.detail or ("현재 상태에서 사용할 수 있는 동작입니다." if action_key else "사용 가능한 동작이 없습니다."))
        button_var.set(recommendation.button_label or ("추천 실행" if primary else "상태 보기"))
        enabled = bool(action_key) and bool(recommendation.enabled) and (recommendation.read_only or not self._busy)
        button.configure(state="normal" if enabled else "disabled")

    def _refresh_home_action_area(
        self,
        *,
        current_preview: StartRunPreview | None = None,
        new_preview: StartRunPreview | None = None,
    ) -> None:
        current_preview = current_preview or self._build_start_run_preview(START_MODE_CURRENT_RUN)
        new_preview = new_preview or self._build_start_run_preview(START_MODE_NEW_RUN)
        primary = self._build_home_primary_action_recommendation(
            current_preview=current_preview,
            new_preview=new_preview,
        )
        secondary = self._build_home_secondary_action_recommendation(primary)
        self._apply_home_action_recommendation(primary, primary=True)
        self._apply_home_action_recommendation(secondary, primary=False)
        next_action_count = len(self.panel_state.next_actions) if self.panel_state else 0
        issue_count = len(self.panel_state.issues) if self.panel_state else 0
        parts: list[str] = []
        if next_action_count:
            parts.append(f"추가 추천 {next_action_count}건")
        if issue_count:
            parts.append(f"복구/점검 {issue_count}건")
        if self._busy:
            parts.append("작업 중")
        if not parts:
            parts.append("추가 추천이나 복구 후보가 없습니다")
        self.home_advanced_summary_var.set(" / ".join(parts) + ". 저수준 버튼과 복구 후보는 기본 접힘입니다.")

    def run_home_primary_action(self) -> None:
        if not self._home_primary_action_key:
            return
        self._run_recommended_action(
            self._home_primary_action_key,
            command_text=self._home_primary_action_command_text,
        )

    def run_home_secondary_action(self) -> None:
        if not self._home_secondary_action_key:
            return
        self._run_recommended_action(
            self._home_secondary_action_key,
            command_text=self._home_secondary_action_command_text,
        )

    def render_home_dashboard(self) -> None:
        if not self.panel_state or not self.effective_data:
            return

        config = self.effective_data.get("Config", {})
        run_context = self.effective_data.get("RunContext", {})
        self.home_context_var.set(
            "Lane: {lane} | Config: {config_path} | RunRoot: {run_root} | 실행: {action_context} | inspection: {inspection_context}".format(
                lane=config.get("LaneName", "") or "(none)",
                config_path=config.get("ConfigPath", "") or self.config_path_var.get().strip() or "(none)",
                run_root=self._current_run_root_display_text(),
                action_context=self._action_context_summary(),
                inspection_context=self._inspection_context_summary(),
            )
        )
        self.home_updated_at_var.set("마지막 갱신: {0}".format(self.effective_data.get("GeneratedAt", "-")))
        detail = self.panel_state.overall_detail
        if self.paired_status_error:
            detail = self.home_controller.build_overall_detail(
                base_detail=detail,
                paired_status_error=self.paired_status_error,
                watcher_hint=self._watcher_runtime_hint(),
            )
        else:
            detail = self.home_controller.build_overall_detail(
                base_detail=detail,
                paired_status_error="",
                watcher_hint=self._watcher_runtime_hint(),
            )
        if self.panel_state.issues:
            primary_issue = self.panel_state.issues[0]
            detail = "{0} / 우선 조치: {1} -> {2}".format(detail, primary_issue.title, primary_issue.action_label)
        self.home_overall_var.set("상태: {0}".format(self.panel_state.overall_label))
        self.home_overall_detail_var.set(detail)
        current_preview = self._build_start_run_preview(START_MODE_CURRENT_RUN)
        new_preview = self._build_start_run_preview(START_MODE_NEW_RUN)
        self._apply_home_execution_context_model(
            self._build_home_execution_context_model(
                current_preview=current_preview,
                new_preview=new_preview,
            )
        )

        for card in self.panel_state.cards:
            vars_by_key = self.home_card_vars.get(card.key)
            if not vars_by_key:
                continue
            vars_by_key["value"].set(card.value)
            vars_by_key["detail"].set(card.detail)
        self._refresh_visible_acceptance_summary(
            current_preview=current_preview,
            new_preview=new_preview,
        )
        next_action_key = str(self.panel_state.next_actions[0].action_key if self.panel_state.next_actions else "").strip()

        for stage in self.panel_state.stages:
            vars_by_key = self.home_stage_vars.get(stage.key)
            button = self.home_stage_buttons.get(stage.key)
            if vars_by_key:
                vars_by_key["status"].set("상태: {0}".format(stage.status_text))
                vars_by_key["detail"].set(stage.detail)
            if button:
                button.configure(
                    text=self._highlighted_button_text(stage.action_label, active=(stage.action_key == next_action_key)),
                    state="disabled" if self._busy or not stage.enabled else "normal",
                )

        self._refresh_home_action_area(
            current_preview=current_preview,
            new_preview=new_preview,
        )
        self._render_action_frame(self.home_next_actions_frame, self.panel_state.next_actions)
        self._render_issue_frame(self.home_issue_frame, self.panel_state.issues)
        self.render_home_pair_summaries()

    def render_home_pair_summaries(self) -> None:
        current_pair = self._selected_pair_id()
        selected_home_pair = self._selected_home_pair_selection() or current_pair
        for item in self.home_pair_tree.get_children():
            self.home_pair_tree.delete(item)

        if not self.panel_state:
            self.home_pair_detail_var.set("Pair 요약 데이터가 없습니다.")
            return

        for summary in self.panel_state.pairs:
            self.home_pair_tree.insert(
                "",
                "end",
                iid=summary.pair_id,
                values=(
                    summary.pair_id,
                    summary.targets,
                    "예" if summary.enabled else "아니오",
                    summary.latest_state,
                    summary.current_phase or "-",
                    summary.roundtrip_count,
                    summary.next_expected_handoff or summary.next_action or "-",
                    summary.zip_count,
                    summary.failure_count,
                ),
            )

        self._sync_home_pair_selection(selected_home_pair)
        self._apply_home_pair_tree_highlights()
        summary = self._selected_pair_summary()
        if summary:
            self.home_pair_detail_var.set(self._home_pair_detail_text(summary))

    def _artifact_query(self) -> ArtifactQuery:
        query_context = self._artifact_query_context_state()
        return ArtifactQuery(
            run_root=query_context.run_root,
            pair_id=query_context.pair_id,
            target_id=query_context.target_id,
            latest_only=query_context.latest_only,
            include_missing=query_context.include_missing,
        )

    def _selected_artifact_state(self) -> TargetArtifactState | None:
        selection = self.artifact_tree.selection()
        if not selection:
            return None
        target_id = selection[0]
        for state in self.artifact_states:
            if state.target_id == target_id:
                return state
        return None

    def _populate_artifact_filter_values(self, states: list[TargetArtifactState]) -> None:
        pair_values = [""] + sorted({state.pair_id for state in states if state.pair_id})
        target_values = [""] + sorted({state.target_id for state in states if state.target_id})
        self.artifact_pair_combo.configure(values=pair_values)
        self.artifact_target_combo.configure(values=target_values)
        if self.artifact_pair_filter_var.get().strip() and self.artifact_pair_filter_var.get().strip() not in pair_values:
            self.artifact_pair_filter_var.set("")
        if self.artifact_target_filter_var.get().strip() and self.artifact_target_filter_var.get().strip() not in target_values:
            self.artifact_target_filter_var.set("")

    @staticmethod
    def _artifact_row_cache_signature(rows: object, fields: tuple[str, ...]) -> tuple[tuple[str, ...], ...]:
        if not isinstance(rows, list):
            return ()
        signature: list[tuple[str, ...]] = []
        for row in rows:
            if not isinstance(row, dict):
                continue
            signature.append(tuple(str(row.get(field, "") or "") for field in fields))
        return tuple(signature)

    @staticmethod
    def _artifact_pair_test_cache_signature(pair_test: object) -> tuple[str, ...]:
        if not isinstance(pair_test, dict):
            return ()
        fields = (
            "SummaryFileName",
            "RequestFileName",
            "DoneFileName",
            "ErrorFileName",
            "ReviewFolderName",
        )
        return tuple(str(pair_test.get(field, "") or "") for field in fields)

    def _artifact_view_state_cache_key(
        self,
        *,
        query: ArtifactQuery,
        selected_target_id: str,
        watcher_status: str,
    ) -> tuple[object, ...]:
        effective = self.effective_data if isinstance(self.effective_data, dict) else {}
        paired_status = self.paired_status_data if isinstance(self.paired_status_data, dict) else {}
        effective_row_signature = self._artifact_row_cache_signature(
            effective.get("PreviewRows", []),
            (
                "PairId",
                "RoleName",
                "TargetId",
                "PartnerTargetId",
                "PairTargetFolder",
                "ReviewFolderPath",
                "SummaryPath",
                "RequestPath",
                "DonePath",
                "ErrorPath",
                "ResultPath",
            ),
        )
        paired_row_signature = self._artifact_row_cache_signature(
            paired_status.get("Targets", []),
            (
                "PairId",
                "RoleName",
                "TargetId",
                "PartnerTargetId",
                "TargetFolder",
                "LatestState",
                "SummaryPresent",
                "DonePresent",
                "ErrorPresent",
                "ZipCount",
                "LatestZipName",
                "FailureCount",
                "SourceOutboxContractLatestState",
                "ContractLatestState",
                "SourceOutboxNextAction",
                "NextAction",
                "DispatchState",
                "DispatchUpdatedAt",
                "SeedSendState",
                "SubmitState",
                "SubmitReason",
            ),
        )
        return (
            id(getattr(self, "artifact_controller", None)),
            id(effective) if effective else 0,
            id(paired_status) if paired_status else 0,
            self._artifact_pair_test_cache_signature(paired_status.get("PairTest", {})),
            effective_row_signature,
            paired_row_signature,
            str(query.run_root or ""),
            str(query.pair_id or ""),
            str(query.target_id or ""),
            bool(query.latest_only),
            bool(query.include_missing),
            str(selected_target_id or ""),
            str(watcher_status or ""),
            str(self.paired_status_error or ""),
        )

    def _cached_artifact_view_state(self, cache_key: tuple[object, ...]) -> object | None:
        cache = self.__dict__.get("_artifact_view_state_cache")
        if not isinstance(cache, dict):
            return None
        entries = cache.get("entries")
        if not isinstance(entries, dict):
            return None
        entry = entries.get(cache_key)
        if not isinstance(entry, tuple) or len(entry) != 2:
            return None
        cached_at, tab_state = entry
        try:
            age_seconds = time.monotonic() - float(cached_at)
        except (TypeError, ValueError):
            return None
        if age_seconds > ARTIFACT_VIEW_STATE_CACHE_TTL_SECONDS:
            return None
        return deepcopy(tab_state)

    def _store_artifact_view_state_cache(self, cache_key: tuple[object, ...], tab_state: object) -> None:
        now = time.monotonic()
        cache = self.__dict__.get("_artifact_view_state_cache")
        existing_entries = cache.get("entries") if isinstance(cache, dict) else {}
        entries: dict[tuple[object, ...], tuple[float, object]] = {}
        if isinstance(existing_entries, dict):
            for key, entry in existing_entries.items():
                if not isinstance(key, tuple) or not isinstance(entry, tuple) or len(entry) != 2:
                    continue
                cached_at, cached_state = entry
                try:
                    if (now - float(cached_at)) <= ARTIFACT_VIEW_STATE_CACHE_TTL_SECONDS:
                        entries[key] = (float(cached_at), cached_state)
                except (TypeError, ValueError):
                    continue
        entries[cache_key] = (now, deepcopy(tab_state))
        self.__dict__["_artifact_view_state_cache"] = {"entries": entries}

    def _clear_artifact_view_state_cache(self) -> None:
        self.__dict__.pop("_artifact_view_state_cache", None)

    def refresh_artifacts_tab(self, _event: object | None = None) -> None:
        started_at = time.monotonic()
        steps: list[dict[str, object]] = []
        try:
            self.__dict__["artifact_refresh_pending"] = False
            if self._artifact_home_browse_pair_scope_enabled():
                self._run_timed_refresh_step(
                    steps,
                    "home filter sync",
                    lambda: self._sync_artifact_filters_with_home_pair_selection(refresh=False),
                )
            current_state = self._run_timed_refresh_step(steps, "selection resolve", self._selected_artifact_state)
            selected_target = current_state.target_id if current_state else ""
            if not self.effective_data:
                def render_empty_state() -> None:
                    self._clear_artifact_view_state_cache()
                    self.artifact_states = []
                    self.artifact_pair_summaries = []
                    for item in self.artifact_tree.get_children():
                        self.artifact_tree.delete(item)
                    self.artifact_status_base_text = "결과 / 산출물 데이터를 아직 읽지 못했습니다."
                    self.artifact_status_var.set(self.artifact_status_base_text)
                    self.set_text(self.artifact_summary_text, "")
                    self.set_text(self.artifact_details_text, "")
                    self._refresh_sticky_context_bar()

                self._run_timed_refresh_step(steps, "empty state render", render_empty_state)
                self._record_refresh_timing(
                    label="artifact tab refresh",
                    started_at=started_at,
                    steps=steps,
                )
                return

            query = self._run_timed_refresh_step(steps, "artifact query build", self._artifact_query)
            watcher_status = self._run_timed_refresh_step(steps, "watcher status read", self._watcher_status)
            cache_key = self._run_timed_refresh_step(
                steps,
                "view state cache key",
                lambda: self._artifact_view_state_cache_key(
                    query=query,
                    selected_target_id=selected_target,
                    watcher_status=watcher_status,
                ),
            )
            tab_state = self._run_timed_refresh_step(
                steps,
                "view state cache lookup",
                lambda: self._cached_artifact_view_state(cache_key),
            )
            if tab_state is None:
                tab_state = self._run_timed_refresh_step(
                    steps,
                    "view state build",
                    lambda: self.artifact_controller.build_view_state(
                        effective_data=self.effective_data,
                        paired_status=self.paired_status_data,
                        query=query,
                        selected_target_id=selected_target,
                        watcher_status=watcher_status,
                        paired_status_error=self.paired_status_error,
                    ),
                )

                def store_cache() -> None:
                    self._store_artifact_view_state_cache(cache_key, tab_state)
                    resolved_target = str(getattr(tab_state, "selected_target_id", "") or "")
                    if resolved_target and resolved_target != selected_target:
                        resolved_cache_key = self._artifact_view_state_cache_key(
                            query=query,
                            selected_target_id=resolved_target,
                            watcher_status=watcher_status,
                        )
                        self._store_artifact_view_state_cache(resolved_cache_key, tab_state)

                self._run_timed_refresh_step(steps, "view state cache store", store_cache)
            else:
                steps.append(
                    {
                        "label": "view state cache hit",
                        "elapsed_seconds": 0.0,
                        "elapsed_text": self._format_task_elapsed_seconds(0.0),
                    }
                )

            def apply_models() -> None:
                self.artifact_pair_combo.configure(values=tab_state.pair_values)
                self.artifact_target_combo.configure(values=tab_state.target_values)
                self.artifact_states = tab_state.states
                self.artifact_pair_summaries = tab_state.pair_summaries

            self._run_timed_refresh_step(steps, "artifact models apply", apply_models)

            def render_tree() -> None:
                for item in self.artifact_tree.get_children():
                    self.artifact_tree.delete(item)
                for state in tab_state.states:
                    self.artifact_tree.insert(
                        "",
                        "end",
                        iid=state.target_id,
                        values=(
                            state.pair_id,
                            state.target_id,
                            state.role_name,
                            self.artifact_service.format_target_state_label(state),
                            "예" if state.summary_present else "아니오",
                            state.zip_count,
                            "예" if state.error_present else "아니오",
                            state.failure_count,
                            state.latest_modified_at or "-",
                        ),
                    )

            self._run_timed_refresh_step(steps, "artifact tree render", render_tree)

            def render_status() -> None:
                self.artifact_status_base_text = tab_state.status_base_text
                self._apply_artifact_status_text(base_text=self.artifact_status_base_text, preview=tab_state.preview)

            self._run_timed_refresh_step(steps, "artifact status render", render_status)

            def sync_selection() -> None:
                if tab_state.selected_target_id and tab_state.selected_target_id in self.artifact_tree.get_children():
                    self.artifact_tree.selection_set(tab_state.selected_target_id)
                elif self.artifact_tree.get_children():
                    self.artifact_tree.selection_set(self.artifact_tree.get_children()[0])

            self._run_timed_refresh_step(steps, "artifact selection sync", sync_selection)
            self._run_timed_refresh_step(steps, "artifact details render", self.on_artifact_row_selected)
            self._run_timed_refresh_step(steps, "sticky context refresh", self._refresh_sticky_context_bar)
        except Exception:
            self._record_refresh_timing(
                label="artifact tab refresh",
                started_at=started_at,
                steps=steps,
                outcome="실패",
            )
            raise
        self._record_refresh_timing(
            label="artifact tab refresh",
            started_at=started_at,
            steps=steps,
        )

    def on_artifact_row_selected(self, _event: object | None = None) -> None:
        state = self._selected_artifact_state()
        if state is None:
            self._apply_artifact_status_text(base_text=self.artifact_status_base_text)
            self.set_text(self.artifact_summary_text, "")
            self.set_text(self.artifact_details_text, "")
            self._refresh_sticky_context_bar()
            return

        preview = self.artifact_controller.get_preview(self.artifact_states, state.target_id)
        if preview is None:
            self._apply_artifact_status_text(base_text=self.artifact_status_base_text)
            self.set_text(self.artifact_summary_text, "")
            self.set_text(self.artifact_details_text, "")
            self._refresh_sticky_context_bar()
            return

        contract_paths = self._resolve_artifact_contract_paths(state)
        self._apply_artifact_status_text(
            base_text=self.artifact_status_base_text,
            preview=preview,
            state=state,
            contract_paths=contract_paths,
        )
        self.set_text(self.artifact_summary_text, preview.summary_text)
        artifact_run_root = self._current_run_root_for_artifacts()
        action_run_root = self._current_run_root_for_actions()
        detail_lines = [
            f"조회 RunRoot: {artifact_run_root or '(없음)'}",
            f"조회 RunRoot override: {self._artifact_run_root_uses_override()}",
            f"조회 RunRoot stale 여부: {self._current_artifact_run_root_is_stale()}",
            f"실행 RunRoot: {action_run_root or '(없음)'}",
            f"실행 RunRoot stale 여부: {self._current_run_root_is_stale_for_actions()}",
            "",
            f"제목: {preview.title}",
            f"계약 상태(LatestState): {preview.latest_state}",
            f"표시 상태: {preview.state_label or '(없음)'}",
            f"차단 이유: {preview.blocker_reason or '(없음)'}",
            f"다음 조치: {preview.recommended_action or '(없음)'}",
            f"source-outbox 계약 상태: {self.artifact_service.display_latest_state(preview.source_outbox_contract_latest_state) or '(없음)'}",
            f"source-outbox 다음 동작: {self.artifact_service.display_next_action(preview.source_outbox_next_action) or '(없음)'}",
            f"후속 실행 상태: {self.artifact_service.display_dispatch_state(preview.dispatch_state) or '(없음)'}",
            f"후속 실행 갱신 시각: {preview.dispatch_updated_at or '(없음)'}",
            f"latest zip: {preview.latest_zip_name or '(없음)'}",
            f"latest zip 경로: {preview.latest_zip_path or '(없음)'}",
            f"target 폴더: {preview.target_folder or '(없음)'}",
            f"review 폴더: {preview.review_folder or '(없음)'}",
            f"work 폴더: {contract_paths.get('WorkFolderPath', '') or '(없음)'}",
            f"source outbox: {contract_paths.get('SourceOutboxPath', '') or '(없음)'}",
            f"source outbox 진단: {contract_paths.get('SourceOutboxPathWarning', '') or '(없음)'}",
            f"source summary: {contract_paths.get('SourceSummaryPath', '') or '(없음)'}",
            f"source review zip: {contract_paths.get('SourceReviewZipPath', '') or '(없음)'}",
            f"publish ready: {contract_paths.get('PublishReadyPath', '') or '(없음)'}",
            f"published archive: {contract_paths.get('PublishedArchivePath', '') or '(없음)'}",
            f"request 경로: {preview.request_path or '(없음)'}",
            f"done 경로: {preview.done_path or '(없음)'}",
            f"error 경로: {preview.error_path or '(없음)'}",
            f"result 경로: {preview.result_path or '(없음)'}",
            f"check wrapper: {contract_paths.get('CheckScriptPath', '') or '(없음)'}",
            f"submit wrapper: {contract_paths.get('SubmitScriptPath', '') or '(없음)'}",
            f"check cmd: {contract_paths.get('CheckCmdPath', '') or '(없음)'}",
            f"submit cmd: {contract_paths.get('SubmitCmdPath', '') or '(없음)'}",
            f"wrapper 경로 출처: {contract_paths.get('Source', '') or '(없음)'}",
            f"check wrapper 존재: {contract_paths.get('CheckScriptPathExists', False)}",
            f"submit wrapper 존재: {contract_paths.get('SubmitScriptPathExists', False)}",
            f"source memory warning: {self.artifact_source_memory_warning or '(없음)'}",
            f"상태 배지: {' '.join(self._artifact_warning_badges(state=state, contract_paths=contract_paths)) or '(없음)'}",
            "",
            "최근 source 경로:",
        ]
        remembered_sources = self._artifact_last_sources(state.target_id)
        if remembered_sources:
            detail_lines.extend(
                [
                    f"- SummarySourcePath: {remembered_sources.get('SummarySourcePath', '(없음)')}",
                    f"- ReviewZipSourcePath: {remembered_sources.get('ReviewZipSourcePath', '(없음)')}",
                    f"- RecordedAt: {remembered_sources.get('RecordedAt', '(없음)')}",
                ]
            )
        else:
            detail_lines.append("- (없음)")
        detail_lines.extend(
            [
                "",
            ]
        )
        detail_lines.extend(self._artifact_last_action_summary_lines(state.target_id))
        detail_lines.extend(
            [
                "",
            "메모:",
            ]
        )
        if preview.notes:
            detail_lines.extend([f"- {item}" for item in preview.notes])
        else:
            detail_lines.append("- (없음)")
        self.set_text(self.artifact_details_text, "\n".join(detail_lines))
        self._refresh_sticky_context_bar()

    def open_selected_artifact_path(self, kind: str) -> None:
        state = self._selected_artifact_state()
        if state is None:
            messagebox.showwarning("선택 필요", "target row를 먼저 선택하세요.")
            return
        path_value = self.artifact_service.resolve_artifact_path(state, kind)
        if not path_value:
            messagebox.showwarning("경로 없음", f"{kind} 경로를 찾지 못했습니다.")
            return
        try:
            self.artifact_service.open_path(path_value)
        except FileNotFoundError:
            messagebox.showwarning("경로 없음", path_value)
            return
        self.set_text(self.output_text, f"{kind} 열기:\n{path_value}")

    def copy_selected_artifact_path(self) -> None:
        state = self._selected_artifact_state()
        if state is None:
            messagebox.showwarning("선택 필요", "target row를 먼저 선택하세요.")
            return
        label = self.artifact_path_kind_var.get().strip() or "summary"
        kind = ARTIFACT_PATH_LABEL_TO_KIND.get(label, "summary")
        path_value = self.artifact_service.resolve_artifact_path(state, kind)
        if not path_value:
            messagebox.showwarning("경로 없음", f"{kind} 경로를 찾지 못했습니다.")
            return
        self._copy_to_clipboard(path_value)
        self.set_text(self.output_text, f"{kind} 경로 복사 완료:\n{path_value}")

    def _preview_row_for_target(self, target_id: str) -> dict | None:
        normalized = str(target_id or "").strip()
        if not normalized:
            return None
        for row in self.preview_rows:
            if str(row.get("TargetId", "") or "").strip() == normalized:
                return row
        return None

    def _safe_read_json_file(self, path_value: str) -> dict:
        path_text = str(path_value or "").strip()
        if not path_text:
            return {}
        try:
            raw = Path(path_text).read_text(encoding="utf-8-sig")
        except OSError:
            return {}
        if not raw.strip():
            return {}
        try:
            payload = json.loads(raw)
        except Exception:
            return {}
        return payload if isinstance(payload, dict) else {}

    def _pair_test_file_name(self, key: str, default: str) -> str:
        pair_test = (self.effective_data or {}).get("PairTest", {}) or {}
        value = str(pair_test.get(key, "") or "").strip()
        return value or default

    def _artifact_last_sources(self, target_id: str) -> dict[str, str]:
        return dict(self.artifact_last_sources_by_target.get(str(target_id or "").strip(), {}) or {})

    @staticmethod
    def _target_autoloop_parse_extend_cycles_value(value: object) -> tuple[int, str]:
        raw_value = str(value or "").strip()
        if not raw_value:
            return 0, "추가 횟수를 입력하세요."
        try:
            additional_cycles = int(raw_value)
        except (TypeError, ValueError):
            return 0, f"추가 횟수는 정수여야 합니다: {raw_value}"
        if additional_cycles < 1:
            return 0, "추가 횟수는 1 이상이어야 합니다."
        if additional_cycles > 1000:
            return 0, "추가 횟수는 1000 이하로 입력하세요."
        return additional_cycles, ""

    def _target_autoloop_extend_preferences_file_path(self) -> Path:
        raw_value = self.__dict__.get(
            "target_autoloop_extend_preferences_path",
            SNAPSHOT_DIR / "target-autoloop-extend-preferences.json",
        )
        try:
            return Path(raw_value)
        except Exception:
            return SNAPSHOT_DIR / "target-autoloop-extend-preferences.json"

    def _load_target_autoloop_extend_preferences(self) -> None:
        self.__dict__["target_autoloop_extend_preferences_warning"] = ""
        preferences_path = self._target_autoloop_extend_preferences_file_path()
        try:
            if not preferences_path.exists():
                return
            raw = preferences_path.read_text(encoding="utf-8")
        except OSError as exc:
            self.__dict__["target_autoloop_extend_preferences_warning"] = f"extend-preferences read failed: {exc}"
            return
        if not raw.strip():
            return
        try:
            payload = json.loads(raw)
        except Exception as exc:
            self.__dict__["target_autoloop_extend_preferences_warning"] = (
                f"extend-preferences parse failed; defaults kept ({preferences_path.name}): {exc}"
            )
            return
        if not isinstance(payload, dict):
            self.__dict__["target_autoloop_extend_preferences_warning"] = (
                f"extend-preferences payload is not an object; defaults kept ({preferences_path.name})"
            )
            return
        schema_version = payload.get("SchemaVersion", None)
        if schema_version not in (None, TARGET_AUTOLOOP_EXTEND_PREFERENCES_SCHEMA_VERSION):
            self.__dict__["target_autoloop_extend_preferences_warning"] = (
                "extend-preferences schema version is unsupported; defaults kept "
                f"({preferences_path.name}, version={schema_version})"
            )
            return
        additional_cycles, detail = self._target_autoloop_parse_extend_cycles_value(
            payload.get("AdditionalCycles", payload.get("LastAdditionalCycles", ""))
        )
        if detail:
            self.__dict__["target_autoloop_extend_preferences_warning"] = (
                f"extend-preferences AdditionalCycles ignored ({preferences_path.name}): {detail}"
            )
            return
        value_var = self.__dict__.get("target_autoloop_extend_cycles_var")
        if value_var is not None and hasattr(value_var, "set"):
            value_var.set(str(additional_cycles))
        card_vars = self.__dict__.get("target_autoloop_policy_card_vars", {}) or {}
        if isinstance(card_vars, dict):
            for store in card_vars.values():
                if not isinstance(store, dict):
                    continue
                card_value_var = store.get("extend_cycles_var")
                if card_value_var is not None and hasattr(card_value_var, "set"):
                    card_value_var.set(str(additional_cycles))

    def _save_target_autoloop_extend_preferences(self, additional_cycles: int) -> None:
        additional_cycles, detail = self._target_autoloop_parse_extend_cycles_value(additional_cycles)
        if detail:
            self.__dict__["target_autoloop_extend_preferences_warning"] = f"extend-preferences save skipped: {detail}"
            return
        preferences_path = self._target_autoloop_extend_preferences_file_path()
        temp_path: Path | None = None
        try:
            preferences_path.parent.mkdir(parents=True, exist_ok=True)
            payload = {
                "SchemaVersion": TARGET_AUTOLOOP_EXTEND_PREFERENCES_SCHEMA_VERSION,
                "SavedAt": datetime.now().isoformat(timespec="seconds"),
                "AdditionalCycles": additional_cycles,
            }
            temp_path = preferences_path.with_name(
                preferences_path.name + f".{os.getpid()}.{threading.get_ident()}.tmp"
            )
            temp_path.write_text(
                json.dumps(payload, ensure_ascii=False, indent=2),
                encoding="utf-8",
            )
            os.replace(temp_path, preferences_path)
            self.__dict__["target_autoloop_extend_preferences_warning"] = ""
        except Exception as exc:
            self.__dict__["target_autoloop_extend_preferences_warning"] = f"extend-preferences save failed: {exc}"
        finally:
            if temp_path is not None and temp_path.exists():
                try:
                    temp_path.unlink()
                except OSError:
                    pass

    def _target_autoloop_card_view_preferences_file_path(self) -> Path:
        raw_value = self.__dict__.get(
            "target_autoloop_card_view_preferences_path",
            SNAPSHOT_DIR / "target-autoloop-card-view-preferences.json",
        )
        try:
            return Path(raw_value)
        except Exception:
            return SNAPSHOT_DIR / "target-autoloop-card-view-preferences.json"

    def _load_target_autoloop_card_view_preferences(self) -> None:
        self.__dict__["target_autoloop_card_view_preferences_warning"] = ""
        preferences_path = self._target_autoloop_card_view_preferences_file_path()
        try:
            if not preferences_path.exists():
                return
            raw = preferences_path.read_text(encoding="utf-8")
        except OSError as exc:
            self.__dict__["target_autoloop_card_view_preferences_warning"] = f"card-view-preferences read failed: {exc}"
            return
        if not raw.strip():
            return
        try:
            payload = json.loads(raw)
        except Exception as exc:
            self.__dict__["target_autoloop_card_view_preferences_warning"] = (
                f"card-view-preferences parse failed; defaults kept ({preferences_path.name}): {exc}"
            )
            return
        if not isinstance(payload, dict):
            self.__dict__["target_autoloop_card_view_preferences_warning"] = (
                f"card-view-preferences payload is not an object; defaults kept ({preferences_path.name})"
            )
            return
        schema_version = payload.get("SchemaVersion", None)
        if schema_version not in (None, TARGET_AUTOLOOP_CARD_VIEW_PREFERENCES_SCHEMA_VERSION):
            self.__dict__["target_autoloop_card_view_preferences_warning"] = (
                "card-view-preferences schema version is unsupported; defaults kept "
                f"({preferences_path.name}, version={schema_version})"
            )
            return
        detail_visible = bool(payload.get("CardDetailVisible", False))
        visible_var = self.__dict__.get("target_autoloop_policy_card_detail_visible_var")
        if visible_var is not None and hasattr(visible_var, "set"):
            visible_var.set(detail_visible)
        view_mode = str(payload.get("CardViewMode", payload.get("ViewMode", "full")) or "full").strip().lower()
        if view_mode not in {"full", "compact"}:
            view_mode = "full"
        mode_var = self.__dict__.get("target_autoloop_policy_card_view_mode_var")
        if mode_var is not None and hasattr(mode_var, "set"):
            mode_var.set(view_mode)
        focused_target_id = str(payload.get("FocusedTargetId", payload.get("FocusTargetId", "")) or "").strip()
        if focused_target_id in set(BOARD_TARGET_FALLBACK):
            focus_var = self.__dict__.get("target_autoloop_policy_card_focus_target_var")
            if focus_var is not None and hasattr(focus_var, "set"):
                focus_var.set(focused_target_id)
        self._set_target_autoloop_policy_card_view_status(mode=view_mode, focus_target_id=focused_target_id or None)

    def _save_target_autoloop_card_view_preferences(self) -> None:
        visible_var = self.__dict__.get("target_autoloop_policy_card_detail_visible_var")
        detail_visible = False
        if visible_var is not None and hasattr(visible_var, "get"):
            try:
                detail_visible = bool(visible_var.get())
            except Exception:
                detail_visible = False
        view_mode = self._target_autoloop_policy_card_view_mode()
        focus_target_id = self._target_autoloop_policy_card_focus_target_id()
        preferences_path = self._target_autoloop_card_view_preferences_file_path()
        temp_path: Path | None = None
        try:
            preferences_path.parent.mkdir(parents=True, exist_ok=True)
            payload = {
                "SchemaVersion": TARGET_AUTOLOOP_CARD_VIEW_PREFERENCES_SCHEMA_VERSION,
                "SavedAt": datetime.now().isoformat(timespec="seconds"),
                "CardDetailVisible": detail_visible,
                "CardViewMode": view_mode,
                "FocusedTargetId": focus_target_id,
            }
            temp_path = preferences_path.with_name(
                preferences_path.name + f".{os.getpid()}.{threading.get_ident()}.tmp"
            )
            temp_path.write_text(
                json.dumps(payload, ensure_ascii=False, indent=2),
                encoding="utf-8",
            )
            os.replace(temp_path, preferences_path)
            self.__dict__["target_autoloop_card_view_preferences_warning"] = ""
        except Exception as exc:
            self.__dict__["target_autoloop_card_view_preferences_warning"] = f"card-view-preferences save failed: {exc}"
        finally:
            if temp_path is not None and temp_path.exists():
                try:
                    temp_path.unlink()
                except OSError:
                    pass

    def _load_artifact_source_memory(self) -> None:
        self.artifact_source_memory_warning = ""
        try:
            if not self.artifact_source_memory_path.exists():
                self.artifact_last_sources_by_target = {}
                return
            raw = self.artifact_source_memory_path.read_text(encoding="utf-8")
        except OSError as exc:
            self.artifact_last_sources_by_target = {}
            self.artifact_source_memory_warning = f"source-memory read failed: {exc}"
            return
        if not raw.strip():
            self.artifact_last_sources_by_target = {}
            return
        try:
            payload = json.loads(raw)
        except Exception as exc:
            self.artifact_last_sources_by_target = {}
            self.artifact_source_memory_warning = (
                f"source-memory parse failed; memory cache reset ({self.artifact_source_memory_path.name}): {exc}"
            )
            return
        if not isinstance(payload, dict):
            self.artifact_last_sources_by_target = {}
            self.artifact_source_memory_warning = (
                f"source-memory payload is not an object; memory cache reset ({self.artifact_source_memory_path.name})"
            )
            return

        schema_version = payload.get("SchemaVersion", None)
        if schema_version not in (None, ARTIFACT_SOURCE_MEMORY_SCHEMA_VERSION):
            self.artifact_last_sources_by_target = {}
            self.artifact_source_memory_warning = (
                "source-memory schema version is unsupported; memory cache reset "
                f"({self.artifact_source_memory_path.name}, version={schema_version})"
            )
            return

        targets_payload = payload.get("Targets", payload)
        if not isinstance(targets_payload, dict):
            self.artifact_last_sources_by_target = {}
            self.artifact_source_memory_warning = (
                f"source-memory targets payload is invalid; memory cache reset ({self.artifact_source_memory_path.name})"
            )
            return

        remembered: dict[str, dict[str, str]] = {}
        for target_id, item in targets_payload.items():
            normalized_target = str(target_id or "").strip()
            if not normalized_target or not isinstance(item, dict):
                continue
            summary_path = str(item.get("SummarySourcePath", "") or "").strip()
            review_zip_path = str(item.get("ReviewZipSourcePath", "") or "").strip()
            recorded_at = str(item.get("RecordedAt", "") or "").strip()
            if not summary_path and not review_zip_path:
                continue
            remembered[normalized_target] = {
                "SummarySourcePath": summary_path,
                "ReviewZipSourcePath": review_zip_path,
                "RecordedAt": recorded_at,
            }
        self.artifact_last_sources_by_target = remembered

    def _save_artifact_source_memory(self) -> None:
        temp_path: Path | None = None
        try:
            self.artifact_source_memory_path.parent.mkdir(parents=True, exist_ok=True)
            payload = {
                "SchemaVersion": ARTIFACT_SOURCE_MEMORY_SCHEMA_VERSION,
                "SavedAt": datetime.now().isoformat(timespec="seconds"),
                "Targets": {
                    target_id: {
                        "SummarySourcePath": str(item.get("SummarySourcePath", "") or "").strip(),
                        "ReviewZipSourcePath": str(item.get("ReviewZipSourcePath", "") or "").strip(),
                        "RecordedAt": str(item.get("RecordedAt", "") or "").strip(),
                    }
                    for target_id, item in self.artifact_last_sources_by_target.items()
                    if str(target_id or "").strip()
                },
            }
            temp_path = self.artifact_source_memory_path.with_name(
                self.artifact_source_memory_path.name
                + f".{os.getpid()}.{threading.get_ident()}.tmp"
            )
            temp_path.write_text(
                json.dumps(payload, ensure_ascii=False, indent=2),
                encoding="utf-8",
            )
            os.replace(temp_path, self.artifact_source_memory_path)
            self.artifact_source_memory_warning = ""
        except Exception as exc:
            self.artifact_source_memory_warning = f"source-memory save failed: {exc}"
        finally:
            if temp_path is not None and temp_path.exists():
                try:
                    temp_path.unlink()
                except OSError:
                    pass

    def _remember_artifact_sources(self, target_id: str, summary_path: str, review_zip_path: str) -> None:
        normalized_target = str(target_id or "").strip()
        if not normalized_target:
            return
        self.artifact_last_sources_by_target[normalized_target] = {
            "SummarySourcePath": str(summary_path or "").strip(),
            "ReviewZipSourcePath": str(review_zip_path or "").strip(),
            "RecordedAt": datetime.now().isoformat(timespec="seconds"),
        }
        self._save_artifact_source_memory()

    def _remember_artifact_action_result(self, target_id: str, payload: dict[str, object]) -> None:
        normalized_target = str(target_id or "").strip()
        if not normalized_target:
            return
        self.artifact_last_action_by_target[normalized_target] = dict(payload)

    def _artifact_last_action_summary_lines(self, target_id: str) -> list[str]:
        record = dict(self.artifact_last_action_by_target.get(str(target_id or "").strip(), {}) or {})
        if not record:
            return ["마지막 panel 실행: (없음)"]

        lines = [
            "마지막 panel 실행:",
            "- Action: {0}".format(record.get("Action", "(없음)")),
            "- Status: {0}".format(record.get("Status", "(없음)")),
            "- At: {0}".format(record.get("RecordedAt", "(없음)")),
            "- UsedWrapper: {0}".format(record.get("UsedWrapper", False)),
            "- ExecutionPath: {0}".format(record.get("ExecutionPath", "(없음)")),
            "- RequiresOverwrite: {0}".format(record.get("RequiresOverwrite", False)),
            "- 계약 LatestState: {0}".format(record.get("LatestState", "(없음)")),
            "- LatestZipPath: {0}".format(record.get("LatestZipPath", "(없음)")),
        ]
        summary_source_path = str(record.get("SummarySourcePath", "") or "").strip()
        review_zip_source_path = str(record.get("ReviewZipSourcePath", "") or "").strip()
        if summary_source_path:
            lines.append("- SummarySourcePath: {0}".format(summary_source_path))
        if review_zip_source_path:
            lines.append("- ReviewZipSourcePath: {0}".format(review_zip_source_path))
        error_text = str(record.get("Error", "") or "").strip()
        if error_text:
            lines.append("- Error: {0}".format(error_text))
        return lines

    def _begin_submit_action(self, target_id: str) -> bool:
        normalized_target = str(target_id or "").strip()
        if not normalized_target:
            return True
        if normalized_target in self.artifact_submit_active_targets:
            return False
        self.artifact_submit_active_targets.add(normalized_target)
        return True

    def _finish_submit_action(self, target_id: str) -> None:
        normalized_target = str(target_id or "").strip()
        if not normalized_target:
            return
        self.artifact_submit_active_targets.discard(normalized_target)

    def _confirm_recent_submit_repeat(self, target_id: str) -> bool:
        record = dict(self.artifact_last_action_by_target.get(str(target_id or "").strip(), {}) or {})
        if str(record.get("Action", "") or "").strip() != "submit":
            return True
        if str(record.get("Status", "") or "").strip() not in {"success", "running"}:
            return True
        recorded_at_text = str(record.get("RecordedAt", "") or "").strip()
        if not recorded_at_text:
            return True
        try:
            recorded_at = datetime.fromisoformat(recorded_at_text)
        except ValueError:
            return True
        age_seconds = (datetime.now() - recorded_at).total_seconds()
        if age_seconds > 15:
            return True
        return messagebox.askyesno(
            "submit 재실행 확인",
            (
                f"{target_id} 에 대해 {age_seconds:.1f}초 전에 submit 실행 기록이 있습니다.\n"
                "연속 재실행은 중복 제출일 수 있습니다. 계속할까요?"
            ),
            parent=self,
        )

    def _current_run_root_is_stale_for_actions(self) -> bool:
        return self._run_root_is_stale(self._current_run_root_for_actions())

    def _run_root_is_stale(self, run_root: str) -> bool:
        candidate = str(run_root or "").strip()
        if not candidate:
            return False

        run_context = (self.effective_data or {}).get("RunContext", {}) or {}
        selected_run_root = str(run_context.get("SelectedRunRoot", "") or "").strip()
        if selected_run_root and self._same_run_root_path(candidate, selected_run_root):
            return bool(run_context.get("SelectedRunRootIsStale", False))

        threshold = int(run_context.get("StaleRunThresholdSec", 1800) or 1800)
        run_root_path = Path(candidate)
        if not run_root_path.exists():
            return False

        try:
            age_seconds = max(0.0, datetime.now().timestamp() - run_root_path.stat().st_mtime)
        except OSError:
            return False
        return age_seconds >= threshold

    def _prepare_run_root_override_to_ignore(self) -> str:
        requested_run_root = self.run_root_var.get().strip()
        if not requested_run_root:
            return ""
        if self._run_root_is_stale(requested_run_root):
            return requested_run_root
        return ""

    def _format_run_root_prepare_output(
        self,
        *,
        output: str,
        ignored_run_root: str = "",
        prepared_run_root: str = "",
    ) -> str:
        lines: list[str] = []
        if ignored_run_root:
            lines.extend(
                [
                    "오래된 RunRoot 입력 무시 후 새 RunRoot 생성",
                    f"IgnoredRunRoot: {ignored_run_root}",
                    "",
                ]
            )
        lines.append(output)
        if prepared_run_root:
            lines.extend(
                [
                    "",
                    f"ActionRunRoot: {prepared_run_root}",
                    "RunRoot 입력칸 갱신 완료",
                ]
            )
        return "\n".join(lines)

    def _run_root_prepare_last_result(self, *, ignored_run_root: str = "", prepared_run_root: str = "") -> str:
        if prepared_run_root:
            if ignored_run_root:
                return "마지막 결과: stale RunRoot 입력 무시 후 새 RunRoot 준비 및 입력칸 갱신 완료"
            return "마지막 결과: 새 RunRoot 준비 및 입력칸 갱신 완료"
        if ignored_run_root:
            return "마지막 결과: stale RunRoot 입력 무시 후 RunRoot 준비 완료"
        return "마지막 결과: RunRoot 준비 완료"

    @staticmethod
    def _resolve_run_root_summary_run_root(*candidates: str) -> str:
        return resolve_run_root_summary_run_root(*candidates)

    def _run_root_summary_text_for(self, *, run_root: str, config_path: str) -> str:
        return self._runtime_workflow().load_run_root_summary_text(
            run_root=str(run_root or "").strip(),
            config_path=config_path,
        )

    def _run_root_summary_text(self, run_root: str = "", *, config_path: str = "") -> str:
        summary_run_root = self._resolve_run_root_summary_run_root(
            run_root,
            self._current_run_root_for_actions(),
        )
        summary_config_path = str(config_path or self.config_path_var.get().strip())
        return self._run_root_summary_text_for(
            run_root=summary_run_root,
            config_path=summary_config_path,
        )

    def _requested_run_root_for_prepare(self) -> str:
        if self._run_root_override_state() != "override-active":
            return ""
        if self._prepare_run_root_override_to_ignore():
            return ""
        return self.run_root_var.get().strip()

    def _artifact_warning_badges(
        self,
        state: TargetArtifactState | None = None,
        contract_paths: dict[str, object] | None = None,
    ) -> list[str]:
        badges: list[str] = []
        if str(getattr(self, "artifact_source_memory_warning", "") or "").strip():
            badges.append("[SOURCE MEMORY WARNING]")
        if self._artifact_run_root_uses_override():
            badges.append("[ARTIFACT RUNROOT OVERRIDE]")
        if self._current_artifact_run_root_is_stale():
            badges.append("[ARTIFACT RUNROOT STALE]")
        if state is not None:
            resolved_contract = contract_paths or self._resolve_artifact_contract_paths(state)
            if not bool(resolved_contract.get("CheckScriptPathExists", False)):
                badges.append("[LEGACY CHECK FALLBACK RISK]")
            if not bool(resolved_contract.get("SubmitScriptPathExists", False)):
                badges.append("[LEGACY SUBMIT FALLBACK RISK]")
            if str(resolved_contract.get("SourceOutboxPathWarning", "") or "").strip():
                badges.append("[OUTPUTFILES PARENT MISMATCH]")
        return badges

    def _apply_artifact_status_text(
        self,
        *,
        base_text: str,
        preview=None,
        state: TargetArtifactState | None = None,
        contract_paths: dict[str, object] | None = None,
    ) -> None:
        status_text = self.artifact_controller.decorate_status_text(base_text, preview)
        artifact_run_root = self._current_run_root_for_artifacts()
        action_run_root = self._current_run_root_for_actions()
        if artifact_run_root or action_run_root:
            status_prefix = "조회={0} | 실행={1}".format(
                Path(artifact_run_root).name if artifact_run_root else "(없음)",
                Path(action_run_root).name if action_run_root else "(없음)",
            )
            if artifact_run_root != action_run_root:
                status_prefix += " | 컨텍스트 분리"
            status_text = " | ".join(part for part in [status_prefix, status_text] if part)
        badges = self._artifact_warning_badges(state=state, contract_paths=contract_paths)
        if badges:
            status_text = " ".join(badges + [status_text])
        self.artifact_status_var.set(status_text)

    def _resolve_artifact_contract_paths(self, state: TargetArtifactState) -> dict[str, object]:
        preview_row = self._preview_row_for_target(state.target_id) or {}
        request_path = self.artifact_service.resolve_artifact_path(state, "request") or str(preview_row.get("RequestPath", "") or "")
        request_payload = self._safe_read_json_file(request_path)
        request_output_paths = self._resolved_output_paths_from_row(request_payload)
        preview_output_paths = self._resolved_output_paths_from_row(preview_row)
        request_outbox_path, request_outbox_warning = self._resolved_source_outbox_path_analysis_from_row(request_payload)
        preview_outbox_path, preview_outbox_warning = self._resolved_source_outbox_path_analysis_from_row(preview_row)
        target_folder = str(
            request_payload.get("TargetFolder", "")
            or preview_row.get("PairTargetFolder", "")
            or state.target_folder
            or ""
        ).strip()

        def resolve_contract_path(request_key: str, row_key: str, fallback_name: str) -> str:
            direct = str(request_payload.get(request_key, "") or preview_row.get(row_key, "") or "").strip()
            if direct:
                return direct
            if target_folder and fallback_name:
                return str(Path(target_folder) / fallback_name)
            return ""

        resolved = {
            "TargetFolder": target_folder,
            "RequestPath": request_path,
            "WorkFolderPath": resolve_contract_path(
                "WorkFolderPath",
                "WorkFolderPath",
                self._pair_test_file_name("WorkFolderName", "work"),
            ),
            "CheckScriptPath": resolve_contract_path(
                "CheckScriptPath",
                "CheckScriptPath",
                self._pair_test_file_name("CheckScriptFileName", "check-artifact.ps1"),
            ),
            "SubmitScriptPath": resolve_contract_path(
                "SubmitScriptPath",
                "SubmitScriptPath",
                self._pair_test_file_name("SubmitScriptFileName", "submit-artifact.ps1"),
            ),
            "CheckCmdPath": resolve_contract_path(
                "CheckCmdPath",
                "CheckCmdPath",
                self._pair_test_file_name("CheckCmdFileName", "check-artifact.cmd"),
            ),
            "SubmitCmdPath": resolve_contract_path(
                "SubmitCmdPath",
                "SubmitCmdPath",
                self._pair_test_file_name("SubmitCmdFileName", "submit-artifact.cmd"),
            ),
            "Source": "request" if request_payload else ("preview" if preview_row else "fallback"),
        }
        request_has_authoritative_contract = any(
            str(request_payload.get(field_name, "") or "").strip()
            for field_name in (
                "SourceOutboxPath",
                "SourceSummaryPath",
                "SourceReviewZipPath",
                "PublishReadyPath",
            )
        )
        if request_has_authoritative_contract:
            source_outbox_warning = str(request_outbox_warning or "").strip()
        else:
            source_outbox_warning = str(request_outbox_warning or preview_outbox_warning or "").strip()
        source_outbox_path = str(
            request_payload.get("SourceOutboxPath", "")
            or request_outbox_path
            or preview_outbox_path
            or ""
        ).strip()
        if not source_outbox_path and target_folder and not source_outbox_warning:
            source_outbox_path = str(
                Path(target_folder)
                / self._pair_test_file_name("SourceOutboxFolderName", "source-outbox")
            )
        resolved["SourceOutboxPath"] = source_outbox_path
        resolved["SourceOutboxPathWarning"] = source_outbox_warning
        resolved["SourceSummaryPath"] = str(
            request_output_paths.get("SourceSummaryPath", "")
            or preview_output_paths.get("SourceSummaryPath", "")
            or (str(Path(source_outbox_path) / self._pair_test_file_name("SourceSummaryFileName", "summary.txt")) if source_outbox_path else "")
        ).strip()
        resolved["SourceReviewZipPath"] = str(
            request_output_paths.get("SourceReviewZipPath", "")
            or preview_output_paths.get("SourceReviewZipPath", "")
            or (str(Path(source_outbox_path) / self._pair_test_file_name("SourceReviewZipFileName", "review.zip")) if source_outbox_path else "")
        ).strip()
        resolved["PublishReadyPath"] = str(
            request_output_paths.get("PublishReadyPath", "")
            or preview_output_paths.get("PublishReadyPath", "")
            or (str(Path(source_outbox_path) / self._pair_test_file_name("PublishReadyFileName", "publish.ready.json")) if source_outbox_path else "")
        ).strip()
        resolved["PublishedArchivePath"] = str(
            request_payload.get("PublishedArchivePath", "")
            or preview_row.get("PublishedArchivePath", "")
            or (str(Path(source_outbox_path) / self._pair_test_file_name("PublishedArchiveFolderName", ".published")) if source_outbox_path else "")
        ).strip()

        for key in (
            "WorkFolderPath",
            "SourceOutboxPath",
            "SourceSummaryPath",
            "SourceReviewZipPath",
            "PublishReadyPath",
            "PublishedArchivePath",
            "CheckScriptPath",
            "SubmitScriptPath",
            "CheckCmdPath",
            "SubmitCmdPath",
        ):
            path_value = str(resolved.get(key, "") or "").strip()
            resolved[key + "Exists"] = bool(path_value and Path(path_value).exists())
        return resolved

    def _build_artifact_action_command(
        self,
        *,
        state: TargetArtifactState,
        config_path: str,
        run_root: str,
        wrapper_key: str,
        fallback_script_name: str,
        extra: list[str],
    ) -> ArtifactCommandPlan:
        contract_paths = self._resolve_artifact_contract_paths(state)
        wrapper_path = str(contract_paths.get(wrapper_key, "") or "").strip()
        if wrapper_path and Path(wrapper_path).exists():
            return ArtifactCommandPlan(
                command=tuple(self.command_service.build_powershell_file_command(wrapper_path, extra=extra)),
                execution_path=wrapper_path,
                used_wrapper=True,
                contract_paths=contract_paths,
            )

        command = self.command_service.build_script_command(
            fallback_script_name,
            config_path=config_path,
            run_root=run_root,
            target_id=state.target_id,
            extra=extra,
        )
        return ArtifactCommandPlan(
            command=tuple(command),
            execution_path=str(ROOT / fallback_script_name),
            used_wrapper=False,
            contract_paths=contract_paths,
        )

    def _selected_artifact_action_context(self) -> ArtifactActionContextSnapshot | None:
        state = self._selected_artifact_state()
        if state is None:
            messagebox.showwarning("선택 필요", "target row를 먼저 선택하세요.")
            return None

        run_root = self._current_run_root_for_actions()
        if not run_root:
            messagebox.showwarning("RunRoot 필요", "artifact 검증/가져오기에는 RunRoot가 필요합니다.")
            return None

        artifact_run_root = self._current_run_root_for_artifacts()
        if artifact_run_root:
            normalized_artifact = os.path.normcase(os.path.normpath(artifact_run_root))
            normalized_action = os.path.normcase(os.path.normpath(run_root))
            if normalized_artifact != normalized_action:
                confirmed = messagebox.askyesno(
                    "Artifact 실행 RunRoot 확인",
                    "\n".join(
                        [
                            "현재 결과 / 산출물 탭은 action RunRoot와 다른 RunRoot를 조회 중입니다.",
                            "",
                            f"조회 RunRoot: {artifact_run_root}",
                            f"실행 RunRoot: {run_root}",
                            "",
                            "artifact check/submit은 실행 RunRoot 기준 target folder 계약에 기록됩니다.",
                            "계속할까요?",
                        ]
                    ),
                    parent=self,
                )
                if not confirmed:
                    return None

        config_path = self.config_path_var.get().strip()
        if not config_path:
            messagebox.showwarning("설정 필요", "artifact 검증/가져오기에는 ConfigPath가 필요합니다.")
            return None

        return ArtifactActionContextSnapshot(
            state=state,
            config_path=config_path,
            run_root=run_root,
            run_root_is_stale=self._run_root_is_stale(run_root),
        )

    def _record_artifact_action_result(
        self,
        *,
        action: str,
        status: str,
        context: ArtifactActionContextSnapshot,
        sources: ArtifactSourceSelection,
        plan: ArtifactCommandPlan,
        requires_overwrite: bool = False,
        latest_state: str = "",
        latest_zip_path: str = "",
        error: str = "",
    ) -> None:
        self._remember_artifact_action_result(
            context.state.target_id,
            build_artifact_action_record(
                action=action,
                status=status,
                context=context,
                sources=sources,
                plan=plan,
                recorded_at=datetime.now().isoformat(timespec="seconds"),
                requires_overwrite=requires_overwrite,
                latest_state=latest_state,
                latest_zip_path=latest_zip_path,
                error=error,
            ),
        )

    def _prompt_external_artifact_sources(self, state: TargetArtifactState) -> tuple[str, str] | None:
        contract_paths = self._resolve_artifact_contract_paths(state)
        remembered = self._artifact_last_sources(state.target_id)
        remembered_summary_path = str(remembered.get("SummarySourcePath", "") or "").strip()
        remembered_review_zip_path = str(remembered.get("ReviewZipSourcePath", "") or "").strip()
        if (
            remembered_summary_path
            and remembered_review_zip_path
            and Path(remembered_summary_path).exists()
            and Path(remembered_review_zip_path).exists()
        ):
            reuse_confirmed = messagebox.askyesno(
                "최근 source 재사용",
                "\n".join(
                    [
                        f"{state.target_id} 에 마지막으로 사용한 source 경로가 있습니다.",
                        "",
                        f"source summary: {remembered_summary_path}",
                        f"source zip: {remembered_review_zip_path}",
                        "",
                        "이 경로를 그대로 다시 사용할까요?",
                    ]
                ),
                parent=self,
            )
            if reuse_confirmed:
                return remembered_summary_path, remembered_review_zip_path

        initial_dir = str(contract_paths.get("WorkFolderPath", "") or "").strip()
        if not initial_dir:
            initial_dir = str(Path(state.target_folder).parent) if state.target_folder else str(ROOT)
        initial_file = ""
        if remembered_summary_path:
            remembered_summary = Path(remembered_summary_path)
            if remembered_summary.parent.exists():
                initial_dir = str(remembered_summary.parent)
            initial_file = remembered_summary.name
        summary_path = filedialog.askopenfilename(
            title=f"{state.target_id} source summary 파일 선택",
            initialdir=initial_dir,
            initialfile=initial_file,
            filetypes=[("Text/Markdown", "*.txt *.md"), ("All files", "*.*")],
        )
        if not summary_path:
            return None

        zip_initial_dir = str(Path(summary_path).resolve().parent)
        zip_initial_file = ""
        if remembered_review_zip_path:
            remembered_review_zip = Path(remembered_review_zip_path)
            if remembered_review_zip.parent.exists():
                zip_initial_dir = str(remembered_review_zip.parent)
            zip_initial_file = remembered_review_zip.name
        review_zip_path = filedialog.askopenfilename(
            title=f"{state.target_id} source review zip 선택 (paired submit 아님)",
            initialdir=zip_initial_dir,
            initialfile=zip_initial_file,
            filetypes=[("ZIP", "*.zip"), ("All files", "*.*")],
        )
        if not review_zip_path:
            return None

        return summary_path, review_zip_path

    def _format_external_artifact_preflight(self, payload: dict) -> str:
        validation = payload.get("Validation", {}) or {}
        preflight = payload.get("Preflight", {}) or {}
        lines = [
            "외부 artifact preflight",
            "이 summary/source zip은 입력 source입니다. paired submit 자체는 target-local wrapper 또는 import가 target folder contract에 기록할 때 완료됩니다.",
        ]
        summary_lines = [str(item) for item in (preflight.get("SummaryLines", []) or []) if str(item).strip()]
        if summary_lines:
            lines.extend(summary_lines)
        else:
            lines.append("(preflight summary 없음)")
        lines.extend(
            [
                "",
                "Issues: " + (", ".join(str(item) for item in (validation.get("Issues", []) or [])) or "(none)"),
                "Warnings: " + (", ".join(str(item) for item in (validation.get("Warnings", []) or [])) or "(none)"),
            ]
        )
        return "\n".join(lines)

    def check_selected_external_artifact(self) -> None:
        context = self._selected_artifact_action_context()
        if context is None:
            return
        selected_sources = self._prompt_external_artifact_sources(context.state)
        if selected_sources is None:
            return
        sources = ArtifactSourceSelection(*selected_sources)
        self._remember_artifact_sources(context.state.target_id, sources.summary_path, sources.review_zip_path)

        plan = self._build_artifact_action_command(
            state=context.state,
            config_path=context.config_path,
            run_root=context.run_root,
            wrapper_key="CheckScriptPath",
            fallback_script_name="check-paired-exchange-artifact.ps1",
            extra=[
                "-SummarySourcePath",
                sources.summary_path,
                "-ReviewZipSourcePath",
                sources.review_zip_path,
                "-AsJson",
            ],
        )
        self._record_artifact_action_result(
            action="check",
            status="running",
            context=context,
            sources=sources,
            plan=plan,
        )
        self.last_command_var.set(subprocess.list2cmdline(list(plan.command)))

        def worker() -> subprocess.CompletedProcess[str]:
            return self.command_service.run(list(plan.command))

        def on_failure(exc: Exception) -> None:
            self._record_artifact_action_result(
                action="check",
                status="failed",
                context=context,
                sources=sources,
                plan=plan,
                error=str(exc),
            )

        def on_success(completed: subprocess.CompletedProcess[str]) -> None:
            payload = json.loads(completed.stdout)
            preflight_text = self._format_external_artifact_preflight(payload)
            validation = payload.get("Validation", {}) or {}
            preflight = payload.get("Preflight", {}) or {}
            current_target = payload.get("PreImportStatus", {}) or {}
            latest_state = str(preflight.get("CurrentLatestState", "") or current_target.get("LatestState", "") or "")
            latest_zip_path = str(preflight.get("DestinationZipPath", "") or "")
            self._record_artifact_action_result(
                action="check",
                status="success",
                context=context,
                sources=sources,
                plan=plan,
                requires_overwrite=bool(validation.get("RequiresOverwrite", False)),
                latest_state=latest_state,
                latest_zip_path=latest_zip_path,
            )
            header_lines = [
                "artifact check 실행",
                f"실행 경로: {plan.execution_path}",
                f"target-local wrapper 사용: {'예' if plan.used_wrapper else '아니오 (root fallback)'}",
                f"wrapper 경로 출처: {plan.contract_paths.get('Source', '') or '(없음)'}",
            ]
            if not plan.used_wrapper:
                header_lines.append("LEGACY FALLBACK WARNING: target-local wrapper 없이 root fallback check를 사용했습니다.")
            if context.run_root_is_stale:
                header_lines.append("주의: 현재 선택된 RunRoot가 stale 표시입니다. 새 wrapper가 없는 예전 run일 수 있습니다.")
            self.set_text(
                self.output_text,
                "\n".join(header_lines) + "\n\n" + preflight_text + "\n\nJSON\n" + json.dumps(payload, ensure_ascii=False, indent=2),
            )
            self.on_artifact_row_selected()

        self.run_background_task(
            state="artifact check 실행 중",
            hint=f"{context.state.target_id} target-local check wrapper 또는 fallback 검증을 수행 중입니다.",
            worker=worker,
            on_success=on_success,
            success_state="artifact check 실행 완료",
            success_hint="검증 결과 JSON과 실행 경로를 출력했습니다.",
            failure_state="artifact check 실행 실패",
            failure_hint="선택한 summary/zip 경로, target wrapper 경로, RunRoot 계약을 확인하세요.",
            on_failure=on_failure,
        )

    def import_selected_external_artifact(self) -> None:
        context = self._selected_artifact_action_context()
        if context is None:
            return
        selected_sources = self._prompt_external_artifact_sources(context.state)
        if selected_sources is None:
            return
        sources = ArtifactSourceSelection(*selected_sources)
        self._remember_artifact_sources(context.state.target_id, sources.summary_path, sources.review_zip_path)
        if not self._confirm_recent_submit_repeat(context.state.target_id):
            return

        check_plan = self._build_artifact_action_command(
            state=context.state,
            config_path=context.config_path,
            run_root=context.run_root,
            wrapper_key="CheckScriptPath",
            fallback_script_name="check-paired-exchange-artifact.ps1",
            extra=[
                "-SummarySourcePath",
                sources.summary_path,
                "-ReviewZipSourcePath",
                sources.review_zip_path,
                "-AsJson",
            ],
        )
        def worker() -> subprocess.CompletedProcess[str]:
            return self.command_service.run(list(check_plan.command))

        def on_failure(exc: Exception) -> None:
            self._record_artifact_action_result(
                action="submit-preflight",
                status="failed",
                context=context,
                sources=sources,
                plan=check_plan,
                error=str(exc),
            )

        def on_success(completed: subprocess.CompletedProcess[str]):
            check_payload = json.loads(completed.stdout)
            preflight_text = self._format_external_artifact_preflight(check_payload)
            validation = check_payload.get("Validation", {}) or {}
            preflight = check_payload.get("Preflight", {}) or {}
            current_target = check_payload.get("PreImportStatus", {}) or {}
            requires_overwrite = bool(validation.get("RequiresOverwrite", False))
            latest_state = str(preflight.get("CurrentLatestState", "") or current_target.get("LatestState", "") or "")
            latest_zip_path = str(preflight.get("DestinationZipPath", "") or "")
            preflight_header_lines = [
                "artifact submit 사전검사",
                f"check 실행 경로: {check_plan.execution_path}",
                f"target-local wrapper 사용: {'예' if check_plan.used_wrapper else '아니오 (root fallback)'}",
                f"wrapper 경로 출처: {check_plan.contract_paths.get('Source', '') or '(없음)'}",
            ]
            if not check_plan.used_wrapper:
                preflight_header_lines.append("LEGACY FALLBACK WARNING: target-local wrapper 없이 root fallback check를 사용했습니다.")
            if context.run_root_is_stale:
                preflight_header_lines.append("주의: 현재 선택된 RunRoot가 stale 표시입니다. 새 wrapper가 없는 예전 run일 수 있습니다.")
            self.set_text(
                self.output_text,
                "\n".join(preflight_header_lines) + "\n\n" + preflight_text + "\n\nJSON\n" + json.dumps(check_payload, ensure_ascii=False, indent=2),
            )

            if not bool(validation.get("Ok", False)):
                self._record_artifact_action_result(
                    action="submit-preflight",
                    status="blocked",
                    context=context,
                    sources=sources,
                    plan=check_plan,
                    requires_overwrite=requires_overwrite,
                    latest_state=latest_state,
                    latest_zip_path=latest_zip_path,
                )
                messagebox.showwarning("외부 artifact import 차단", "입력 artifact 검증에 실패했습니다. output 영역의 preflight 결과를 먼저 확인하세요.", parent=self)
                return None

            self._record_artifact_action_result(
                action="submit-preflight",
                status="success",
                context=context,
                sources=sources,
                plan=check_plan,
                requires_overwrite=requires_overwrite,
                latest_state=latest_state,
                latest_zip_path=latest_zip_path,
            )

            confirm_lines = [
                f"target: {context.state.target_id}",
                f"source summary: {sources.summary_path}",
                f"source zip: {sources.review_zip_path}",
                f"check 실행 경로: {check_plan.execution_path}",
                f"wrapper 사용: {'예' if check_plan.used_wrapper else '아니오 (root fallback)'}",
                "",
                preflight_text,
                "",
                "현재 RunRoot target folder 계약으로 summary.txt, review zip, done.json, result.json을 기록할까요?",
            ]
            if context.run_root_is_stale:
                confirm_lines.append("주의: 선택된 RunRoot가 stale 표시입니다. 새 RunRoot로 다시 준비한 wrapper가 아닐 수 있습니다.")
            if requires_overwrite:
                confirm_lines.append("이 import는 기존 contract 파일 또는 현재 성공 상태를 덮어씁니다. 계속하려면 overwrite를 명시적으로 승인해야 합니다.")

            confirmed = messagebox.askyesno(
                "외부 artifact import" if not requires_overwrite else "외부 artifact import (overwrite)",
                "\n".join(confirm_lines),
                parent=self,
            )
            if not confirmed:
                self._record_artifact_action_result(
                    action="submit-preflight",
                    status="cancelled",
                    context=context,
                    sources=sources,
                    plan=check_plan,
                    requires_overwrite=requires_overwrite,
                    latest_state=latest_state,
                    latest_zip_path=latest_zip_path,
                )
                return None

            extra = [
                "-SummarySourcePath",
                sources.summary_path,
                "-ReviewZipSourcePath",
                sources.review_zip_path,
                "-AsJson",
            ]
            if requires_overwrite:
                extra.append("-Overwrite")

            submit_plan = self._build_artifact_action_command(
                state=context.state,
                config_path=context.config_path,
                run_root=context.run_root,
                wrapper_key="SubmitScriptPath",
                fallback_script_name="import-paired-exchange-artifact.ps1",
                extra=extra,
            )
            if not submit_plan.used_wrapper:
                fallback_confirmed = messagebox.askyesno(
                    "legacy fallback submit 확인",
                    "\n".join(
                        [
                            f"{context.state.target_id} submit이 target-local wrapper 없이 legacy fallback 경로로 실행됩니다.",
                            f"실행 경로: {submit_plan.execution_path}",
                            f"wrapper 경로 출처: {submit_plan.contract_paths.get('Source', '') or '(없음)'}",
                            "이 경로는 예전 RunRoot 호환용입니다. 새 RunRoot를 다시 준비하지 않았다면 혼선 가능성이 큽니다.",
                            "",
                            "정말 fallback submit을 계속할까요?",
                        ]
                    ),
                    parent=self,
                )
                if not fallback_confirmed:
                    self._record_artifact_action_result(
                        action="submit-preflight",
                        status="cancelled",
                        context=context,
                        sources=sources,
                        plan=check_plan,
                        requires_overwrite=requires_overwrite,
                        latest_state=latest_state,
                        latest_zip_path=latest_zip_path,
                    )
                    return None

            if not self._begin_submit_action(context.state.target_id):
                self._record_artifact_action_result(
                    action="submit-preflight",
                    status="blocked",
                    context=context,
                    sources=sources,
                    plan=check_plan,
                    requires_overwrite=requires_overwrite,
                    latest_state=latest_state,
                    latest_zip_path=latest_zip_path,
                )
                messagebox.showwarning("submit 진행 중", f"{context.state.target_id} submit이 이미 진행 중입니다.", parent=self)
                return None

            launch_request = ArtifactSubmitLaunchRequest(
                preflight=ArtifactSubmitPreflight(
                    context=context,
                    sources=sources,
                    check_plan=check_plan,
                    payload=check_payload,
                    preflight_text=preflight_text,
                    requires_overwrite=requires_overwrite,
                    latest_state=latest_state,
                    latest_zip_path=latest_zip_path,
                ),
                submit_plan=submit_plan,
            )
            return lambda request=launch_request: self._execute_artifact_submit(request)

        self.run_background_task(
            state="artifact submit 사전검사 중",
            hint=f"{context.state.target_id} submit 전 target-local check wrapper 또는 fallback 검증을 수행 중입니다.",
            worker=worker,
            on_success=on_success,
            success_state="artifact submit 사전검사 완료",
            success_hint="preflight 결과를 확인한 뒤 submit을 이어서 실행할 수 있습니다.",
            failure_state="artifact submit 사전검사 실패",
            failure_hint="summary/zip 경로, target wrapper 경로, RunRoot target 계약을 확인하세요.",
            on_failure=on_failure,
        )

    def _execute_artifact_submit(self, request: ArtifactSubmitLaunchRequest) -> None:
        context = request.preflight.context
        sources = request.preflight.sources
        submit_plan = request.submit_plan
        requires_overwrite = request.preflight.requires_overwrite
        self._record_artifact_action_result(
            action="submit",
            status="running",
            context=context,
            sources=sources,
            plan=submit_plan,
            requires_overwrite=requires_overwrite,
            latest_state=request.preflight.latest_state,
            latest_zip_path=request.preflight.latest_zip_path,
        )
        self.last_command_var.set(subprocess.list2cmdline(list(submit_plan.command)))

        def worker() -> subprocess.CompletedProcess[str]:
            return self.command_service.run(list(submit_plan.command))

        def on_failure(exc: Exception) -> None:
            self._record_artifact_action_result(
                action="submit",
                status="failed",
                context=context,
                sources=sources,
                plan=submit_plan,
                requires_overwrite=requires_overwrite,
                latest_state=request.preflight.latest_state,
                latest_zip_path=request.preflight.latest_zip_path,
                error=str(exc),
            )
            self._finish_submit_action(context.state.target_id)

        def on_success(completed: subprocess.CompletedProcess[str]) -> None:
            try:
                payload = json.loads(completed.stdout)
                preflight_text = self._format_external_artifact_preflight(payload)
                post_import_status = payload.get("PostImportStatus", {}) or {}
                contract = payload.get("Contract", {}) or {}
                latest_state = str(post_import_status.get("LatestState", "") or "")
                latest_zip_path = str(contract.get("DestinationZipPath", "") or contract.get("LatestZipPath", "") or "")
                self._record_artifact_action_result(
                    action="submit",
                    status="success",
                    context=context,
                    sources=sources,
                    plan=submit_plan,
                    requires_overwrite=requires_overwrite,
                    latest_state=latest_state,
                    latest_zip_path=latest_zip_path,
                )
                header_lines = [
                    "artifact submit 실행",
                    f"submit 실행 경로: {submit_plan.execution_path}",
                    f"target-local wrapper 사용: {'예' if submit_plan.used_wrapper else '아니오 (root fallback)'}",
                    f"wrapper 경로 출처: {submit_plan.contract_paths.get('Source', '') or '(없음)'}",
                ]
                if not submit_plan.used_wrapper:
                    header_lines.append("LEGACY FALLBACK WARNING: target-local wrapper 없이 root fallback submit을 사용했습니다.")
                if context.run_root_is_stale:
                    header_lines.append("주의: 현재 선택된 RunRoot가 stale 표시입니다. 새 RunRoot로 다시 준비한 wrapper가 아닐 수 있습니다.")
                header_lines.extend(
                    [
                        f"RequiresOverwrite: {requires_overwrite}",
                        f"계약 LatestState: {latest_state or '(없음)'}",
                        f"LatestZipPath: {latest_zip_path or '(없음)'}",
                    ]
                )
                self.set_text(
                    self.output_text,
                    "\n".join(header_lines) + "\n\n" + preflight_text + "\n\nJSON\n" + json.dumps(payload, ensure_ascii=False, indent=2),
                )
                self.refresh_paired_status_background(label="artifact submit 후 paired status 갱신")
                self.on_artifact_row_selected()
            finally:
                self._finish_submit_action(context.state.target_id)

        self.run_background_task(
            state="artifact submit 실행 중",
            hint=f"{context.state.target_id} target-local submit wrapper 또는 fallback import를 실행 중입니다.",
            worker=worker,
            on_success=on_success,
            success_state="artifact submit 실행 완료",
            success_hint="paired status와 결과 탭을 새 산출물 기준으로 다시 읽었습니다.",
            failure_state="artifact submit 실행 실패",
            failure_hint="summary/zip 경로, target wrapper 경로, RunRoot target 계약을 확인하세요.",
            on_failure=on_failure,
        )

    def on_home_pair_selected(self, _event: object | None = None) -> None:
        summary = self._selected_pair_summary()
        self._apply_home_pair_tree_highlights()
        if self._artifact_home_browse_pair_scope_enabled():
            self._sync_artifact_filters_with_home_pair_selection(refresh=self._has_ui_attr("artifact_tree"))
        self._apply_artifact_tree_highlights()
        if not summary:
            self.home_pair_detail_var.set(self._home_pair_detail_text(summary))
            return
        self.home_pair_detail_var.set(self._home_pair_detail_text(summary))
        self.update_pair_button_states()

    def apply_selected_home_pair(self) -> None:
        pair_id = self._selected_home_pair_id()
        top_target_id = self._resolve_top_target_for_pair(pair_id)
        self._set_action_context(
            pair_id=pair_id,
            target_id=top_target_id if top_target_id else self.target_id_var.get().strip(),
            source="home-pair-apply",
        )
        self._sync_home_pair_selection(pair_id)
        self._sync_pair_scoped_views_with_action_context(refresh_artifacts=True)
        self.render_target_board()
        self.update_pair_button_states()
        self.rebuild_panel_state()
        self.set_text(self.output_text, f"선택 Pair 반영 완료:\n{pair_id}")

    def apply_selected_inspection_context(self) -> None:
        inspection_context = self._selected_inspection_context_state()
        pair_id = inspection_context.pair_id
        target_id = inspection_context.target_id
        if not pair_id and not target_id:
            messagebox.showwarning("선택 필요", "반영할 preview row 또는 board target을 먼저 선택하세요.")
            return
        resolved_target = target_id
        if target_id:
            resolved_target = target_id
        elif pair_id:
            resolved_target = self._resolve_top_target_for_pair(pair_id)
        self._set_action_context(
            pair_id=pair_id if pair_id else None,
            target_id=resolved_target if resolved_target else None,
            source="inspection-apply",
        )
        self._sync_home_pair_selection(self._selected_pair_id())
        self._sync_pair_scoped_views_with_action_context(refresh_artifacts=True)
        self.render_target_board()
        self.update_pair_button_states()
        self.rebuild_panel_state()
        self.set_text(
            self.output_text,
            "inspection 실행 기준 반영 완료:\nPair={0}\nTarget={1}".format(
                self._selected_pair_id(),
                self.target_id_var.get().strip() or "(없음)",
            ),
        )

    def rebuild_panel_state(self, *, timing_steps: list[dict[str, object]] | None = None) -> None:
        if not self.effective_data or not self.relay_status_data or not self.visibility_status_data:
            return
        effective_data = dict(self.effective_data)
        runtime_hints = self._run_refresh_ui_step(timing_steps, "runtime hints", self._panel_runtime_hints)
        effective_data["PanelRuntimeHints"] = runtime_hints

        def build_bundle() -> DashboardRawBundle:
            return DashboardRawBundle(
                effective_data=effective_data,
                relay_status=self.relay_status_data,
                visibility_status=self.visibility_status_data,
                paired_status=self.paired_status_data,
                paired_status_error=self.paired_status_error,
            )

        bundle = self._run_refresh_ui_step(timing_steps, "bundle compose", build_bundle)
        selected_pair = self._run_refresh_ui_step(timing_steps, "selected pair resolve", self._selected_pair_id)

        aggregator_timing_steps: list[dict[str, object]] | None = [] if timing_steps is not None else None

        def build_aggregated_state():
            if aggregator_timing_steps is None:
                return self.dashboard_aggregator.build_panel_state(
                    bundle=bundle,
                    selected_pair=selected_pair,
                )
            try:
                return self.dashboard_aggregator.build_panel_state(
                    bundle=bundle,
                    selected_pair=selected_pair,
                    timing_steps=aggregator_timing_steps,
                )
            except TypeError as exc:
                if "timing_steps" not in str(exc):
                    raise
                if aggregator_timing_steps is not None:
                    aggregator_timing_steps.clear()
                return self.dashboard_aggregator.build_panel_state(
                    bundle=bundle,
                    selected_pair=selected_pair,
                )

        self.panel_state = self._run_refresh_ui_step(
            timing_steps,
            "aggregator build",
            build_aggregated_state,
        )
        if timing_steps is not None:
            self._append_refresh_timing_steps(timing_steps, aggregator_timing_steps, prefix="aggregator: ")
        if self.__dict__.get("_defer_home_dashboard_render_until_idle", False):
            self.__dict__["_home_dashboard_render_deferred_until_idle"] = True
            if timing_steps is not None:
                timing_steps.append(
                    {
                        "label": "home dashboard render deferred",
                        "elapsed_seconds": 0.0,
                        "elapsed_text": self._format_task_elapsed_seconds(0.0),
                    }
                )
        else:
            self._run_refresh_ui_step(timing_steps, "home dashboard render", self.render_home_dashboard)
        self._run_refresh_ui_step(timing_steps, "sticky context refresh", self._refresh_sticky_context_bar)

    def run_script(
        self,
        script_name: str,
        *,
        extra: list[str] | None = None,
        run_root_override: str | None = None,
        pair_id_override: str | None = None,
        target_id_override: str | None = None,
    ) -> subprocess.CompletedProcess[str]:
        context = self._current_context()
        command = self.command_service.build_script_command(
            script_name=script_name,
            config_path=context.config_path,
            run_root=context.run_root if run_root_override is None else run_root_override,
            pair_id=context.pair_id if pair_id_override is None else pair_id_override,
            target_id=context.target_id if target_id_override is None else target_id_override,
            extra=extra,
        )
        self.last_command_var.set(subprocess.list2cmdline(command))
        return self.status_service.run_script(
            script_name,
            context,
            extra=extra,
            run_root_override=run_root_override,
            pair_id_override=pair_id_override,
            target_id_override=target_id_override,
        )

    def run_json_script(
        self,
        script_name: str,
        *,
        extra: list[str] | None = None,
        run_root_override: str | None = None,
        pair_id_override: str | None = None,
        target_id_override: str | None = None,
    ) -> dict:
        context = self._current_context()
        command = self.command_service.build_script_command(
            script_name=script_name,
            config_path=context.config_path,
            run_root=context.run_root if run_root_override is None else run_root_override,
            pair_id=context.pair_id if pair_id_override is None else pair_id_override,
            target_id=context.target_id if target_id_override is None else target_id_override,
            extra=extra,
        )
        self.last_command_var.set(subprocess.list2cmdline(command))
        return self.status_service.run_json_script(
            script_name,
            context,
            extra=extra,
            run_root_override=run_root_override,
            pair_id_override=pair_id_override,
            target_id_override=target_id_override,
        )

    def _apply_dashboard_refresh_bundle(
        self,
        bundle,
        *,
        auto_pair_policy_preview: bool,
        timing_steps: list[dict[str, object]] | None = None,
    ) -> None:
        prior_override_state = self._run_root_override_state()
        prior_action_run_root = self._current_run_root_for_actions()
        effective_payload = bundle.effective_data
        relay_payload = bundle.relay_status
        visibility_payload = bundle.visibility_status
        paired_payload = bundle.paired_status
        paired_error = bundle.paired_status_error
        selected_run_root = effective_payload.get("RunContext", {}).get("SelectedRunRoot", "") or ""

        def apply_payload() -> None:
            self.effective_data = effective_payload
            self.relay_status_data = relay_payload
            self.visibility_status_data = visibility_payload
            self.paired_status_data = paired_payload
            self.paired_status_error = paired_error
            self.preview_rows = list(effective_payload.get("PreviewRows", []))
            self._clear_start_run_preview_cache()
            self._clear_pair_policy_route_snapshot_cache()
            self._clear_message_editor_saved_preview_seed_payload()
            self._prime_pair_policy_route_snapshot_cache_from_effective_payload(effective_payload)
            self._prime_message_editor_saved_preview_seed_payload(effective_payload)

        def update_run_root_controls() -> None:
            if prior_override_state != "override-active":
                run_root_source = effective_payload.get("RunContext", {}).get("SelectedRunRootSource", "") or ""
                if self._should_preserve_target_autoloop_run_root_on_dashboard_refresh(
                    prior_run_root=prior_action_run_root,
                    refreshed_selected_run_root=selected_run_root,
                ):
                    self.run_root_var.set(str(prior_action_run_root or "").strip())
                    self.__dict__[
                        "_target_autoloop_runroot_preserved_after_full_refresh"
                    ] = str(prior_action_run_root or "").strip()
                elif selected_run_root and run_root_source != "next-preview":
                    self.run_root_var.set(selected_run_root)
                else:
                    self.run_root_var.set("")
            self._update_run_root_controls()

        def schedule_settings_preview() -> None:
            self.__dict__["_pair_policy_refresh_auto_preview"] = bool(auto_pair_policy_preview)
            self._schedule_settings_preview_refresh(auto_pair_policy_preview=auto_pair_policy_preview)

        def sync_context_state() -> None:
            self._coerce_selected_pair_into_runtime_scope()
            self._sync_message_scope_id_from_context()
            self._apply_watcher_start_defaults_if_pristine()
            self._refresh_watcher_notes()

        def sync_selection() -> None:
            selected_target = self._selected_inspection_target_id() or self.target_id_var.get().strip()
            selected_pair = self._selected_inspection_pair_id() or self._selected_pair_id()
            if self.preview_rows and not self._sync_preview_selection_with_pair(selected_pair, target_id=selected_target):
                first = self.row_tree.get_children()[0]
                self.row_tree.selection_set(first)
                self.on_row_selected()
            elif not self.preview_rows:
                self._set_inspection_context(source="")
                self.clear_details()

        def update_operator_status() -> None:
            result_text = "마지막 결과: 전체 새로고침 완료"
            if paired_error:
                result_text += " / pair-status 일부 생략"
            self.set_operator_status("전체 상태 불러옴", "홈 탭에서 준비 단계와 pair 요약을 바로 확인할 수 있습니다.", result_text)

        self._run_refresh_ui_step(timing_steps, "dashboard payload 반영", apply_payload)
        self._run_refresh_ui_step(timing_steps, "runroot controls update", update_run_root_controls)
        self._run_refresh_ui_step(timing_steps, "summary render", lambda: self.render_summary(effective_payload))
        self._run_refresh_ui_step(timing_steps, "rows render", lambda: self.render_rows(self.preview_rows))
        self._run_refresh_ui_step(timing_steps, "settings preview schedule", schedule_settings_preview)
        self._run_refresh_ui_step(
            timing_steps,
            "autoloop status refresh/pending",
            self._refresh_target_autoloop_status_if_visible_or_mark_pending,
        )
        self._run_refresh_ui_step(timing_steps, "context sync", sync_context_state)
        target_board_steps: list[dict[str, object]] = []
        self._run_refresh_ui_step(
            timing_steps,
            "target board render",
            lambda: self._render_target_board_with_optional_timing(target_board_steps, update_buttons=False),
        )
        if timing_steps is not None:
            self._append_refresh_timing_steps(timing_steps, target_board_steps, prefix="board: ")
        panel_state_steps: list[dict[str, object]] = []
        self._run_refresh_ui_step(
            timing_steps,
            "panel state rebuild",
            lambda: self._rebuild_panel_state_with_optional_timing(panel_state_steps),
        )
        if timing_steps is not None:
            self._append_refresh_timing_steps(timing_steps, panel_state_steps, prefix="panel: ")
        self._run_refresh_ui_step(timing_steps, "artifact refresh/pending", self._refresh_artifacts_if_visible_or_mark_pending)
        self._run_refresh_ui_step(timing_steps, "selection sync", sync_selection)
        self._run_refresh_ui_step(timing_steps, "snapshot list refresh", self.refresh_snapshot_list)
        self._run_refresh_ui_step(timing_steps, "button state update", self.update_pair_button_states)
        self._run_refresh_ui_step(timing_steps, "operator status update", update_operator_status)

    def _collect_dashboard_refresh_bundle(
        self,
        context: AppContext,
        steps: list[dict[str, object]],
        *,
        report_progress: bool = False,
    ) -> DashboardRawBundle:
        if report_progress:
            self._post_background_progress("전체 새로고침 중", "1/3 전체 상태 수집 중")
        bundle = self._run_timed_refresh_step(
            steps,
            "전체 상태 수집",
            lambda: self.refresh_controller.refresh_full(context),
        )
        self._append_refresh_timing_steps(
            steps,
            getattr(bundle, "refresh_timing_steps", []),
            prefix="수집: ",
        )

        def enrich_bundle() -> DashboardRawBundle:
            effective_payload = dict(bundle.effective_data or {})
            effective_payload["PanelPairRouteSummaryPayloads"] = self._effective_payload_pair_route_summary_payloads(
                effective_payload
            )
            effective_payload["PanelMessageEditorSeedPayload"] = self._effective_payload_message_editor_seed_payload(
                effective_payload
            )
            bundle.effective_data = effective_payload
            return bundle

        if report_progress:
            self._post_background_progress("전체 새로고침 중", "2/3 payload 보강 중")
        return self._run_timed_refresh_step(steps, "payload 보강", enrich_bundle)

    def refresh_full_dashboard_status(self, *, auto_pair_policy_preview: bool = True) -> None:
        if self.__dict__.get("refresh_controller") is None:
            self.load_effective_config(auto_pair_policy_preview=auto_pair_policy_preview)
            return

        started_at = time.monotonic()
        steps: list[dict[str, object]] = []
        try:
            context = self._run_timed_refresh_step(steps, "문맥 계산", self._effective_refresh_context)
        except Exception as exc:
            self._record_refresh_timing(
                label="전체 새로고침",
                started_at=started_at,
                steps=steps,
                outcome="실패",
            )
            messagebox.showerror("불러오기 실패", str(exc))
            self.set_operator_status("불러오기 실패", "상태 JSON 수집에 실패했습니다.", f"마지막 결과: 실패 ({exc})")
            return

        def worker() -> DashboardRawBundle:
            return self._collect_dashboard_refresh_bundle(
                context,
                steps,
                report_progress=True,
            )

        def on_success(bundle: DashboardRawBundle):
            self._set_background_task_step("전체 새로고침 중", "3/3 UI 적용 중")
            ui_steps: list[dict[str, object]] = []
            self._run_timed_refresh_step(
                steps,
                "UI 적용",
                lambda: self._apply_dashboard_refresh_bundle(
                    bundle,
                    auto_pair_policy_preview=auto_pair_policy_preview,
                    timing_steps=ui_steps,
                ),
            )
            self._append_refresh_timing_steps(steps, ui_steps, prefix="UI: ")
            return lambda: self._record_refresh_timing(
                label="전체 새로고침",
                started_at=started_at,
                steps=steps,
            )

        def on_failure(exc: Exception) -> str:
            self._record_refresh_timing(
                label="전체 새로고침",
                started_at=started_at,
                steps=steps,
                outcome="실패",
            )
            messagebox.showerror("불러오기 실패", str(exc))
            return self._format_background_exception(exc)

        self.run_background_task(
            state="전체 새로고침 중",
            hint="effective config, runtime, visibility, paired 상태를 백그라운드에서 수집 중입니다.",
            worker=worker,
            on_success=on_success,
            success_state="전체 상태 불러옴",
            success_hint="홈 탭에서 준비 단계와 pair 요약을 바로 확인할 수 있습니다.",
            failure_state="불러오기 실패",
            failure_hint="상태 JSON 수집에 실패했습니다.",
            on_failure=on_failure,
        )

    def load_effective_config(self, *, auto_pair_policy_preview: bool = True) -> None:
        started_at = time.monotonic()
        steps: list[dict[str, object]] = []
        try:
            context = self._run_timed_refresh_step(steps, "문맥 계산", self._effective_refresh_context)
            bundle = self._collect_dashboard_refresh_bundle(
                context,
                steps,
                report_progress=False,
            )
            ui_steps: list[dict[str, object]] = []
            self._run_timed_refresh_step(
                steps,
                "UI 적용",
                lambda: self._apply_dashboard_refresh_bundle(
                    bundle,
                    auto_pair_policy_preview=auto_pair_policy_preview,
                    timing_steps=ui_steps,
                ),
            )
            self._append_refresh_timing_steps(steps, ui_steps, prefix="UI: ")
        except Exception as exc:
            self._record_refresh_timing(
                label="전체 새로고침",
                started_at=started_at,
                steps=steps,
                outcome="실패",
            )
            messagebox.showerror("불러오기 실패", str(exc))
            self.set_operator_status("불러오기 실패", "상태 JSON 수집에 실패했습니다.", f"마지막 결과: 실패 ({exc})")
            return
        self._record_refresh_timing(
            label="전체 새로고침",
            started_at=started_at,
            steps=steps,
        )

